// Module-level socket.io instance — set once during server init, used by notification helpers
let _io: InstanceType<typeof SocketIOServer> | null = null;

/**
 * Read the shared Socket.IO server. Returns null until registerRoutes() has
 * finished bootstrapping it (line ~44841). QE WebSocket setup in
 * server/index.ts uses this to mount the /execution-agent and /recorder
 * namespaces on the same `/socket.io/` path the rest of the app uses --
 * required for environments (e.g. Hilti) whose proxy chain only allow-lists
 * `/socket.io/*` for WebSocket upgrades.
 */
export function getSharedSocketIO(): InstanceType<typeof SocketIOServer> | null {
  return _io;
}

/** Safely convert DB date to ISO string; returns "" for invalid/zero dates (e.g. MySQL 0000-00-00). */
function safeToISOString(val: Date | string | null | undefined): string {
  if (val == null) return "";
  if (typeof val === "object" && typeof (val as Date).toISOString === "function") {
    const t = (val as Date).getTime();
    return isNaN(t) ? "" : (val as Date).toISOString();
  }
  if (typeof val === "string") {
    const normalized = val.trim().replace(" ", "T");
    const d = new Date(normalized);
    return isNaN(d.getTime()) ? "" : d.toISOString();
  }
  if (typeof val === "number") {
    const d = new Date(val);
    return isNaN(d.getTime()) ? "" : d.toISOString();
  }
  const d = new Date(val as any);
  return isNaN(d.getTime()) ? "" : d.toISOString();
}

function extractAdoOrganizationName(organizationUrl: string): string {
  try {
    const parsed = new URL(organizationUrl);
    const pathOrg = parsed.pathname.split("/").filter(Boolean)[0];
    if (pathOrg) return pathOrg;
    const match = organizationUrl.match(/dev\.azure\.com\/([^/]+)/);
    return match?.[1] || "";
  } catch {
    const match = String(organizationUrl).match(/dev\.azure\.com\/([^/]+)/);
    return match?.[1] || "";
  }
}

/** Get subscription date from row; driver may return camelCase or snake_case. */
function getSubDate(sub: any, key: "startDate" | "expiryDate"): string {
  const camel = key === "startDate" ? "startDate" : "expiryDate";
  const snake = key === "startDate" ? "start_date" : "expiry_date";
  const val = sub?.[camel] ?? sub?.[snake];
  return safeToISOString(val);
}

function normalizeCredentialUrl(value: string | null | undefined): string {
  return String(value || "").trim().replace(/\/+$/, "").toLowerCase();
}

type UserPatReadiness = {
  projectManagementReadyInstanceUrls: Set<string>;
  hasAnyProjectManagementPat: boolean;
  repoReadyProviders: Set<string>;
  hasAnyRepoPat: boolean;
};

const adoProjectsCache = new Map<string, { data: any[], expires: number }>();

function invalidateAdoProjectsCacheForUser(userId: string | null | undefined) {
  const prefixes = [
    `ado-projects-${userId || "default"}-`,
    `hub-projects-${userId || "default"}-`,
  ];
  for (const key of Array.from(adoProjectsCache.keys())) {
    if (prefixes.some((prefix) => key.startsWith(prefix))) {
      adoProjectsCache.delete(key);
    }
  }
}

async function getUserPatReadiness(userId: string): Promise<UserPatReadiness> {
  const [jiraRows, gitRows] = await Promise.all([
    db
      .select({ instanceUrl: schema.userJiraCredentials.instanceUrl })
      .from(schema.userJiraCredentials)
      .where(
        and(
          eq(schema.userJiraCredentials.userId, userId),
          eq(schema.userJiraCredentials.isActive, 1),
          sql`${schema.userJiraCredentials.lastTestedAt} IS NOT NULL`,
          sql`${schema.userJiraCredentials.apiTokenEncrypted} IS NOT NULL`,
          sql`${schema.userJiraCredentials.apiTokenEncrypted} <> ''`,
        ),
      ),
    db
      .select({ id: schema.userGitCredentials.id, provider: schema.userGitCredentials.provider })
      .from(schema.userGitCredentials)
      .where(
        and(
          eq(schema.userGitCredentials.userId, userId),
          eq(schema.userGitCredentials.isActive, 1),
          sql`${schema.userGitCredentials.lastTestedAt} IS NOT NULL`,
          sql`${schema.userGitCredentials.tokenEncrypted} IS NOT NULL`,
          sql`${schema.userGitCredentials.tokenEncrypted} <> ''`,
        ),
      ),
  ]);

  return {
    projectManagementReadyInstanceUrls: new Set(jiraRows.map((row) => normalizeCredentialUrl(row.instanceUrl)).filter(Boolean)),
    hasAnyProjectManagementPat: jiraRows.length > 0,
    repoReadyProviders: new Set(gitRows.map((row) => row.provider).filter(Boolean)),
    hasAnyRepoPat: gitRows.length > 0,
  };
}

function getProjectPatStatus(
  project: {
    jiraInstanceUrl?: string | null;
    goldenRepoReference?: any;
    repoIntegrationConfig?: {
      providerKey?: string | null;
      displayName?: string | null;
      baseUrl?: string | null;
      repositoryId?: string | null;
      repositoryName?: string | null;
    } | null;
  },
  readiness: UserPatReadiness,
) {
  const jiraInstanceUrl = normalizeCredentialUrl(project.jiraInstanceUrl);
  const projectManagementPatConfigured = jiraInstanceUrl
    ? readiness.projectManagementReadyInstanceUrls.has(jiraInstanceUrl)
    : readiness.hasAnyProjectManagementPat;
  const repoProvider = getProjectRepoProvider(project);
  const repoPatRequired = repoProvider !== null;
  const repoPatConfigured = repoPatRequired
    ? readiness.repoReadyProviders.has(repoProvider)
    : false;
  const repoPatSatisfied = !repoPatRequired || repoPatConfigured;
  const userPatConfigured = projectManagementPatConfigured && repoPatSatisfied;
  const credentialStatus = {
    jira: {
      required: Boolean(jiraInstanceUrl),
      configured: projectManagementPatConfigured,
    },
    repo: {
      required: repoPatRequired,
      configured: repoPatConfigured,
    },
    readyForUser: userPatConfigured,
  };

  return {
    credentialStatus,
    projectManagementPatConfigured,
    repoPatConfigured,
    repoPatRequired,
    repoPatSatisfied,
    userPatConfigured,
    // Backward-compatible aliases while the client finishes moving off provider-specific names.
    userJiraPatConfigured: projectManagementPatConfigured,
    userGitlabPatConfigured: repoPatRequired ? repoPatConfigured : false,
  };
}

const PROJECT_READINESS_KIND = "project-readiness";
const PROJECT_READINESS_ID = "default";

function getProjectReadinessProjectId(project: { id?: string | null } | null | undefined): string | null {
  return typeof project?.id === "string" && project.id.trim() ? project.id.trim() : null;
}

function getProjectRepoProvider(project: {
  goldenRepoReference?: any;
  repoIntegrationConfig?: {
    providerKey?: string | null;
    displayName?: string | null;
    baseUrl?: string | null;
    repositoryId?: string | null;
    repositoryName?: string | null;
  } | null;
} | null | undefined): string | null {
  const explicitProvider =
    typeof project?.repoIntegrationConfig?.providerKey === "string" &&
    project.repoIntegrationConfig.providerKey.trim()
      ? project.repoIntegrationConfig.providerKey.trim()
      : typeof project?.goldenRepoReference?.provider === "string"
        ? project.goldenRepoReference.provider
        : null;
  if (explicitProvider) return explicitProvider;

  const repoConfig = project?.repoIntegrationConfig;
  const hasMappedRepo = Boolean(repoConfig?.repositoryId || repoConfig?.repositoryName);
  if (!hasMappedRepo) return null;

  const providerHint = `${repoConfig?.displayName || ""} ${repoConfig?.baseUrl || ""}`.toLowerCase();
  if (providerHint.includes("gitlab")) return "gitlab";
  if (providerHint.includes("github")) return "github";
  if (providerHint.includes("bitbucket")) return "bitbucket";
  if (providerHint.includes("azure") || providerHint.includes("dev.azure.com")) return "azure_repos";

  // Existing personal PAT save path defaults unmapped repo providers to GitLab;
  // keep requirement detection conservative when a repository is mapped but the
  // catalog provider key is missing from the joined config row.
  return "gitlab";
}

function getProjectRepoReadinessIdentity(project: {
  goldenRepoReference?: any;
  repoIntegrationConfig?: { providerKey?: string | null } | null;
}) {
  const provider = getProjectRepoProvider(project);
  if (provider) {
    return { integrationId: provider, providerKey: provider };
  }
  return { integrationId: "default", providerKey: provider || null };
}

function requiresProjectRepoPat(project: {
  goldenRepoReference?: any;
  repoIntegrationConfig?: { providerKey?: string | null } | null;
} | null | undefined): boolean {
  const provider = getProjectRepoProvider(project);
  return Boolean(provider);
}

async function hasSuccessfulProjectReadiness(userId: string | null | undefined, projectId: string | null): Promise<boolean> {
  if (!userId || !projectId) return false;
  const [row] = await db
    .select({ id: schema.userProjectIntegrationCredentials.id })
    .from(schema.userProjectIntegrationCredentials)
    .where(
      and(
        eq(schema.userProjectIntegrationCredentials.userId, userId),
        eq(schema.userProjectIntegrationCredentials.projectId, projectId),
        eq(schema.userProjectIntegrationCredentials.integrationKind, PROJECT_READINESS_KIND),
        eq(schema.userProjectIntegrationCredentials.integrationId, PROJECT_READINESS_ID),
        eq(schema.userProjectIntegrationCredentials.lastTestStatus, "success"),
      ),
    )
    .limit(1);
  return Boolean(row);
}

async function hasSuccessfulProjectIntegrationReadiness(
  userId: string | null | undefined,
  projectId: string | null,
  integrationKind: string,
  integrationId: string,
): Promise<boolean> {
  if (!userId || !projectId) return false;
  const [row] = await db
    .select({ id: schema.userProjectIntegrationCredentials.id })
    .from(schema.userProjectIntegrationCredentials)
    .where(
      and(
        eq(schema.userProjectIntegrationCredentials.userId, userId),
        eq(schema.userProjectIntegrationCredentials.projectId, projectId),
        eq(schema.userProjectIntegrationCredentials.integrationKind, integrationKind),
        eq(schema.userProjectIntegrationCredentials.integrationId, integrationId),
        eq(schema.userProjectIntegrationCredentials.lastTestStatus, "success"),
      ),
    )
    .limit(1);
  return Boolean(row);
}

async function hasProjectRepoCredential(
  userId: string | null | undefined,
  projectId: string | null,
  provider?: string | null,
) {
  if (!userId || !projectId) return false;
  const conditions = [
    eq(schema.userProjectRepoCredentials.userId, userId),
    eq(schema.userProjectRepoCredentials.projectId, projectId),
    eq(schema.userProjectRepoCredentials.isActive, 1),
    sql`${schema.userProjectRepoCredentials.lastTestedAt} IS NOT NULL`,
    sql`${schema.userProjectRepoCredentials.tokenEncrypted} IS NOT NULL`,
    sql`${schema.userProjectRepoCredentials.tokenEncrypted} <> ''`,
  ];
  if (provider) {
    conditions.push(eq(schema.userProjectRepoCredentials.provider, provider));
  }

  const [row] = await db
    .select({ id: schema.userProjectRepoCredentials.id })
    .from(schema.userProjectRepoCredentials)
    .where(and(...conditions))
    .limit(1);
  return Boolean(row);
}

async function getProjectRepoIntegrationConfig(projectId: string | null | undefined): Promise<{
  providerKey: string | null;
  displayName: string | null;
  baseUrl: string;
  repositoryId: string;
  repositoryName: string;
} | null> {
  if (!projectId) return null;
  const { isProjectIntegrationSkippedConfig } = await import(
    "@shared/project-integration-constants"
  );
  const [row] = await db
    .select({
      config: schema.projectIntegrationConfigs.config,
      providerKey: schema.integrationToolCatalog.providerKey,
      displayName: schema.integrationToolCatalog.displayName,
    })
    .from(schema.projectIntegrationConfigs)
    .leftJoin(
      schema.integrationToolCatalog,
      eq(schema.projectIntegrationConfigs.toolCatalogId, schema.integrationToolCatalog.id),
    )
    .where(
      and(
        eq(schema.projectIntegrationConfigs.projectId, projectId),
        eq(schema.projectIntegrationConfigs.categoryKey, "repo"),
      ),
    )
    .orderBy(desc(schema.projectIntegrationConfigs.updatedAt))
    .limit(1);

  if (!row) return null;
  const config = (row.config || {}) as Record<string, string>;
  if (isProjectIntegrationSkippedConfig(config)) return null;

  return {
    providerKey: row.providerKey || null,
    displayName: row.displayName || null,
    baseUrl: config.baseUrl || config.organizationUrl || "",
    repositoryId:
      config.projectId ||
      config.repositoryId ||
      config.repositorySlug ||
      config.repository ||
      "",
    repositoryName:
      config.namespacePath ||
      config.projectName ||
      config.repositoryName ||
      config.repository ||
      config.repositorySlug ||
      "",
  };
}

async function getProjectPatStatusForUser(
  project: {
    id?: string | null;
    jiraInstanceUrl?: string | null;
    goldenRepoReference?: any;
    repoIntegrationConfig?: { providerKey?: string | null } | null;
  },
  readiness: UserPatReadiness,
  userId?: string | null,
) {
  const globalStatus = getProjectPatStatus(project, readiness);
  const projectId = getProjectReadinessProjectId(project);
  const projectManagementPatConfigured = globalStatus.projectManagementPatConfigured;
  const repoProvider = getProjectRepoProvider(project);
  const projectRepoPatConfigured = globalStatus.repoPatRequired
    ? globalStatus.repoPatConfigured ||
      await hasProjectRepoCredential(userId, projectId, repoProvider)
    : false;
  const projectRepoPatSatisfied = !globalStatus.repoPatRequired || projectRepoPatConfigured;
  const userCredentialStatus = {
    ...globalStatus,
    projectManagementPatConfigured,
    repoPatConfigured: projectRepoPatConfigured,
    repoPatSatisfied: projectRepoPatSatisfied,
    userGitlabPatConfigured: globalStatus.repoPatRequired ? projectRepoPatConfigured : false,
    userPatConfigured: projectManagementPatConfigured && projectRepoPatSatisfied,
  };
  const projectUserPatConfigured = userCredentialStatus.userPatConfigured;

  return {
    ...userCredentialStatus,
    credentialStatus: {
      jira: {
        required: userCredentialStatus.credentialStatus.jira.required,
        configured: projectManagementPatConfigured,
      },
      repo: {
        required: userCredentialStatus.repoPatRequired,
        configured: userCredentialStatus.repoPatConfigured,
      },
      readyForUser: projectUserPatConfigured,
    },
    globalUserPatConfigured: globalStatus.userPatConfigured,
    projectUserPatConfigured,
    userPatConfigured: projectUserPatConfigured,
  };
}

async function upsertProjectReadinessRow(params: {
  userId: string;
  projectId: string;
  integrationKind: string;
  integrationId: string;
  providerKey?: string | null;
  message: string;
}) {
  const now = new Date();
  await db
    .insert(schema.userProjectIntegrationCredentials)
    .values({
      id: randomUUID(),
      userId: params.userId,
      projectId: params.projectId,
      integrationKind: params.integrationKind,
      integrationId: params.integrationId,
      providerKey: params.providerKey || null,
      lastTestStatus: "success",
      lastTestMessage: params.message,
      lastTestedAt: now,
      updatedAt: now,
    } as any)
    .onDuplicateKeyUpdate({
      set: {
        providerKey: params.providerKey || null,
        lastTestStatus: "success",
        lastTestMessage: params.message,
        lastTestedAt: now,
        updatedAt: now,
      },
    });
}

async function markProjectReadyForUser(params: {
  userId: string;
  project: { id?: string | null; jiraInstanceUrl?: string | null; goldenRepoReference?: any; integrationType?: string | null };
  patStatus: ReturnType<typeof getProjectPatStatus>;
  message?: string;
}) {
  const projectId = getProjectReadinessProjectId(params.project);
  if (!projectId || !params.patStatus.userPatConfigured) return;

  const message = params.message || "Personal credentials validated for this project.";
  await upsertProjectReadinessRow({
    userId: params.userId,
    projectId,
    integrationKind: PROJECT_READINESS_KIND,
    integrationId: PROJECT_READINESS_ID,
    message,
  });

  if (params.patStatus.projectManagementPatConfigured) {
    await upsertProjectReadinessRow({
      userId: params.userId,
      projectId,
      integrationKind: "project-management",
      integrationId: "default",
      providerKey: params.project.integrationType === "jira" ? "jira" : "ado",
      message,
    });
  }

  if (requiresProjectRepoPat(params.project) && params.patStatus.repoPatConfigured) {
    const repoIdentity = getProjectRepoReadinessIdentity(params.project);
    await upsertProjectReadinessRow({
      userId: params.userId,
      projectId,
      integrationKind: "repository",
      integrationId: repoIdentity.integrationId,
      providerKey: repoIdentity.providerKey,
      message,
    });
  }
}

function isPersonalGitCredentialError(error: unknown): boolean {
  const message = error instanceof Error ? error.message.toLowerCase() : String(error || "").toLowerCase();
  return (
    message.includes("personal") ||
    message.includes("no active") ||
    message.includes("credential") ||
    message.includes("pat/api key") ||
    message.includes("signed-in user")
  );
}

async function assertProjectReadyForUser(project: any, userId: string) {
  if (!project || project.deletedFromAdo) {
    return { ok: false as const, status: 404, error: "Project not found" };
  }

  const visibleProjects = await sdlcService.getAllProjects(userId);
  if (!visibleProjects.some((visibleProject) => visibleProject.id === project.id)) {
    return { ok: false as const, status: 403, error: "You do not have access to this project" };
  }

  const patReadiness = await getUserPatReadiness(userId);
  const projectWithRepoIntegration = {
    ...project,
    repoIntegrationConfig: project.repoIntegrationConfig || await getProjectRepoIntegrationConfig(project.id),
  };
  const patStatus = await getProjectPatStatusForUser(projectWithRepoIntegration, patReadiness, userId);
  if (!patStatus.userPatConfigured) {
    return {
      ok: false as const,
      status: 428,
      error:
        "Project is not synced for your user. Configure and validate your personal project management and repository provider credentials before opening this project.",
      patStatus,
    };
  }

  return { ok: true as const, patStatus };
}

function getGitlabBaseUrlFromProject(project: { goldenRepoReference?: any } | null | undefined): string | undefined {
  const ref = project?.goldenRepoReference;
  const repoUrl = typeof ref?.repoUrl === "string" ? ref.repoUrl : "";
  if (!repoUrl || ref?.provider !== "gitlab") return undefined;
  try {
    const parsed = new URL(repoUrl);
    return `${parsed.protocol}//${parsed.host}`.replace(/\/+$/, "");
  } catch {
    return undefined;
  }
}


type CachedValue<T> = {
  expiresAt: number;
  value: T;
};

const DASHBOARD_METRICS_CACHE_TTL_MS = 30 * 1000;
const LIVE_PROJECT_COUNT_CACHE_TTL_MS = 60 * 1000;
const LIVE_GOLDEN_REPO_COUNT_CACHE_TTL_MS = 60 * 1000;
const dashboardMetricsCache = new Map<string, CachedValue<any>>();
const liveProjectCountCache = new Map<string, CachedValue<any>>();
const liveGoldenRepoCountCache = new Map<string, CachedValue<any>>();

function getCachedValue<T>(cache: Map<string, CachedValue<T>>, key: string): T | null {
  const entry = cache.get(key);
  if (!entry) {
    return null;
  }

  if (entry.expiresAt <= Date.now()) {
    cache.delete(key);
    return null;
  }

  return entry.value;
}

function setCachedValue<T>(cache: Map<string, CachedValue<T>>, key: string, value: T, ttlMs: number) {
  cache.set(key, {
    value,
    expiresAt: Date.now() + ttlMs,
  });
}



