// Deterministic parser for extracting functional requirements (FR-* or MLDP-*) from
// the "Requirements" section of a generated BRD JSON document.
// Supports top-level sections and subsections. Uses primary pattern (FR/MLDP) with
// fallback to generic requirement IDs when primary doesn't match.

/** Collect content from a section and all its subsections (recursive) */
function collectRequirementsContent(section: any): string[] {
  const chunks: string[] = [];
  if (!section) return chunks;

  const content = typeof section.content === "string" ? section.content.trim() : "";
  if (content) chunks.push(content);

  const subsections = Array.isArray(section.subsections) ? section.subsections : [];
  for (const sub of subsections) {
    chunks.push(...collectRequirementsContent(sub));
  }
  return chunks;
}

const REQUIREMENT_SKIP_HEADER_WORDS = new Set([
  "req id", "requirement", "description", "id", "requirement id", "requirement description",
  "term/acronym", "term", "acronym", "definition", "stakeholder", "kpi",
  "target", "measurement method", "role", "responsibilities", "integration",
  "impact", "likelihood", "mitigation strategy", "milestone", "target date",
].map((w) => w.toLowerCase()));

// Accept requirement IDs in all common variants/cases:
// fr-01, fr-001, fr01, fr001, nfr-01, tr01, ir001, req-01, r01, mldp-01, br-01, dr-01
// Also compound IDs like BR-AUTH-001, NFR-PERF-01
const REQUIREMENT_ID_PREFIX = "(?:FR|MLDP|NFR|TR|IR|BR|DR|REQ|R)";

function normalizeRequirementId(raw: string): string {
  const value = String(raw || "").trim().replace(/\s+/g, "");
  const match = value.match(/^([a-z]+)-?(\d+)$/i);
  if (!match) return value.toUpperCase();
  return `${match[1].toUpperCase()}-${match[2]}`;
}

/** Parse markdown table rows from content using the given row matcher */
function parseTableRows(
  content: string,
  rowRegex: RegExp,
  brdId?: string,
  options?: { skipHeaderWords?: string[] },
): Array<{ name: string; description: string }> {
  const results: Array<{ name: string; description: string }> = [];
  const skipHeaderWords = options?.skipHeaderWords
    ? new Set(options.skipHeaderWords.map((w) => w.toLowerCase()))
    : REQUIREMENT_SKIP_HEADER_WORDS;

  const lines = content.split(/\r?\n/);
  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!line || line.match(/^\s*\|[\s\-:|]+\|\s*$/)) continue; // skip empty, separator rows

    if (!rowRegex.test(line)) continue;

    const cells = line
      .split("|")
      .map((c: string) => c.trim())
      .filter((c: string) => c.length > 0);

    if (cells.length < 2) continue;

    const name = cells[0];
    const description = cells[1];
    if (!name || !description) continue;

    if (skipHeaderWords.has(name.toLowerCase())) continue;

    results.push({ name, description });
  }
  return results;
}

/** Parse tab or space-delimited requirement rows (e.g. "FR1\tAbility to..." or "FR1  Ability to...") */
function parseTabOrSpaceDelimitedRequirementRows(
  content: string,
): Array<{ name: string; description: string }> {
  const results: Array<{ name: string; description: string }> = [];
  const idLike = /^(?:\d+\.?\s*$|[A-Z]{1,8}[- ]?\d+)$/i;
  const lines = content.split(/\r?\n/);

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!line) continue;

    // Try tab first, then 2+ spaces
    let cells: string[] = line.split(/\t/).map((c: string) => c.trim()).filter((c: string) => c.length > 0);
    if (cells.length < 2) {
      cells = line.split(/\s{2,}/).map((c: string) => c.trim()).filter((c: string) => c.length > 0);
    }
    if (cells.length < 2) {
      // Fallback A: match "FR1 Ability to..." (ID at start + space + rest is description)
      // Fallback B: match "FR-01: Ability to..." or "FR-01 - Ability to..."
      const match = line.match(/^([A-Z]{1,8}[\s\-]*\d+)\s*(?::|-)?\s+(.+)$/i);
      if (match) {
        cells = [match[1].trim(), match[2].trim()];
      }
    }
    if (cells.length < 2) continue;

    const name = cells[0];
    const description = cells.slice(1).join(" ").trim(); // Join rest in case split created multiple parts
    if (!name || !description) continue;
    if (REQUIREMENT_SKIP_HEADER_WORDS.has(name.toLowerCase())) continue;
    if (!idLike.test(name) && !(name.length <= 20 && /\d/.test(name))) continue;

    results.push({ name: normalizeRequirementId(name), description });
  }
  return results;
}

function respondWithJiraCredentialError(res: Response, error: unknown): boolean {
  if (!isUserJiraCredentialError(error)) return false;
  res.status(userJiraCredentialHttpStatus(error)).json({
    error: userJiraCredentialMessage(error),
    details: error instanceof Error ? error.message : String(error),
  });
  return true;
}

/** Parse loose multi-line requirement blocks like:
 * FR-\n01 <description...> or NFR-02 <description...>
 */
function parseLooseRequirementBlocks(
  content: string,
): Array<{ name: string; description: string }> {
  const results: Array<{ name: string; description: string }> = [];
  if (!content || !content.trim()) return results;

  const normalized = content
    // Join split IDs across wrapped lines (e.g. FR-\n01 -> FR-01)
    .replace(/\b(FR|NFR|TR|IR|BR|DR|REQ|R|MLDP)\s*-\s*\r?\n\s*(\d{1,4})\b/gi, "$1-$2")
    .replace(/\b(FR|NFR|TR|IR|BR|DR|REQ|R|MLDP)\s*\r?\n\s*(\d{1,4})\b/gi, "$1-$2")
    // Normalize bullets/spaces
    .replace(/[•·]/g, "-")
    .replace(/\t/g, " ")
    .replace(/\u00a0/g, " ");

  const lines = normalized.split(/\r?\n/).map((l) => l.trim()).filter(Boolean);
  const idStart = new RegExp(
    `^(?:[-*]\\s*)?((?:${REQUIREMENT_ID_PREFIX})[\\s\\-]*(?:[A-Z]+-)?\\d{1,6})\\b[:.)-]?\\s*(.*)$`,
    "i",
  );

  let currentId: string | null = null;
  let currentDescParts: string[] = [];

  const flush = () => {
    if (!currentId) return;
    const description = currentDescParts.join(" ").replace(/\s+/g, " ").trim();
    if (description && !REQUIREMENT_SKIP_HEADER_WORDS.has(currentId.toLowerCase())) {
      results.push({ name: currentId, description });
    }
    currentId = null;
    currentDescParts = [];
  };

  for (const line of lines) {
    const m = line.match(idStart);
    if (m) {
      flush();
      currentId = normalizeRequirementId(m[1]);
      const initial = (m[2] || "").trim();
      if (initial) currentDescParts.push(initial);
      continue;
    }

    // Continue accumulating description lines for active requirement
    if (currentId) {
      // Stop if we hit a clear non-requirement heading
      if (/^\d+(?:\.\d+){0,3}\s+/.test(line) || /^#{1,6}\s+/.test(line)) {
        flush();
        continue;
      }
      currentDescParts.push(line);
    }
  }

  flush();
  return results;
}

/** Parse requirement rows from text that came from table extraction where columns are flattened.
 * Supports patterns like:
 * "FR-01 The system shall ... (Queue Monitoring) High"
 * "NFR-02 ... Medium"
 */
function parseFlattenedTableRequirementRows(
  content: string,
): Array<{ name: string; description: string }> {
  const results: Array<{ name: string; description: string }> = [];
  if (!content || !content.trim()) return results;

  const normalized = content
    .replace(/\b(FR|NFR|TR|IR|BR|DR|REQ|R|MLDP)\s*-\s*\r?\n\s*(\d{1,4})\b/gi, "$1-$2")
    .replace(/\b(FR|NFR|TR|IR|BR|DR|REQ|R|MLDP)\s*\r?\n\s*(\d{1,4})\b/gi, "$1-$2")
    .replace(/\u00a0/g, " ");

  const lines = normalized.split(/\r?\n/).map((l) => l.trim()).filter(Boolean);
  const idStart = new RegExp(
    `^((?:${REQUIREMENT_ID_PREFIX})[\\s\\-]*(?:[A-Z]+-)?\\d{1,6})\\b[:.)-]?\\s*(.*)$`,
    "i",
  );
  const priorityTail = /\b(High|Medium|Low|Critical)\s*$/i;

  let currentId: string | null = null;
  let currentDesc: string[] = [];

  const flush = () => {
    if (!currentId) return;
    let description = currentDesc.join(" ").replace(/\s+/g, " ").trim();
    description = description.replace(priorityTail, "").trim();
    if (description) {
      results.push({ name: currentId, description });
    }
    currentId = null;
    currentDesc = [];
  };

  for (const line of lines) {
    const m = line.match(idStart);
    if (m) {
      flush();
      currentId = normalizeRequirementId(m[1]);
      const rest = (m[2] || "").trim();
      if (rest) currentDesc.push(rest);
      continue;
    }
    if (currentId) {
      if (/^(ID|Requirement Description|Priority)$/i.test(line)) continue;
      if (/^\d+(?:\.\d+){0,3}\s+/.test(line) || /^#{1,6}\s+/.test(line)) {
        flush();
        continue;
      }
      currentDesc.push(line);
    }
  }

  flush();
  return results;
}

/** Exported for testing */
export function parseRequirementsFromBrdJson(
  brdJson: any,
  brdId?: string,
): Array<{ name: string; description: string }> {
  const seen = new Set<string>();
  const addUnique = (r: { name: string; description: string }) => {
    const key = `${r.name}:${r.description}`;
    if (seen.has(key)) return;
    seen.add(key);
    results.push(r);
  };

  const results: Array<{ name: string; description: string }> = [];

  if (!brdJson || !Array.isArray((brdJson as any).sections)) {
    return results;
  }

  // Find Requirements section - try Functional Requirements first, then generic Requirements
  const isRequirementLikeTitle = (title: string): boolean => {
    const t = (title || "").toLowerCase().trim();
    return (
      t.includes("requirements") ||
      t.includes("functional requirement") ||
      t.includes("non-functional requirement") ||
      t.includes("non functional requirement") ||
      t.includes("technical requirement") ||
      t.includes("integration requirement") ||
      t.includes("business rule") ||
      t.includes("data requirement") ||
      /^(\d+\.)+\s*(functional|non[- ]?functional|technical|integration|business\s+rule|data\s+requirement)/i.test(t)
    );
  };

  const isRequirementsSection = (s: any) => {
    if (!s || typeof s.title !== "string") return false;
    const t = s.title.toLowerCase().trim();
    return (
      (t.includes("functional requirements") && !t.includes("non-functional") && !t.includes("business requirements document")) ||
      ((t.match(/^\d+\.\s*requirements?/) || t === "requirements") &&
        !t.includes("business requirements document") &&
        !t.includes("non-functional") &&
        !t.includes("brd"))
    );
  };

  let requirementsSection = (brdJson as any).sections.find(
    (s: any) => isRequirementsSection(s),
  );

  // Collect content from best matching section(s)
  let contentChunks: string[] = [];
  if (requirementsSection) {
    contentChunks.push(...collectRequirementsContent(requirementsSection));
  }

  // If flat structure (no subsections), also gather content from following sibling sections
  // e.g. "4.1 Functional Requirements", "4.2 Non-Functional Requirements", etc.
  const sections = (brdJson as any).sections as any[];
  const reqIndex = requirementsSection
    ? sections.findIndex((s: any) => s === requirementsSection)
    : -1;
  if (reqIndex >= 0) {
    const isRequirementSubsection = (s: any) => {
      if (!s || typeof s.title !== "string") return false;
      const t = s.title.toLowerCase().trim();
      return (
        /^\d+\.\d+\s/.test(s.title.trim()) ||
        t.includes("functional requirements") ||
        t.includes("non-functional requirements") ||
        t.includes("technical requirements") ||
        t.includes("integration requirements")
      );
    };
    for (let i = reqIndex + 1; i < sections.length; i++) {
      if (!isRequirementSubsection(sections[i])) break;
      const subContent = typeof sections[i].content === "string" ? sections[i].content.trim() : "";
      if (subContent) contentChunks.push(subContent);
    }
  }

  // Fallback A: if no canonical section found, gather all requirement-like titled sections
  if (contentChunks.length === 0) {
    for (const s of sections) {
      if (!s || typeof s.title !== "string") continue;
      if (!isRequirementLikeTitle(s.title)) continue;
      contentChunks.push(...collectRequirementsContent(s));
    }
  }

  // Fallback B: if still empty, scan all sections (covers documents with atypical headings)
  if (contentChunks.length === 0) {
    for (const s of sections) {
      contentChunks.push(...collectRequirementsContent(s));
    }
  }

  const allContent = contentChunks.join("\n\n");
  const allSectionsContent = sections
    .flatMap((s: any) => collectRequirementsContent(s))
    .join("\n\n");

  if (!allContent.trim() && !allSectionsContent.trim()) {
    return results;
  }

  // Primary: FR/MLDP/NFR/TR/IR/BR/DR/REQ/R - markdown pipe format
  // Supports simple IDs (FR-01) and compound IDs (BR-AUTH-001)
  const primaryRegex = new RegExp(
    `^\\s*\\|\\s*(${REQUIREMENT_ID_PREFIX})[\\s\\-]*(?:[A-Z]+-)?\\d+[^|]*\\|`,
    "i",
  );
  let parsed = parseTableRows(allContent, primaryRegex, brdId);

  if (parsed.length > 0) {
    for (const r of parsed) addUnique(r);
  } else {
    // Fallback 1: generic pipe-delimited rows
    const fallbackRegex = /^\s*\|[^|]+\|[^|]+\|/;
    const fallbackParsed = parseTableRows(allContent, fallbackRegex, brdId);
    const idLike = /^(?:\d+\.?\s*$|[A-Z]{1,8}[- ]?\d+)$/i;
    for (const r of fallbackParsed) {
      const name = normalizeRequirementId(r.name.trim());
      if (idLike.test(name) || (name.length <= 20 && /\d/.test(name))) {
        addUnique({ ...r, name });
      }
    }

    // Fallback 2: tab-delimited format (e.g. from DOCX/PDF export: "FR1\tDescription")
    if (results.length === 0) {
      const tabParsed = parseTabOrSpaceDelimitedRequirementRows(allContent);
      for (const r of tabParsed) addUnique(r);
    }

    // Fallback 3: loose multiline blocks (e.g. FR-\n01 in PDF/DOCX wrapped text)
    if (results.length === 0) {
      const blockParsed = parseLooseRequirementBlocks(allContent);
      for (const r of blockParsed) addUnique(r);
    }

    // Fallback 4: flattened table rows with trailing priority column text
    if (results.length === 0) {
      const flattenedParsed = parseFlattenedTableRequirementRows(allContent);
      for (const r of flattenedParsed) addUnique(r);
    }
  }

  // Final safety-net: if requirement-scoped content still yields nothing,
  // scan ALL BRD text so parent heading variations won't block extraction.
  if (results.length === 0 && allSectionsContent.trim()) {
    const globalPrimary = parseTableRows(allSectionsContent, primaryRegex, brdId);
    for (const r of globalPrimary) addUnique(r);

    if (results.length === 0) {
      const globalFallbackRegex = /^\s*\|[^|]+\|[^|]+\|/;
      const globalFallback = parseTableRows(allSectionsContent, globalFallbackRegex, brdId);
      const idLike = /^(?:\d+\.?\s*$|[A-Z]{1,8}[- ]?\d+)$/i;
      for (const r of globalFallback) {
        const name = normalizeRequirementId(r.name.trim());
        if (idLike.test(name) || (name.length <= 20 && /\d/.test(name))) {
          addUnique({ ...r, name });
        }
      }
    }

    if (results.length === 0) {
      const globalTab = parseTabOrSpaceDelimitedRequirementRows(allSectionsContent);
      for (const r of globalTab) addUnique(r);
    }

    if (results.length === 0) {
      const globalLoose = parseLooseRequirementBlocks(allSectionsContent);
      for (const r of globalLoose) addUnique(r);
    }

    if (results.length === 0) {
      const globalFlat = parseFlattenedTableRequirementRows(allSectionsContent);
      for (const r of globalFlat) addUnique(r);
    }
  }

  if (results.length === 0) { } return results;
}

/**
 * Helper function to extract requirements from generated BRD JSON and save them to database.
 * This is called during BRD generation (not during approval) for better performance.
 * The function is idempotent - it will skip if requirements already exist.
 * Errors are logged but not thrown, so generation doesn't fail if extraction fails.
 */
async function extractAndSaveRequirementsFromBrd(
  brdId: string,
  projectId: string,
  generatedBrdJson: any,
): Promise<void> {
  try {// Idempotency check: skip if requirements already exist for this BRD
    const existingRequirements = await db
      .select({ id: schema.devBrdRequirements.id })
      .from(schema.devBrdRequirements)
      .where(eq(schema.devBrdRequirements.brdId, brdId))
      .limit(1);

    if (existingRequirements.length > 0) {
      return;
    }

    // Handle case where JSON might be stored as string in database
    let brdJson = generatedBrdJson;
    if (brdJson && typeof brdJson === "string") {
      try {
        brdJson = JSON.parse(brdJson);
      } catch (parseError) {
        console.error(
          "[Routes][DEV-BRD][Requirements] Failed to parse generated_brd_json string:",
          parseError,
        );
        return;
      }
    }

    if (!brdJson) {
      return;
    }

    if (!projectId) {
      return;
    }

    const parsedRequirements = parseRequirementsFromBrdJson(brdJson, brdId);
    if (parsedRequirements.length === 0) {
      return;
    }

    await db.insert(schema.devBrdRequirements).values(
      parsedRequirements.map((req) => ({
        projectId,
        brdId,
        requirementName: String(req.name).trim(),
        description: String(req.description),
        priority: "medium",
        acceptanceCriteria: null,
        status: "new",
      })),
    );

    console.log(
      "[Routes][DEV-BRD][Requirements] Successfully inserted",
      parsedRequirements.length,
      "requirement(s) into dev_brd_requirements for BRD",
      brdId,

      "during generation",
    );
  } catch (error) {
    // Log but do not throw - generation should not fail if requirement extraction fails
    console.error(
      "[Routes][DEV-BRD][Requirements] Failed to extract/insert BRD requirements during generation:",
      error,
    );
    console.error(
      "[Routes][DEV-BRD][Requirements] Error stack:",
      error instanceof Error ? error.stack : "No stack trace",
    );
    // Don't throw - this is a non-critical operation
  }
}

// Document parsing functions have been moved to helper/brd-document-parser.ts

type ArtifactCollections = {
  epics: any[];
  features: any[];
  userStories: any[];
};

const normalizeArtifactArray = (items: any): any[] => (Array.isArray(items) ? items : []);

// ================================
// Created for Conversational UI history feature
// ================================
const unixNow = () => Math.floor(Date.now() / 1000);

const ensureModifiedItems = (
  items?: ModifiedArtifactItems | string | null
): ModifiedArtifactItems => {
  let parsed: ModifiedArtifactItems | null = null;
  if (typeof items === "string") {
    try {
      parsed = JSON.parse(items);
    } catch (error) {
      parsed = null;
    }
  } else if (items && typeof items === "object") {
    parsed = items as ModifiedArtifactItems;
  }

  return {
    epics: Array.from(new Set(parsed?.epics ?? [])),
    features: Array.from(new Set(parsed?.features ?? [])),
    userStories: Array.from(new Set(parsed?.userStories ?? [])),
  };
};

const summarizeArtifactTotals = (
  epics?: any[],
  features?: any[],
  userStories?: any[]
): number =>
  normalizeArtifactArray(epics).length +
  normalizeArtifactArray(features).length +
  normalizeArtifactArray(userStories).length;

const getArtifactIdentifier = (item: any, fallbackIndex: number, prefix: string): string | null => {
  if (!item || typeof item !== "object") {
    return `${prefix}-${fallbackIndex}`;
  }

  // Always prioritize the actual id field if it exists - this is the most reliable identifier
  if (item.id !== undefined && item.id !== null) {
    const idStr = String(item.id).trim();
    if (idStr.length > 0) {
      return idStr;
    }
  }

  // Fallback to title-based identifier if no id
  if (typeof item.title === "string" && item.title.trim().length > 0) {
    return `${prefix}-${item.title.trim()}-${fallbackIndex}`;
  }

  // Last resort: use index-based identifier
  return `${prefix}-${fallbackIndex}`;
};

const detectChangedArtifactIds = (previous: any[], next: any[], prefix: string): string[] => {
  const previousMap = new Map<string, { item: any; identifier: string }>();
  previous.forEach((item, index) => {
    const id = getArtifactIdentifier(item, index, prefix);
    if (id) {
      previousMap.set(id, { item, identifier: id });
    }
  });

  const changedIds = new Set<string>();
  const debugInfo: { new: string[]; changed: string[]; unchanged: number } = {
    new: [],
    changed: [],
    unchanged: 0,
  };

  next.forEach((item, index) => {
    const id = getArtifactIdentifier(item, index, prefix);
    if (!id) {
      return;
    }

    const previousEntry = previousMap.get(id);
    if (!previousEntry) {
      // New item - mark as changed
      debugInfo.new.push(id);
      changedIds.add(id);
      return;
    }

    const previousItem = previousEntry.item;
    try {
      // Deep comparison - normalize both objects for comparison
      // Sort keys to ensure consistent comparison
      const prevKeys = Object.keys(previousItem).sort();
      const nextKeys = Object.keys(item).sort();
      const prevStr = JSON.stringify(previousItem, prevKeys);
      const nextStr = JSON.stringify(item, nextKeys);

      if (prevStr !== nextStr) {
        debugInfo.changed.push(id);
        changedIds.add(id);
      } else {
        debugInfo.unchanged++;
      }
    } catch (error) {
      // Fall back to marking as changed if serialization fails
      changedIds.add(id);
    }
  });

  const result = Array.from(changedIds);
  return result;
};

const mergeModifiedArtifacts = (
  existing: ModifiedArtifactItems,
  changes: ModifiedArtifactItems
): ModifiedArtifactItems => ({
  epics: Array.from(new Set([...existing.epics, ...changes.epics])),
  features: Array.from(new Set([...existing.features, ...changes.features])),
  userStories: Array.from(new Set([...existing.userStories, ...changes.userStories])),
});

const getBaselineArtifactMetadata = (
  epics?: any[],
  features?: any[],
  userStories?: any[]
) => {
  const totalCount = summarizeArtifactTotals(epics, features, userStories);
  const modifiedItems = ensureModifiedItems();

  return {
    totalCount,
    modifiedItems,
    modifiedCount: 0,
    isModified: false,
  };
};

const computeModifiedArtifactMetadata = (
  existingArtifact: any | null,
  updatedCollections: ArtifactCollections
) => {
  const previousCollections: ArtifactCollections = {
    epics: normalizeArtifactArray(existingArtifact?.epics),
    features: normalizeArtifactArray(existingArtifact?.features),
    userStories: normalizeArtifactArray(existingArtifact?.userStories),
  };

  const changedEpics = detectChangedArtifactIds(previousCollections.epics, updatedCollections.epics, "epic");
  const changedFeatures = detectChangedArtifactIds(previousCollections.features, updatedCollections.features, "feature");
  const changedStories = detectChangedArtifactIds(previousCollections.userStories, updatedCollections.userStories, "story");

  const existingModifiedItems = ensureModifiedItems(existingArtifact?.modifiedItems);
  const mergedModifiedItems = mergeModifiedArtifacts(existingModifiedItems, {
    epics: changedEpics,
    features: changedFeatures,
    userStories: changedStories,
  });

  const totalCount = summarizeArtifactTotals(
    updatedCollections.epics,
    updatedCollections.features,
    updatedCollections.userStories
  );

  const modifiedCount =
    mergedModifiedItems.epics.length +
    mergedModifiedItems.features.length +
    mergedModifiedItems.userStories.length;

  return {
    totalCount,
    modifiedItems: mergedModifiedItems,
    modifiedCount,
    isModified: modifiedCount > 0,
  };
};

// Unified helper function to get Azure DevOps config for ALL phases
// Priority: Artifact Organizations (Client Settings) > SDLC Settings > Environment Variables > Golden Repository
async function getAzureDevOpsConfig(projectName?: string, organization?: string): Promise<AzureConfig | null> {
  // Primary: Check Artifact Organizations (where Azure DevOps config is stored in Hub Artifacts)
  try {
    const artifactOrgs = await storage.getArtifactOrganizations();

    // If a projectName or organization was provided, enforce strict matching: only use an artifact org
    // whose projectName and organization match the requested values. Do NOT fallback to the first
    // artifact org if none match — that would cause a different project's config to be used.
    const strictMatchRequested = !!(projectName || organization);

    let targetOrg;
    if (organization || projectName) {
      // Match by organization first (if provided), then by projectName (if organization not provided)
      // This allows using the correct PAT token from the artifact org while using the selected project's name
      targetOrg = artifactOrgs.find(org => {
        // Extract organization name from URL for comparison
        let orgName = org.organizationUrl;
        if (orgName.includes('dev.azure.com')) {
          orgName = orgName.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '').split('/')[0];
        } else if (orgName.includes('visualstudio.com')) {
          const match = orgName.match(/([^\.]+)\.visualstudio\.com/);
          if (match) {
            orgName = match[1];
          }
        }
        orgName = orgName.replace(/\/+$/, '').trim();

        // If organization is provided, match by organization only (we'll use query projectName for API calls)
        if (organization) {
          const orgMatches = orgName === organization || orgName.toLowerCase() === organization.toLowerCase();
          return orgMatches && org.patToken;
        }

        // If only projectName is provided (no organization), match by projectName
        if (projectName) {
          const projectMatches = org.projectName === projectName || org.projectName?.toLowerCase() === projectName.toLowerCase();
          return projectMatches && org.patToken;
        }

        return false;
      });

      if (!targetOrg && strictMatchRequested) {
        targetOrg = undefined;
      }
    }
    // Only use the first available artifact org when no projectName or organization was requested
    if (!targetOrg && !strictMatchRequested) {
      targetOrg = artifactOrgs.find(org => org.patToken);
    }

    if (targetOrg) {

      if (targetOrg.patToken) {
        const decryptedPAT = safeDecryptPAT(targetOrg.patToken);
        if (decryptedPAT) {
          // Extract organization name from URL
          let orgName = targetOrg.organizationUrl;
          if (orgName.includes('dev.azure.com')) {
            orgName = orgName.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '').split('/')[0];
          } else if (orgName.includes('visualstudio.com')) {
            const match = orgName.match(/([^\.]+)\.visualstudio\.com/);
            if (match) {
              orgName = match[1];
            }
          }
          // Remove any trailing slashes
          orgName = orgName.replace(/\/+$/, '').trim();

          // Use projectName parameter if provided (from selected project), otherwise use artifact org's projectName
          const projectToUse = projectName || targetOrg.projectName;
          return {
            organization: orgName,
            project: projectToUse,
            pat: decryptedPAT,
          };
        } else {
        }
      } else {
      }
    } else {
    }
  } catch (error) {
    console.error('[Azure DevOps] Error fetching Artifact Organizations:', error);
  }

  // Fallback: Check SDLC settings in database
  try {
    const settings = await db.select().from(sdlcSettings).limit(1);
    if (settings.length > 0) {
      const setting = settings[0];
      if (setting.organizationName && setting.projectName && setting.patToken && (!projectName || setting.projectName === projectName || setting.projectName?.toLowerCase() === projectName?.toLowerCase())) {
        const decryptedPAT = safeDecryptPAT(setting.patToken);
        if (decryptedPAT) {
          // Extract organization name if it's a URL, otherwise use as-is
          let orgName = setting.organizationName;
          if (orgName.includes('dev.azure.com')) {
            orgName = orgName.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '');
          } else if (orgName.includes('visualstudio.com')) {
            const match = orgName.match(/([^\.]+)\.visualstudio\.com/);
            if (match) {
              orgName = match[1];
            }
          }
          // Remove any trailing slashes
          orgName = orgName.replace(/\/+$/, '');

          return {
            organization: orgName,
            project: setting.projectName,
            pat: decryptedPAT,
          };
        }
      }
    }
  } catch (error) {
  }

  // Fallback to environment variables
  const envOrg = process.env.ADO_ORG || process.env.ADO_ORGANIZATION || process.env.ADO_ORG_URL;
  const envProject = process.env.ADO_PROJECT || process.env.ADO_PROJECT_NAME;
  const envPat = process.env.ADO_PAT || process.env.ADO_TOKEN;

  if (envOrg && envProject && envPat) {
    if (!projectName || envProject === projectName || envProject?.toLowerCase() === projectName?.toLowerCase()) {
      const orgCandidate = envOrg.replace(/\/$/, '').split('/').pop()!;
      return {
        organization: orgCandidate,
        project: envProject,
        pat: envPat,
      };
    }
  }

  // Last fallback: Golden Repository Organizations
  const goldenOrgs = await storage.getGoldenRepoOrganizations();
  let firstOrg = null;
  if (projectName) {
    firstOrg = goldenOrgs.find(org => org.projectName === projectName && org.patToken);
    if (!firstOrg) {
      firstOrg = goldenOrgs.find(org => org.projectName?.toLowerCase() === projectName.toLowerCase() && org.patToken);
    }
    if (!firstOrg) {
    }
  }
  // Only use the first golden org when no specific project was requested
  if (!firstOrg && !projectName) {
    firstOrg = goldenOrgs[0];
  }

  if (firstOrg && firstOrg.patToken) {
    const decryptedPAT = safeDecryptPAT(firstOrg.patToken);
    if (decryptedPAT) {
      const organization = firstOrg.organizationUrl.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '');
      const adoProject = firstOrg.projectName;

      return {
        organization,
        project: adoProject,
        pat: decryptedPAT,
      };
    }
  }

  return null;
}

// ------------------------------
// Added for the conversational UI history - conversation title generation
// ------------------------------
async function generateConversationTitleWithLLM(firstMessage: string): Promise<string> {
  // Use the hosting-agnostic LLM client (Bedrock on AWS, Azure on Azure).
  if (!azureOpenAI) {
    console.warn("[Title LLM] No chat LLM configured, falling back to heuristic title");
    return fallbackTitle(firstMessage);
  }

  const systemPrompt = `
You are an assistant that generates VERY SHORT conversation titles.

Rules:
- 3 to 6 words maximum.
- Output ONLY the title text, nothing else.
- No quotes, no trailing punctuation, no emojis.
- Capture the main topic/intent of the user's request.
- Capitalize main words.

Examples:
User message: "create a epic to add a conversation history in the chat version"
Title: Epic for Conversation History

User message: "how to optimize this python code that scrapes a website"
Title: Optimize Python Web Scraper

User message: "help me design a microservice architecture for payments"
Title: Payments Microservice Architecture
`.trim();

  const userPrompt = `User first message:\n"${firstMessage}"\n\nReturn only the 3–6 word title.`;

  try {
    const response = await azureOpenAI.chat.completions.create({
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt },
      ],
      temperature: 0.3,
      max_tokens: 32,
    });

    const raw = response?.choices?.[0]?.message?.content ?? "";
    const cleaned = String(raw)
      .replace(/\r?\n/g, " ")
      .replace(/^"+|"+$/g, "")
      .replace(/[\u201C\u201D]/g, "") // smart quotes
      .trim();

    if (!cleaned) {
      return fallbackTitle(firstMessage);
    }

    // Ensure not too long
    const normalized = cleaned.replace(/\s+/g, " ");
    const finalTitle =
      normalized.length > 80 ? normalized.slice(0, 77) : normalized;
    console.log(`[Title LLM] Generated title via LLM → "${finalTitle}"`);
    return finalTitle;
  } catch (err) {
    console.error("[Title LLM] Error generating title:", err);
    return fallbackTitle(firstMessage);
  }
}

async function generateConversationSummaryWithLLM(params: {
  existingSummary: string;
  messages: { role: string; content: string }[];
}): Promise<string> {
  const { existingSummary, messages } = params;

  // Use the hosting-agnostic LLM client (Bedrock on AWS, Azure on Azure).
  if (!azureOpenAI) {
    console.warn(
      "[Summary LLM] No chat LLM configured, falling back to simple concatenation",
    );
    const messagesText = messages
      .map((m) => `${m.role.toUpperCase()}: ${m.content}`)
      .join(" | ");
    const combined =
      (existingSummary ? existingSummary + " | " : "") + messagesText;
    // hard truncate so it doesn't explode
    return combined.slice(0, 2000);
  }

  const messagesText = messages
    .map((m) => `${m.role.toUpperCase()}: ${m.content}`)
    .join("\n");

  const systemPrompt = `
You are a summarizer for an internal chat system.

Rules:
Maintain a concise, continuous summary of the entire BRD, capturing all key decisions, requirements, features, functionalities, personas, constraints, and technical details. Exclude all chit-chat, greetings, and non-essential content.
The summary has no fixed length; the LLM should determine an appropriate level of detail while ensuring that no critical information is omitted.
When a BRD is uploaded, first produce an accurate, complete, and well-structured summary.
Incorporate this summary into the workflow context and use it as the foundation for generating all workflow artifacts, including but not limited to: user stories, acceptance criteria, process workflows, text-based diagrams, test cases, and technical specifications.
/* COMMENTED OUT - Now passing full BRD document directly to LLM for artifact generation
When BRD is uploaded then all artifacts must be derived strictly from the summarized BRD, not the full document.
*/
Maintain consistency, accuracy, and alignment with the summarized requirements throughout the entire workflow.
`.trim();

  const userPrompt = `
Existing summary (may be empty):
"""${existingSummary || "None yet."}"""

New messages:
"""${messagesText}"""

Update the existing summary to include the new messages.
Return only the updated summary text.
`;

  try {
    const response = await azureOpenAI.chat.completions.create({
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt },
      ],
      temperature: 0.2,
      max_tokens: 512,
    });

    const raw = response?.choices?.[0]?.message?.content ?? "";
    const cleaned = String(raw).trim();

    if (!cleaned) {
      const messagesTextShort = messages
        .map((m) => `${m.role.toUpperCase()}: ${m.content}`)
        .join(" | ");
      const combined =
        (existingSummary ? existingSummary + " | " : "") + messagesTextShort;
      return combined.slice(0, 2000);
    }

    return cleaned;
  } catch (err) {
    console.error("[Summary LLM] Error generating summary:", err);
    const messagesTextShort = messages
      .map((m) => `${m.role.toUpperCase()}: ${m.content}`)
      .join(" | ");
    const combined =
      (existingSummary ? existingSummary + " | " : "") + messagesTextShort;
    return combined.slice(0, 2000);
  }
}

async function summariseConversation(
  conversationId: string,
  options: { force?: boolean; batchSize?: number } = {},
) {
  const { force = false, batchSize = 10 } = options;

  // 1) Load unsummarised messages (oldest first)
  const unsummarisedRows = await db
    .select({
      id: schema.messages.id,
      role: schema.messages.role,
      content: schema.messages.content,
      createdAt: schema.messages.createdAt,
    })
    .from(schema.messages)
    .where(
      and(
        eq(schema.messages.conversationId, conversationId),
        eq(schema.messages.isSummarised, false),
      ),
    )
    .orderBy(schema.messages.createdAt)
    .limit(batchSize);

  if (unsummarisedRows.length === 0) {
    return; // nothing to do
  }

  // If not forcing and we don't yet have batchSize messages, skip for now
  if (!force && unsummarisedRows.length < batchSize) {
    return;
  }

  // 2) Get existing summary (may be null)
  const existingSummaryRows = await db
    .select({ summary: schema.conversationSummaries.summary })
    .from(schema.conversationSummaries)
    .where(eq(schema.conversationSummaries.conversationId, conversationId))
    .limit(1);

  const existingSummary = existingSummaryRows[0]?.summary ?? "";

  // 3) Call Azure LLM
  const newSummary = await generateConversationSummaryWithLLM({
    existingSummary,
    messages: unsummarisedRows.map((m) => ({
      role: m.role,
      content: m.content,
    })),
  });

  const now = unixNow();

  // 4) Update summary + mark messages summarised in a transaction
  await db.transaction(async (tx) => {
    await tx
      .update(schema.conversationSummaries)
      .set({ summary: newSummary, updatedAt: now })
      .where(eq(schema.conversationSummaries.conversationId, conversationId));

    await tx
      .update(schema.messages)
      .set({ isSummarised: true })
      .where(
        inArray(
          schema.messages.id,
          unsummarisedRows.map((m) => m.id),
        ),
      );

    // keep ConversationTitles.updatedAt in sync
    await tx
      .update(schema.conversationTitles)
      .set({ updatedAt: now })
      .where(eq(schema.conversationTitles.conversationId, conversationId));
  });
}



// Simple fallback if LLM is not available
function fallbackTitle(firstMessage: string): string {
  const s = (firstMessage || "").replace(/\s+/g, " ").trim();
  if (!s) return "New conversation";
  return s.length > 60 ? s.slice(0, 57) + "..." : s;
}

// ===============================
// Load Time Tracking for Performance Metrics
// ===============================
interface LoadTimeMetric {
  endpoint: string;
  method: string;
  duration: number; // milliseconds
  timestamp: number; // Unix timestamp
  statusCode: number;
}

// In-memory store for recent load time metrics (last 100 requests)
const loadTimeMetrics: LoadTimeMetric[] = [];
const MAX_METRICS = 100;

// // Middleware to track response times for ALL endpoints


function loadTimeTrackingMiddleware(req: Request, res: Response, next: Function) {
  const start = Date.now();

  res.on("finish", () => {
    // Reduce log noise: BRD/test-plan status polling happens every ~2s while generating.
    // Keep metrics in-memory if desired, but don't print to terminal.
    if (
      req.originalUrl.startsWith("/api/brd/generate/status/") ||
      req.originalUrl.startsWith("/api/testing/test-plan/status/") ||
      req.originalUrl.startsWith("/api/jobs/") // universal async-job status polling
    ) {
      return;
    }

    const metric: LoadTimeMetric = {
      endpoint: req.originalUrl,  // better than req.path
      method: req.method,
      duration: Date.now() - start,
      timestamp: Math.floor(Date.now() / 1000),
      statusCode: res.statusCode,
    };

    loadTimeMetrics.push(metric);
    if (loadTimeMetrics.length > MAX_METRICS) {
      loadTimeMetrics.shift();
    }

  });

  next();
}

