  // Temporary debug: perform direct Azure DevOps REST call using env PAT and return raw response
  app.get('/internal/debug/ado-test', async (_req: Request, res: Response) => {
    try {
      const org = process.env.ADO_ORG;
      const project = process.env.ADO_PROJECT;
      const pat = process.env.ADO_PAT;
      if (!org || !project || !pat) return res.status(400).json({ error: 'missing_env', message: 'ADO_ORG/ADO_PROJECT/ADO_PAT required' });

      const apiUrl = `https://dev.azure.com/${org}/${project}/_apis/git/repositories?api-version=7.1-preview.1`;
      const authToken = Buffer.from(`:${pat}`).toString('base64');

      const fetchOptions: any = {
        method: 'GET',
        headers: {
          'Authorization': `Basic ${authToken}`,
          'Accept': 'application/json'
        }
      };

      // Use global fetch if available
      const nodeFetch = (globalThis as any).fetch;
      let response: any;
      if (typeof nodeFetch === 'function') {
        response = await nodeFetch(apiUrl, fetchOptions);
        const bodyText = await response.text();
        const headersObj: Record<string, string> = {};
        response.headers.forEach((v: string, k: string) => headersObj[k] = v);
        return res.status(200).json({ status: response.status, statusText: response.statusText, headers: headersObj, body: bodyText });
      } else {
        // Fallback to https.request
        const https = await import('https');
        const url = new URL(apiUrl);
        const opts = {
          hostname: url.hostname,
          path: url.pathname + url.search,
          method: 'GET',
          headers: fetchOptions.headers,
        } as any;

        const raw = await new Promise((resolve, reject) => {
          const req = https.request(opts, (resp) => {
            const chunks: Buffer[] = [];
            resp.on('data', (c) => chunks.push(Buffer.from(c)));
            resp.on('end', () => {
              const body = Buffer.concat(chunks).toString('utf8');
              const headers: Record<string, string> = {};
              Object.entries(resp.headers).forEach(([k, v]) => headers[k] = Array.isArray(v) ? v.join(';') : (v || ''));
              resolve({ statusCode: resp.statusCode, statusMessage: resp.statusMessage, headers, body });
            });
          });
          req.on('error', (err) => reject(err));
          req.end();
        });
        return res.status(200).json(raw);
      }
    } catch (err: any) {
      return res.status(500).json({ error: 'exception', message: err?.message || String(err) });
    }
  });

  // Debug: read all ADO_PAT occurrences in .env and test each one (mask returned PATs)
  app.get('/internal/debug/ado-test-multi', async (_req: Request, res: Response) => {
    try {
      const envPath = path.resolve(process.cwd(), '.env');
      let fileText = '';
      try {
        fileText = await fs.readFile(envPath, 'utf8');
      } catch (e) {
        return res.status(500).json({ error: 'no_env_file', message: `Could not read .env at ${envPath}` });
      }

      // Extract all ADO_PAT assignments (simple regex, handles quoted/unquoted)
      const patMatches = Array.from(fileText.matchAll(/^\s*ADO_PAT\s*=\s*(?:"([^"]+)"|'([^']+)'|([^\n]+))/gim));
      if (!patMatches.length) return res.status(400).json({ error: 'no_pats', message: 'No ADO_PAT entries found in .env' });

      const pats = patMatches.map(m => (m[1] || m[2] || m[3] || '').trim());
      const org = process.env.ADO_ORG || (process.env.ADO_ORG || '').trim();
      const project = process.env.ADO_PROJECT || (process.env.ADO_PROJECT || '').trim();
      if (!org || !project) return res.status(400).json({ error: 'missing_env_org_project', message: 'ADO_ORG and ADO_PROJECT required in env' });

      const apiUrl = `https://dev.azure.com/${org}/${project}/_apis/git/repositories?api-version=7.1-preview.1`;

      const results: any[] = [];
      for (let i = 0; i < pats.length; i++) {
        const pat = pats[i];
        const authToken = Buffer.from(`:${pat}`).toString('base64');
        // use fetch if available
        const nodeFetch = (globalThis as any).fetch;
        try {
          if (typeof nodeFetch === 'function') {
            const r = await nodeFetch(apiUrl, { method: 'GET', headers: { Authorization: `Basic ${authToken}`, Accept: 'application/json' } });
            results.push({ idx: i, status: r.status, statusText: r.statusText, ok: r.ok });
            continue;
          }
          const https = await import('https');
          const url = new URL(apiUrl);
          const opts = { hostname: url.hostname, path: url.pathname + url.search, method: 'GET', headers: { Authorization: `Basic ${authToken}`, Accept: 'application/json' } } as any;
          const raw = await new Promise((resolve, reject) => {
            const req = https.request(opts, (resp) => {
              resp.on('data', () => { });
              resp.on('end', () => resolve({ statusCode: resp.statusCode, statusMessage: resp.statusMessage }));
            });
            req.on('error', (err) => reject(err));
            req.end();
          });
          results.push({ idx: i, status: (raw as any).statusCode, statusText: (raw as any).statusMessage });
        } catch (err: any) {
          results.push({ idx: i, error: err?.message || String(err) });
        }
      }

      // Masked response: do not include PAT values
      return res.json({ org, project, tested: results });
    } catch (err: any) {
      return res.status(500).json({ error: 'exception', message: err?.message || String(err) });
    }
  });

