  // Internal debug: test PATs stored in artifact organizations (decrypt & test)
  app.get('/internal/debug/test-artifact-org-pats', async (_req: Request, res: Response) => {
    try {
      const orgs = await storage.getArtifactOrganizations();
      const results: any[] = [];

      for (const org of orgs) {
        const hasPat = !!org.patToken;
        const entry: any = {
          id: org.id,
          organizationUrl: org.organizationUrl,
          projectName: org.projectName,
          patConfigured: hasPat,
        };

        if (!hasPat) {
          entry.test = { skipped: true, reason: 'no_pat_configured' };
          results.push(entry);
          continue;
        }

        // Try to decrypt (or treat as plain text)
        let pat: string | null = null;
        try {
          pat = safeDecryptPAT(org.patToken as string);
        } catch (err: any) {
          entry.test = { error: 'decrypt_failed', message: err?.message || String(err) };
          results.push(entry);
          continue;
        }

        if (!pat) {
          entry.test = { error: 'empty_pat_after_decrypt' };
          results.push(entry);
          continue;
        }

        // Derive org name from organizationUrl if possible
        let orgName = '';
        try {
          const u = new URL(org.organizationUrl);
          const parts = u.pathname.split('/').filter(Boolean);
          orgName = parts[0] || '';
        } catch (e) {
          // fallback: try to trim trailing slashes
          const trimmed = (org.organizationUrl || '').replace(/https?:\/\//, '').replace(/\/$/, '');
          orgName = trimmed.split('/')[1] || trimmed.split('/')[0] || '';
        }

        const apiUrl = `https://dev.azure.com/${orgName}/_apis/projects?api-version=7.1-preview.4`;
        const authToken = Buffer.from(`:${pat}`).toString('base64');

        try {
          const nodeFetch = (globalThis as any).fetch;
          if (typeof nodeFetch === 'function') {
            const r = await nodeFetch(apiUrl, { method: 'GET', headers: { Authorization: `Basic ${authToken}`, Accept: 'application/json' } });
            entry.test = { status: r.status, statusText: r.statusText, ok: r.ok };
            results.push(entry);
            continue;
          }

          const https = await import('https');
          const url = new URL(apiUrl);
          const opts = { hostname: url.hostname, path: url.pathname + url.search, method: 'GET', headers: { Authorization: `Basic ${authToken}`, Accept: 'application/json' } } as any;
          const raw = await new Promise((resolve, reject) => {
            const req = https.request(opts, (resp) => {
              const chunks: Buffer[] = [];
              resp.on('data', (c) => chunks.push(Buffer.from(c)));
              resp.on('end', () => {
                const body = Buffer.concat(chunks).toString('utf8');
                resolve({ statusCode: resp.statusCode, statusMessage: resp.statusMessage, body });
              });
            });
            req.on('error', (err) => reject(err));
            req.end();
          });

          entry.test = { status: (raw as any).statusCode, statusText: (raw as any).statusMessage };
          results.push(entry);
        } catch (err: any) {
          entry.test = { error: err?.message || String(err) };
          results.push(entry);
        }
      }

      return res.json({ tested: results });
    } catch (err: any) {
      return res.status(500).json({ error: 'exception', message: err?.message || String(err) });
    }
  });

