  // GET all load time metrics


  app.get("/api/metrics/load-times", (req: Request, res: Response) => {
    const { endpoint, limit = "50" } = req.query;
    const limitNum = Math.min(parseInt(limit as string, 10) || 50, MAX_METRICS);

    let filtered = loadTimeMetrics;

    if (endpoint) {
      filtered = filtered.filter(m =>
        m.endpoint.includes(endpoint as string)
      );
    }

    const recent = filtered.slice(-limitNum);

    res.json({
      count: recent.length,
      metrics: recent
    });
  });


  app.get("/api/metrics/load-times/endpoint", (req: Request, res: Response) => {
    const { endpoint } = req.query;

    if (!endpoint) {
      return res.status(400).json({ error: "Missing ?endpoint= query param" });
    }

    const matches = loadTimeMetrics.filter(m =>
      m.endpoint.includes(endpoint as string)
    );

    res.json({
      endpoint,
      count: matches.length,
      avg: matches.length
        ? Math.round(matches.reduce((a, b) => a + b.duration, 0) / matches.length)
        : 0,
      min: matches.length ? Math.min(...matches.map(m => m.duration)) : 0,
      max: matches.length ? Math.max(...matches.map(m => m.duration)) : 0,
      p95: matches.length
        ? matches
          .slice()
          .sort((a, b) => a.duration - b.duration)[
          Math.floor(matches.length * 0.95)
        ]?.duration
        : 0,
      metrics: matches.slice(-50),
    });
  });

  // ============================================
  // Auth middleware: auto-bootstrap SSO users
  // ============================================
  // This runs on every /api request and is safe/idempotent:
  // - If user already exists, it does nothing
  // - If user is new, it creates the user and assigns Viewer if they have no roles
  app.use("/api", autoBootstrapUser);

  // Open an AI attribution context (AsyncLocalStorage) for every /api request,
  // seeded from req.user. The Bedrock usage recorder reads it. Must run AFTER
  // autoBootstrapUser so req.user is populated.
  const { aiContextMiddleware } = await import("./observability/ai-context");
  app.use("/api", aiContextMiddleware);

