  registerApiTestingRoutes(app, getAzureDevOpsConfig);

  // ============================================
  // Global auth enforcement for all /api routes
  // ============================================
  // Require a valid authenticated user on every /api route except
  // health-check and auth-bootstrap endpoints.
  // Paths are relative to the `/api` mount (Express strips the mount prefix in req.path).
  const AUTH_SKIP_PATHS = [
    "/health",
    "/auth/bootstrap-user",
    "/auth/me",
    "/platform/hosting",
  ];
  const AUTH_SKIP_PREFIXES = [
    "/api/recorder/", "/api/playwright/", "/api/tm/", "/api/qe/",
    "/api/autotest/", "/api/nradiverse/", "/api/test-library/", "/api/coverage/",
    "/api/demo/", "/api/java-migration/", "/api/swagger/",
    "/api/projects", "/api/sprints", "/api/sprint-user-stories",
    "/api/integrations", "/api/execution-runs", "/api/execution/", "/api/export/",
    "/api/synthetic-data/", "/api/baselines", "/api/frameworks",
    "/api/import/", "/api/jira/", "/api/tests/", "/api/sprint/",
    "/api/generate/", "/api/ado/", "/api/agent-config", "/api/analytics/",
    "/api/framework-config",
  ];
  app.use("/api", (req, res, next) => {
    if (AUTH_SKIP_PATHS.includes(req.path)) {
      return next();
    }
    const fullPath = '/api' + (req.path || '');
    if (AUTH_SKIP_PREFIXES.some(prefix => fullPath.startsWith(prefix))) {
      return next();
    }
    // QE requests are rewritten from /qe/api/* → /api/* but originalUrl is preserved
    const origUrl = req.originalUrl || '';
    if (origUrl.startsWith('/qe/api/')) {
      return next();
    }

    // Allow temporary anonymous, read-only access for Azure DevOps listing endpoints
    // Patterns allowed (GET only):
    //  - /sdlc/projects/:projectId/ado/repositories
    //  - /sdlc/projects/:projectId/ado/repositories/:repositoryId/branches
    try {
      if (req.method === 'GET') {
        const path = req.path || '';
        const repoListMatch = /^\/sdlc\/projects\/[^\/]+\/ado\/repositories$/.test(path);
        const branchesMatch = /^\/sdlc\/projects\/[^\/]+\/ado\/repositories\/[^\/]+\/branches$/.test(path);
        if (repoListMatch || branchesMatch) {
          console.warn('[Auth] Allowing temporary anonymous GET for ADO listing endpoint:', path);
          return next();
        }
      }
    } catch (e) {
      // fall through to normal auth enforcement on any error
    }

    return requireAuth(req as any, res, next);
  });

  // Profile setup is optional. Jira/Git credentials are now requested at the
  // organization/project surfaces that actually need those personal tokens.

  // In-memory storage for user information associated with releases and deployments

  // In-memory storage for acknowledged alerts (in production, use database)
  const acknowledgedAlerts = new Map<string, { alertId: string; acknowledgedAt: string; acknowledgedBy?: string }>();
  // Key: releaseId or deploymentId, Value: { createdBy/triggeredBy/deployedBy, createdByName/triggeredByName/deployedByName }
  const releaseUserInfo = new Map<number, { createdBy?: string; createdByName?: string; triggeredBy?: string; triggeredByName?: string }>();
  const deploymentUserInfo = new Map<number, { deployedBy?: string; deployedByName?: string }>();

  // ============================================
  // Job Management System for Long-Running Artifact Generation
  // ============================================
  interface ArtifactGenerationJob {
    jobId: string;
    sessionId?: string;
    status: 'pending' | 'processing' | 'completed' | 'failed' | 'cancelled';
    progress: number;
    step: string;
    createdAt: Date;
    completedAt?: Date;
    result?: any;
    error?: string;
    qualityReport?: any;
    generationLogs?: Array<{ message: string; timestamp: string }>;
    warnings?: string[];
    personaSource?: 'From Golden Repo' | 'From Persona Hub' | 'AI Suggested (Fallback)';
    domainExpertAnalysis?: {
      domain: string;
      domainAnalysis: string;
      domainSource?: 'golden-repo-file' | 'ai-analysis';
    };
    // LLM Council specific fields
    councilData?: {
      responses?: Array<{
        id: string;
        provider: string;
        model: string;
        response: any;
        confidence: number;
        coverage: number;
        consistency: number;
        timestamp: Date;
      }>;
      evaluation?: {
        selectedResponseId: string;
        reasoning: string;
        confidenceScore: number;
        evaluationDetails: any;
      };
      councilStep?: string;
    };
  }

  const artifactGenerationJobs = new Map<string, ArtifactGenerationJob>();

  type ArtifactJobKind = "single" | "council";

  function setAsyncStatusPollingHeaders(res: Response) {
    res.setHeader("Cache-Control", "no-store, no-cache, must-revalidate, proxy-revalidate");
    res.setHeader("Pragma", "no-cache");
    res.setHeader("Expires", "0");
    res.setHeader("Surrogate-Control", "no-store");
    res.setHeader("X-Accel-Buffering", "no");
  }

  /** Persist artifact generation job snapshot to MySQL so jobs survive restarts and cross-instance polling. */
  async function persistArtifactGenerationJob(
    job: ArtifactGenerationJob,
    kind: ArtifactJobKind = job.councilData ? "council" : "single",
  ): Promise<void> {
    try {
      const row: any = {
        jobId: job.jobId,
        sessionId: job.sessionId,
        jobType: kind,
        status: job.status,
        progress: Math.round(job.progress ?? 0),
        step: job.step,
        createdAt: job.createdAt ?? new Date(),
        completedAt: job.completedAt,
        result: job.result != null ? JSON.stringify(job.result) : null,
        error: job.error ?? null,
        qualityReport: (job as any).qualityReport ?? null,
        generationLogs: job.generationLogs ?? null,
        domainExpertAnalysis: (job as any).domainExpertAnalysis ?? null,
        councilData: job.councilData ?? null,
      };

      await db
        .insert(schema.artifactGenerationJobRecords)
        .values(row as any)
        .onDuplicateKeyUpdate({
          set: {
            status: row.status,
            progress: row.progress,
            step: row.step,
            completedAt: row.completedAt,
            result: row.result,
            error: row.error,
            qualityReport: row.qualityReport,
            generationLogs: row.generationLogs,
            domainExpertAnalysis: row.domainExpertAnalysis,
            councilData: row.councilData,
          },
        });
    } catch (e) {
      console.error("[Routes] Failed to persist artifact generation job:", e);
    }
  }

  /** Load artifact generation job from MySQL when it's missing from the in-memory map. */
  async function loadArtifactGenerationJob(jobId: string): Promise<ArtifactGenerationJob | null> {
    try {
      const [row] = await db
        .select()
        .from(schema.artifactGenerationJobRecords)
        .where(eq(schema.artifactGenerationJobRecords.jobId, jobId))
        .limit(1);

      if (!row) {
        return null;
      }

      let parsedResult: any | undefined;
      if (row.result) {
        try {
          parsedResult = JSON.parse(row.result as string);
        } catch {
          parsedResult = undefined;
        }
      }

      const job: ArtifactGenerationJob = {
        jobId: row.jobId,
        sessionId: row.sessionId ?? undefined,
        status: row.status as ArtifactGenerationJob["status"],
        progress: row.progress ?? 0,
        step: row.step ?? "",
        createdAt: row.createdAt ?? new Date(),
        completedAt: row.completedAt ?? undefined,
        result: parsedResult,
        error: row.error ?? undefined,
        qualityReport: (row as any).qualityReport ?? undefined,
        generationLogs: (row as any).generationLogs ?? [],
        domainExpertAnalysis: (row as any).domainExpertAnalysis,
        councilData: (row as any).councilData,
      };

      // Warm the in-memory cache for subsequent polls
      artifactGenerationJobs.set(jobId, job);

      return job;
    } catch (e) {
      console.error("[Routes] Failed to load artifact generation job from DB:", e);
      return null;
    }
  }

  /** Push step message to job so activity log can be persisted and restored after navigation. */
  function pushJobStep(j: ArtifactGenerationJob, step: string) {
    j.step = step;
    (j.generationLogs = j.generationLogs || []).push({ message: step, timestamp: new Date().toISOString() });
  }

  /** Record a user-facing warning on the job (surfaced via status payload + UI toast). */
  function pushJobWarning(j: ArtifactGenerationJob, message: string) {
    (j.warnings = j.warnings || []).push(message);
    pushJobStep(j, message);
  }

  /** Max chars for council response body in status API to avoid 500 from huge payloads. */
  const COUNCIL_STATUS_RESPONSE_PREVIEW_MAX = 2000;

  /**
   * Build a safe status payload for council job polling. Trims councilData.responses[].response
   * to avoid 500 from oversized JSON (full artifacts can be 100k+ chars per member).
   */
  function buildCouncilStatusPayload(job: ArtifactGenerationJob): Record<string, unknown> {
    const base: Record<string, unknown> = {
      jobId: job.jobId,
      status: job.status,
      progress: job.progress,
      step: job.step,
      createdAt: job.createdAt?.toISOString?.() ?? new Date().toISOString(),
      completedAt: job.completedAt?.toISOString?.(),
      error: job.error,
      qualityReport: job.qualityReport,
      generationLogs: job.generationLogs,
      domainExpertAnalysis: job.domainExpertAnalysis,
    };
    // When result is huge, send summary only to avoid 500; client can fetch full result via GET .../result/:jobId
    const STATUS_RESULT_SIZE_LIMIT = 100_000;
    if (job.status === "completed" && job.result != null) {
      const r = job.result as { epics?: unknown[]; features?: unknown[]; userStories?: unknown[] };
      const resultStr = JSON.stringify(job.result);
      if (resultStr.length > STATUS_RESULT_SIZE_LIMIT && (r?.epics != null || r?.features != null || r?.userStories != null)) {
        base.result = {
          _preview: true,
          _fetchResult: true,
          jobId: job.jobId,
          epics: r.epics?.length ?? 0,
          features: r.features?.length ?? 0,
          userStories: r.userStories?.length ?? 0,
        };
      } else {
        base.result = job.result;
      }
    }
    if (!job.councilData) {
      base.councilData = job.councilData;
      return base;
    }
    const responses = job.councilData.responses;
    const trimmedResponses = Array.isArray(responses)
      ? responses.map((r: { id?: string; provider?: string; model?: string; response?: unknown; confidence?: number; coverage?: number; consistency?: number; timestamp?: unknown }) => {
        const resp = r.response;
        let preview: unknown = resp;
        if (resp != null && typeof resp === "object" && "epics" in resp && "features" in resp && "userStories" in resp) {
          const a = resp as { epics?: unknown[]; features?: unknown[]; userStories?: unknown[] };
          preview = { epics: a.epics?.length ?? 0, features: a.features?.length ?? 0, userStories: a.userStories?.length ?? 0, _preview: true };
        } else if (typeof resp === "string" && resp.length > COUNCIL_STATUS_RESPONSE_PREVIEW_MAX) {
          preview = resp.slice(0, COUNCIL_STATUS_RESPONSE_PREVIEW_MAX) + "\n... [truncated for status]";
        } else if (resp != null && typeof resp === "object") {
          const str = JSON.stringify(resp);
          if (str.length > COUNCIL_STATUS_RESPONSE_PREVIEW_MAX) {
            preview = { _preview: true, _length: str.length, summary: str.slice(0, 200) + "..." };
          }
        }
        return {
          id: r.id,
          provider: r.provider,
          model: r.model,
          response: preview,
          confidence: r.confidence,
          coverage: r.coverage,
          consistency: r.consistency,
          timestamp: r.timestamp,
        };
      })
      : job.councilData.responses;
    // Trim evaluation for status payload to avoid 500 from oversized JSON
    let evaluation = job.councilData.evaluation;
    if (evaluation != null && typeof evaluation === "object") {
      const evalStr = JSON.stringify(evaluation);
      if (evalStr.length > COUNCIL_STATUS_RESPONSE_PREVIEW_MAX) {
        evaluation = { _preview: true, _length: evalStr.length } as any;
      }
    }
    base.councilData = {
      ...job.councilData,
      responses: trimmedResponses,
      councilStep: job.councilData.councilStep,
      evaluation,
    };
    return base;
  }

  // Wiki Generation Job Management (for handling Azure 240s timeout)
