  /**
   * Resolve ADO Git repository GUID by repository name when project has repository_id (internal golden_repositories.id)
   * but no goldenRepoReference. Used so the client gets a valid ADO repo ID for tree/file API calls.
   */
  async function resolveAdoRepositoryIdByRepoName(
    linkedGoldenRepoOrg: string,
    linkedGoldenRepoProject: string,
    repositoryName: string
  ): Promise<string | null> {
    const goldenOrgs = await storage.getGoldenRepoOrganizations();
    const extractOrgName = (url: string): string => {
      let name = url;
      if (name.includes("dev.azure.com")) {
        name = name.replace(/https?:\/\/dev\.azure\.com\//, "").replace(/\/$/, "").split("/")[0];
      } else if (name.includes("visualstudio.com")) {
        const m = name.match(/([^.]+)\.visualstudio\.com/);
        if (m) name = m[1];
      }
      return name.replace(/\/+$/, "").trim();
    };
    const matchingOrg = goldenOrgs.find(
      (org) =>
        (extractOrgName(org.organizationUrl) === linkedGoldenRepoOrg ||
          extractOrgName(org.organizationUrl).toLowerCase() === linkedGoldenRepoOrg.toLowerCase()) &&
        (org.projectName === linkedGoldenRepoProject ||
          org.projectName?.toLowerCase() === linkedGoldenRepoProject.toLowerCase())
    );
    if (!matchingOrg?.patToken) return null;
    const decryptedPAT = safeDecryptPAT(matchingOrg.patToken);
    if (!decryptedPAT) return null;
    const authHeader = `Basic ${Buffer.from(`:${decryptedPAT}`).toString("base64")}`;
    const listUrl = `${matchingOrg.organizationUrl.replace(/\/+$/, "")}/${encodeURIComponent(linkedGoldenRepoProject)}/_apis/git/repositories?api-version=${matchingOrg.apiVersion || "7.0"}`;
    try {
      const listRes = await fetch(listUrl, { headers: { Authorization: authHeader } });
      if (!listRes.ok) return null;
      const listJson = await listRes.json();
      const repos = listJson.value || [];
      const repo = repos.find(
        (r: { name?: string }) =>
          r.name === repositoryName ||
          (r.name && r.name.toLowerCase() === repositoryName.toLowerCase())
      );
      return repo?.id ?? null;
    } catch {
      return null;
    }
  }

  function getEffectiveAdoRepositoryIdFromProject(project: any): string | null {
    const ref = project?.goldenRepoReference ?? project?.golden_repo_reference;
    if (!ref || typeof ref !== "object") return null;
    const provider = typeof ref.provider === "string" ? ref.provider.toLowerCase() : "";
    const repoId = typeof ref.repoId === "string" ? ref.repoId.trim() : "";
    if (!repoId) return null;
    if (provider && provider !== "ado") return null;
    if (provider === "ado") return repoId;
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(repoId)
      ? repoId
      : null;
  }

  // ==============================
  // Authentication & User Bootstrap Endpoints
  // ==============================

  // Endpoint for SSO user bootstrap (Azure AD or GitHub)
  // Frontend should call this after successful MSAL or GitHub OAuth login
  app.post("/api/auth/bootstrap-user", async (req: Request, res: Response) => {
    try {
      // Bearer token path: autoBootstrapUser already validated JWT and bootstrapped user.
      const authReq = req as AuthenticatedRequest;
      const jwtUser = authReq.user;
      if (jwtUser?.id) {
        const [existing] = await db
          .select()
          .from(users)
          .where(eq(users.id, jwtUser.id))
          .limit(1);
        if (!existing) {
          return res.status(404).json({ error: "User not found" });
        }
        // Login event: claim/refresh this user's JIRA membership links every login
        // (credential / manual override / email). Idempotent + fire-and-forget so it
        // never blocks login. Unthrottled here because this endpoint fires once per
        // login (unlike autoBootstrapUser which runs on every request).
        import("./integrations/jira/team-sync-service")
          .then((m) => m.claimJiraMembershipsForUser({ userId: existing.id, email: existing.email || undefined }))
          .then((n) => { if (n > 0) console.log(`[Auth] login-claim: linked ${n} JIRA membership(s) for user ${existing.id}`); })
          .catch((e) => console.warn("[Auth] login-claim claimJiraMembershipsForUser failed:", e?.message || e));
        return res.json({
          success: true,
          user: {
            id: existing.id,
            email: existing.email,
            displayName: existing.displayName,
            provider: existing.provider || "microsoft",
            isMfaEnabled: existing.isMfaEnabled,
          },
        });
      }

      if (req.headers.authorization?.startsWith("Bearer ")) {
        return res.status(401).json({
          error: "Unauthorized",
          message: authReq.authFailure?.reason || "Bearer token did not validate or bootstrap a user",
        });
      }

      const { tokenClaims, githubUser } = req.body;
      const tenantIdFromHeader = req.headers["x-tenant-id"] as string | undefined;

      // Determine provider based on request body structure
      // Azure: tokenClaims with oid/tid
      // GitHub: githubUser object
      let providerType: "microsoft" | "github";
      let userInfo: SSOUserInfo;

      if (tokenClaims && (tokenClaims.oid || tokenClaims.tid)) {
        // Azure AD login
        providerType = "microsoft";
        userInfo = extractAzureUserInfo(tokenClaims);
      } else if (githubUser) {
        // GitHub OAuth login
        providerType = "github";
        userInfo = extractGitHubUserInfo(githubUser);
      } else {
        return res.status(400).json({
          error: "Token claims (Azure) or githubUser (GitHub) is required"
        });
      }

      // Validate required fields
      if (!userInfo.email) {
        return res.status(400).json({ error: "Email is required" });
      }

      if (providerType === "microsoft" && !userInfo.azureOid) {
        return res.status(400).json({ error: "Azure OID is required" });
      }

      if (providerType === "github" && !userInfo.githubId) {
        return res.status(400).json({ error: "GitHub ID is required" });
      }

      // Bootstrap user (create if not exists, assign default role if needed)
      // Tenant resolution: uses tenantId from token (userInfo.tenantId) as primary source
      // Falls back to header, then email domain (GitHub only)
      // DO NOT create random tenant IDs - they come from login token
      console.log("[BootstrapUser] Starting bootstrap:", {
        email: userInfo.email,
        tenantIdFromToken: userInfo.tenantId,
        tenantIdFromHeader,
        provider: userInfo.provider,
        tokenClaimsKeys: tokenClaims ? Object.keys(tokenClaims) : [],
      });

      // Validate tenant ID is present for Azure AD
      if (providerType === "microsoft" && !userInfo.tenantId) {
        console.error("[BootstrapUser] Azure AD login missing tenant ID (tid claim)");
        return res.status(400).json({
          error: "Tenant ID (tid) is required for Azure AD authentication",
          message: "Token claims must include 'tid' field",
        });
      }

      const user = await bootstrapUser(userInfo, tenantIdFromHeader);

      return res.json({
        success: true,
        user: {
          id: user.id,
          email: user.email,
          displayName: user.displayName,
          provider: providerType,
          isMfaEnabled: user.isMfaEnabled,
        },
      });
    } catch (error: any) {
      console.error("[Auth] Error bootstrapping user:", error);
      return res.status(500).json({
        error: "Failed to bootstrap user",
        message: error.message,
      });
    }
  });

  // Endpoint to get current user info (for frontend to check user status)
  // Must use same identity as bootstrapUser: (tenant_id, provider, provider_user_id)
  // so frontend role display matches requireRole checks on admin APIs.
  app.get("/api/auth/me", autoBootstrapUser, async (req: Request, res: Response) => {
    let emailForRetry: string | undefined;
    try {
      let { email, azureOid } = req.query as { email?: string; azureOid?: string };
      const tenantIdHeader = (req.headers["x-tenant-id"] as string) || (req.query.tenantId as string);
      const providerHeader = (req.headers["x-auth-provider"] as string) || "azure";
      let provider: string =
        providerHeader === "github"
          ? "github"
          : providerHeader === "cognito"
            ? "cognito"
            : providerHeader === "keycloak"
              ? "keycloak"
              : "microsoft";

      if (!email && !azureOid) {
        const headerEmail = req.headers["x-user-email"] as string | undefined;
        const headerOid = req.headers["x-user-oid"] as string | undefined;
        email = headerEmail ?? email;
        azureOid = headerOid ?? azureOid;
      }

      const authReq = req as AuthenticatedRequest;
      if (!authReq.user?.id && req.headers.authorization?.startsWith("Bearer ")) {
        return res.status(401).json({
          error: "Unauthorized",
          message: authReq.authFailure?.reason || "Bearer token did not validate or bootstrap a user",
        });
      }

      if (!email && authReq.user?.email) {
        email = authReq.user.email;
        azureOid = authReq.user.azureOid || azureOid;
        if (authReq.user.provider === "github") {
          provider = "github";
        } else if (authReq.user.provider === "cognito") {
          provider = "cognito";
        } else if (authReq.user.provider) {
          provider = authReq.user.provider;
        } else {
          provider = "microsoft";
        }
      }

      if (!email) {
        if (isOidcEnabled() || provider === "keycloak") {
          return res.status(401).json({
            error: "Unauthorized",
            message: "Authentication required",
          });
        }
        return res.status(400).json({ error: "Email is required" });
      }
      emailForRetry = email;

      const providerUserId =
        provider === "github" ? undefined : azureOid || authReq.user?.azureOid;

      const userRecord = await resolveUserForSession({
        email,
        providerUserId: providerUserId || undefined,
        tenantIdFromHeader: tenantIdHeader,
        provider,
        userIdFromMiddleware: authReq.user?.id,
      });

      if (!userRecord) {
        return res.status(404).json({
          error: "User not found",
          message: "Sign in via SSO so your account can be bootstrapped before calling /api/auth/me",
        });
      }

      const tenantId = userRecord.tenantId;
      const roleProvider =
        userRecord.provider ?? provider;

      if (tenantId) {
        await ensureViewerRole(userRecord.id, tenantId, roleProvider);
      } else {
        console.warn("[Auth] Cannot assign default role - no tenant ID available", {
          userId: userRecord.id,
          email: userRecord.email,
        });
      }

      const rolesResult = await db
        .select({
          role: roles.name,
          scope: userRoles.scopeType,
          scopeId: userRoles.scopeId,
          tenantId: userRoles.tenantId,
          provider: userRoles.provider,
        })
        .from(userRoles)
        .leftJoin(roles, eq(userRoles.roleId, roles.id))
        .where(eq(userRoles.userId, userRecord.id));

      const canCreateProject = await hasActivityEnabled(userRecord.id, "ADO_PROJECT_CREATE");

      return res.json({
        user: {
          id: userRecord.id,
          email: userRecord.email,
          displayName: userRecord.displayName,
          provider: userRecord.provider || provider,
          isMfaEnabled: userRecord.isMfaEnabled,
          onboardingCompleted: Boolean(userRecord.onboardingCompleted),
        },
        roles: rolesResult.map((r) => ({
          role: r.role ?? "Viewer",
          scope: r.scope,
          scopeId: r.scopeId,
          tenantId: r.tenantId,
          provider: r.provider,
        })),
        canCreateProject,
        onboardingCompleted: Boolean(userRecord.onboardingCompleted),
      });
    } catch (error: any) {
      const code = error?.code ?? "";
      const isTransient = code === "ECONNRESET" || code === "HANDSHAKE_SSL_ERROR" || code === "PROTOCOL_CONNECTION_LOST" || code === "ETIMEDOUT";
      if (isTransient) {
        console.warn(`[Auth] Transient DB error (${code}) fetching user, retrying once...`);
        try {
          await new Promise((r) => setTimeout(r, 500));
          if (emailForRetry) {
            const retryUser = await db.select().from(users).where(eq(users.email, emailForRetry)).limit(1);
          if (retryUser.length > 0) {
            return res.json({
              user: { id: retryUser[0].id, email: retryUser[0].email, displayName: retryUser[0].displayName, provider: retryUser[0].provider || "microsoft", isMfaEnabled: retryUser[0].isMfaEnabled },
              roles: [],
              canCreateProject: false,
            });
          }
          }
        } catch (retryErr) {
          console.error("[Auth] Retry also failed:", retryErr);
        }
      }
      console.error("[Auth] Error fetching user:", error);
      return res.status(500).json({
        error: "Failed to fetch user",
        message: error.message,
      });
    }
  });

  // Check if current user has a specific activity enabled
  // Resolves user by email from JWT claims (same as /api/auth/me) to avoid OID vs email DB mismatch
  app.get("/api/user/can/:activityKey", async (req: Request, res: Response) => {
    try {
      // Extract email from Bearer token claims
      const authHeader = req.headers.authorization;
      if (!authHeader?.startsWith("Bearer ")) return res.json({ allowed: true });

      const token = authHeader.substring(7);
      const { validateIdToken } = await import("./auth/jwt-validator");
      const claims = await validateIdToken(token);
      const email = claims.email || claims.preferred_username;
      if (!email) return res.json({ allowed: true });

      const userRecord = await db.select({ id: users.id }).from(users).where(eq(users.email, email)).limit(1);
      if (!userRecord[0]) return res.json({ allowed: true });

      const allowed = await hasActivityEnabled(userRecord[0].id, req.params.activityKey);
      return res.json({ allowed });
    } catch {
      return res.json({ allowed: true });
    }
  });

