  /**
   * Resolve the TenantAdmin tenant context for the current user.
   * We derive tenant and provider from the RBAC tables rather than trusting
   * any client-provided tenant identifiers.
   */
  async function getOrgAdminTenantContext(userId: string) {
    const adminRoles = await db
      .select({
        tenantId: userRoles.tenantId,
        provider: userRoles.provider,
      })
      .from(userRoles)
      .leftJoin(roles, eq(userRoles.roleId, roles.id))
      .where(
        and(
          eq(userRoles.userId, userId),
          eq(roles.name, "TenantAdmin")
        )
      )
      .limit(1);

    const ctx = adminRoles[0];
    if (!ctx || !ctx.tenantId || !ctx.provider) {
      throw new Error("TenantAdmin tenant context could not be resolved for current user");
    }

    return {
      tenantId: ctx.tenantId,
      provider: ctx.provider,
    };
  }

  /**
   * Resolve tenant context for activity config (TenantAdmin, OrgAdmin, or ProjectAdmin).
   * Prefers TenantAdmin, then OrgAdmin, then ProjectAdmin.
   */
  async function getActivityConfigTenantContext(userId: string) {
    const roleOrder = ["TenantAdmin", "OrgAdmin", "ProjectAdmin"] as const;
    for (const roleName of roleOrder) {
      const rows = await db
        .select({
          tenantId: userRoles.tenantId,
          provider: userRoles.provider,
        })
        .from(userRoles)
        .leftJoin(roles, eq(userRoles.roleId, roles.id))
        .where(
          and(
            eq(userRoles.userId, userId),
            eq(roles.name, roleName)
          )
        )
        .limit(1);
      const ctx = rows[0];
      if (ctx?.tenantId && ctx?.provider) {
        return { tenantId: ctx.tenantId, provider: ctx.provider };
      }
    }
    throw new Error("Tenant context could not be resolved for activity config (require TenantAdmin, OrgAdmin, or ProjectAdmin)");
  }

  /** Reserved scopeId meaning "all organizations" or "all projects" for RBAC. */
  const SCOPE_ID_ALL = "ALL";

  type AdminAssignableProject = { id: string; name: string; organizationId: string };

  const getAssignableSyncedAdminProjects = async (
    authUserId: string,
    tenantId: string,
  ): Promise<AdminAssignableProject[]> => {
    const visibleOrgs = await storage.getVisibleOrganizations(authUserId);
    const tenantOrgs = visibleOrgs
      .filter(org => org.tenantId === tenantId && org.name !== `Organization ${tenantId}`)
      .filter(org => org.ownerUserId === authUserId);

    const orgIds = tenantOrgs.map((o) => o.id);
    if (orgIds.length === 0) return [];

    const patReadiness = await getUserPatReadiness(authUserId);
    const visibleSdlcProjects = await sdlcService.getAllProjects(authUserId);
    const projectIds = visibleSdlcProjects.map((project) => project.id).filter(Boolean);
    const repoConfigByProjectId = new Map<string, any>();

    if (projectIds.length > 0) {
      const { isProjectIntegrationSkippedConfig } = await import(
        "@shared/project-integration-constants"
      );
      const repoConfigRows = await db
        .select({
          projectId: schema.projectIntegrationConfigs.projectId,
          config: schema.projectIntegrationConfigs.config,
          providerKey: schema.integrationToolCatalog.providerKey,
          displayName: schema.integrationToolCatalog.displayName,
          updatedAt: schema.projectIntegrationConfigs.updatedAt,
        })
        .from(schema.projectIntegrationConfigs)
        .leftJoin(
          schema.integrationToolCatalog,
          eq(schema.projectIntegrationConfigs.toolCatalogId, schema.integrationToolCatalog.id),
        )
        .where(
          and(
            inArray(schema.projectIntegrationConfigs.projectId, projectIds),
            eq(schema.projectIntegrationConfigs.categoryKey, "repo"),
          ),
        )
        .orderBy(desc(schema.projectIntegrationConfigs.updatedAt));

      for (const row of repoConfigRows) {
        if (repoConfigByProjectId.has(row.projectId)) continue;
        const config = (row.config || {}) as Record<string, string>;
        if (isProjectIntegrationSkippedConfig(config)) continue;

        repoConfigByProjectId.set(row.projectId, {
          providerKey: row.providerKey || null,
          displayName: row.displayName || null,
          baseUrl: config.baseUrl || config.organizationUrl || "",
          repositoryId:
            config.projectId ||
            config.repositoryId ||
            config.repositorySlug ||
            config.repository ||
            "",
          repositoryName:
            config.namespacePath ||
            config.projectName ||
            config.repositoryName ||
            config.repository ||
            config.repositorySlug ||
            "",
        });
      }
    }
    const assignableProjects: AdminAssignableProject[] = [];

    for (const project of visibleSdlcProjects) {
      let orgId = project.jiraConnectionId;
      if (!orgId) {
        const matchedOrg = tenantOrgs.find((org) => org.name === project.organization);
        orgId = matchedOrg ? matchedOrg.id : undefined;
      }
      if (!orgId || !orgIds.includes(orgId)) continue;

      const patStatus = await getProjectPatStatusForUser(
        {
          ...project,
          repoIntegrationConfig: repoConfigByProjectId.get(project.id) || null,
        },
        patReadiness,
        authUserId,
      );
      if (patStatus.userPatConfigured !== true) continue;

      assignableProjects.push({
        id: project.id,
        name: project.name,
        organizationId: orgId,
      });
    }

    return assignableProjects.filter(
      (project, index, self) => index === self.findIndex((candidate) => candidate.id === project.id),
    );
  };

  const validateSyncedProjectScope = async (
    authUserId: string,
    tenantId: string,
    scopeEntries: Array<{ scopeId: string }>,
  ): Promise<{ ok: true } | { ok: false; status: number; body: { error: string; message?: string } }> => {
    const requestedProjectIds = scopeEntries.flatMap((entry) =>
      entry.scopeId
        .split(",")
        .map((id) => id.trim())
        .filter(Boolean),
    );

    if (requestedProjectIds.length === 0 || requestedProjectIds.includes(SCOPE_ID_ALL)) {
      return {
        ok: false,
        status: 400,
        body: {
          error: "Select one or more synced projects. ALL project assignment is not allowed.",
        },
      };
    }

    const assignableProjectIds = new Set(
      (await getAssignableSyncedAdminProjects(authUserId, tenantId)).map((project) => project.id),
    );
    const invalidProjectIds = requestedProjectIds.filter((id) => !assignableProjectIds.has(id));
    if (invalidProjectIds.length > 0) {
      return {
        ok: false,
        status: 400,
        body: {
          error: "Users can only be assigned to synced projects.",
          message: `Unsynced or inaccessible project ids: ${invalidProjectIds.join(", ")}`,
        },
      };
    }

    return { ok: true };
  };

  // List organizations for the current tenant (for admin user-role scope dropdown)
  app.get("/api/admin/organizations", requireRole(["TenantAdmin"]), async (req: any, res: Response) => {
    try {
      const authUser = req.user;
      if (!authUser?.id) return res.status(401).json({ error: "Unauthorized" });
      const { tenantId } = await getOrgAdminTenantContext(authUser.id);

      const requestedScope = String(req.query.scope ?? "org").toLowerCase();
      const visibleOrgs = await storage.getVisibleOrganizations(authUser.id);

      let orgs = visibleOrgs
        .filter(org => org.tenantId === tenantId && org.name !== `Organization ${tenantId}`)
        // Tenant admins should only see their created organizations in this dropdown
        .filter(org => org.ownerUserId === authUser.id)
        .map(org => ({ id: org.id, name: org.name }));

      if (requestedScope === "project") {
        const activeProjectOrgIds = new Set(
          (await getAssignableSyncedAdminProjects(authUser.id, tenantId)).map((project) => project.organizationId),
        );
        orgs = orgs.filter((org) => activeProjectOrgIds.has(org.id));
      }

      console.log(`[DEBUG] /api/admin/organizations for user ${authUser.id} (tenant: ${tenantId}) returned ${orgs.length} orgs:`, orgs);
      res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, proxy-revalidate');
      res.setHeader('Pragma', 'no-cache');
      res.setHeader('Expires', '0');
      res.json(orgs);
    } catch (error: any) {
      console.error("[Admin] Error fetching organizations:", error);
      res.status(500).json({ error: "Failed to fetch organizations", message: error?.message });
    }
  });

  // List projects for the current tenant (for admin user-role scope dropdown)
  app.get("/api/admin/projects", requireRole(["TenantAdmin"]), async (req: any, res: Response) => {
    try {
      const authUser = req.user;
      if (!authUser?.id) return res.status(401).json({ error: "Unauthorized" });
      const { tenantId } = await getOrgAdminTenantContext(authUser.id);

      const syncedProjects = await getAssignableSyncedAdminProjects(authUser.id, tenantId);

      res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, proxy-revalidate');
      res.setHeader('Pragma', 'no-cache');
      res.setHeader('Expires', '0');
      res.json(syncedProjects);
    } catch (error: any) {
      console.error("[Admin] Error fetching projects:", error);
      res.status(500).json({ error: "Failed to fetch projects", message: error?.message });
    }
  });

  // Fetch all users and their roles for the current OrgAdmin's tenant
  app.get("/api/admin/users", requireRole(["TenantAdmin"]), async (req: any, res: Response) => {
    try {
      const authUser = req.user;
      if (!authUser?.id) {
        return res.status(401).json({ error: "Unauthorized" });
      }

      const { tenantId, provider } = await getOrgAdminTenantContext(authUser.id);

      // Pagination params
      const page = Math.max(1, parseInt((req.query.page as string) ?? "1", 10) || 1);
      const limit = Math.min(100, Math.max(1, parseInt((req.query.limit as string) ?? "10", 10) || 10));
      const search = ((req.query.search as string) ?? "").trim().toLowerCase();

      // Fetch all users with their roles (if any) scoped to this tenant
      // Using LEFT JOIN so users without roles still appear in results
      // Do not filter by provider - show all users in the tenant regardless of auth provider
      const rows = await db
        .select({
          userId: users.id,
          displayName: users.displayName,
          email: users.email,
          userRoleId: userRoles.id,
          role: roles.name,
          scope: userRoles.scopeType,
          projectId: userRoles.scopeType,
          scopeId: userRoles.scopeId,
        })
        .from(users)
        .leftJoin(
          userRoles,
          and(
            eq(userRoles.userId, users.id),
            eq(userRoles.tenantId, tenantId)
          )
        )
        .leftJoin(roles, eq(userRoles.roleId, roles.id))
        .where(and(eq(users.tenantId, tenantId), eq(users.isDeleted, false)));

      // Group by user
      const userMap = new Map<
        string,
        {
          userId: string;
          displayName: string | null;
          email: string;
          projectIds: string[];
          roles: Array<{
            userRoleId: string;
            role: string;
            scope: "org" | "project";
            scopeId: string | null;
            projectId: string | null;
          }>;
        }
      >();

      for (const row of rows) {
        if (!row.userId || !row.email) continue;
        const existing = userMap.get(row.userId) ?? {
          userId: row.userId,
          displayName: row.displayName ?? row.email,
          email: row.email,
          projectIds: [],
          roles: [],
        };

        if (row.userRoleId && row.role && row.scope) {
          existing.roles.push({
            userRoleId: row.userRoleId,
            role: row.role,
            scope: row.scope as "org" | "project",
            scopeId: row.scopeId ?? null,
            projectId: row.scope === "project" ? row.scopeId ?? null : null,
          });
        }

        userMap.set(row.userId, existing);
      }

      const userIds = Array.from(userMap.keys());
      if (userIds.length > 0) {
        const memberRows = await db
          .select({
            userId: projectMembers.userId,
            projectId: projectMembers.projectId,
          })
          .from(projectMembers)
          .where(
            and(
              inArray(projectMembers.userId, userIds),
              eq(projectMembers.tenantId, tenantId),
            ),
          );

        for (const member of memberRows) {
          const existing = userMap.get(member.userId);
          if (!existing || !member.projectId) continue;
          if (!existing.projectIds.includes(member.projectId)) {
            existing.projectIds.push(member.projectId);
          }
        }
      }

      // Convert to array and ensure users without roles show "Viewer" as default
      let result = Array.from(userMap.values()).map((user) => {
        // If user has no explicit roles, add a default Viewer role
        if (user.roles.length === 0) {
          user.roles.push({
            userRoleId: "default-viewer",
            role: "Viewer",
            scope: "org" as const,
            scopeId: null,
            projectId: null,
          });
        }
        return user;
      });

      // Server-side search filter (applied after grouping so we match full user records)
      if (search) {
        result = result.filter((u) => {
          const name = (u.displayName ?? u.email ?? "").toLowerCase();
          const email = (u.email ?? "").toLowerCase();
          return name.includes(search) || email.includes(search);
        });
      }

      // Paginate
      const total = result.length;
      const totalPages = Math.max(1, Math.ceil(total / limit));
      const offset = (page - 1) * limit;
      const items = result.slice(offset, offset + limit);

      res.json({ items, page, limit, total, totalPages });
    } catch (error: any) {
      console.error("[Admin] Error fetching tenant users:", error);
      res.status(500).json({
        error: "Failed to fetch users",
        message: error.message,
      });
    }
  });
  registerAdminUsersRoutes(app, getOrgAdminTenantContext);

  // Create a new user and assign default role (OrgAdmin)
  app.post("/api/admin/users", requireRole(["TenantAdmin"]), async (req: any, res: Response) => {
    try {
      const authUser = req.user;
      if (!authUser?.id) {
        return res.status(401).json({ error: "Unauthorized" });
      }

      const { tenantId, provider } = await getOrgAdminTenantContext(authUser.id);

      const bodySchema = z.object({
        email: z.string().trim().email("Invalid email address"),
        displayName: z.string().min(1, "Display name is required"),
        role: z.string().optional().default("OrgAdmin"),
        scope: z.enum(["org", "project"]).optional().default("org"),
        organizationIds: z.array(z.string()).optional(),
        projectIds: z.array(z.string()).optional(),
      });

      const parseResult = bodySchema.safeParse(req.body);
      if (!parseResult.success) {
        return res.status(400).json({
          error: "Invalid payload",
          details: parseResult.error.flatten(),
        });
      }

      const { email, displayName, role, scope, organizationIds, projectIds } = parseResult.data;

      if (scope === "project") {
        if (projectIds?.includes(SCOPE_ID_ALL) || !projectIds?.length) {
          return res.status(400).json({
            error: "Select one or more synced projects. ALL project assignment is not allowed.",
          });
        }
        const projectScopeValidation = await validateSyncedProjectScope(
          authUser.id,
          tenantId,
          [{ scopeId: projectIds.join(",") }],
        );
        if (!projectScopeValidation.ok) {
          return res.status(projectScopeValidation.status).json(projectScopeValidation.body);
        }
      }

      // Check within the current tenant. A soft-deleted user can be restored;
      // an active same-tenant user should remain a conflict. Do not block on
      // same-email rows in other tenants.
      const existingTenantUser = await db
        .select()
        .from(users)
        .where(and(eq(users.tenantId, tenantId), sql`lower(${users.email}) = ${email.toLowerCase()}`))
        .limit(1);

      const existingUser = existingTenantUser[0];
      if (existingUser && !existingUser.isDeleted) {
        return res.status(409).json({
          error: "User already exists",
          message: "An active user with this email already exists in this tenant",
        });
      }

      const isRestore = Boolean(existingUser?.isDeleted);
      const targetUserId = existingUser?.id ?? randomUUID();
      if (isRestore) {
        await db
          .update(users)
          .set({
            displayName,
            isDeleted: false,
            deletedAt: null,
            provider,
            providerUserId: existingUser?.providerUserId || email,
          })
          .where(eq(users.id, targetUserId));
      } else {
        // Create new user with tenant ID from admin's context. Use a unique
        // placeholder azureOid so invite/pre-provision rows do not collide
        // globally when the same email exists in another tenant.
        const inviteAzureOid = `invite-${randomUUID()}`;
        try {
          await db.insert(users).values({
            id: targetUserId,
            email,
            displayName,
            tenantId,
            provider, // Use admin's provider context
            azureOid: inviteAzureOid,
            providerUserId: email,
            createdAt: new Date(),
          });
        } catch (insertErr: any) {
          // Some deployed users tables still have legacy NOT NULL username/password columns.
          // Drizzle does not model them, so match the SSO bootstrap fallback and satisfy them.
          if (
            (insertErr?.code === "ER_NO_DEFAULT_FOR_FIELD" || insertErr?.errno === 1364) &&
            typeof insertErr?.sqlMessage === "string" &&
            (insertErr.sqlMessage.includes("Field 'username' doesn't have a default value") ||
              insertErr.sqlMessage.includes("Field 'password' doesn't have a default value"))
          ) {
            const username = displayName.trim() || email.split("@")[0] || email;
            const passwordPlaceholder = `admin_invite_${randomUUID()}`;
            await poolConnection.execute(
              `INSERT INTO users (id, azure_oid, email, display_name, tenant_id, provider, provider_user_id, username, password)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
              [
                targetUserId,
                inviteAzureOid,
                email,
                displayName,
                tenantId,
                provider,
                email,
                username,
                passwordPlaceholder,
              ],
            );
          } else {
            throw insertErr;
          }
        }
      }

      // Get or create the specified role
      let roleRecord = await db
        .select()
        .from(roles)
        .where(eq(roles.name, role))
        .limit(1);

      if (roleRecord.length === 0) {
        await db.insert(roles).values({ name: role });
        roleRecord = await db
          .select()
          .from(roles)
          .where(eq(roles.name, role))
          .limit(1);
      }

      const roleRow = roleRecord[0];
      if (!roleRow) {
        return res.status(500).json({ error: `Failed to resolve ${role} role` });
      }

      type ScopeEntry = { scopeId: string };
      let scopeEntries: ScopeEntry[] = [];

      if (scope === "org") {
        const useAll = organizationIds?.includes(SCOPE_ID_ALL) || !organizationIds?.length;
        if (useAll) {
          scopeEntries = [{ scopeId: SCOPE_ID_ALL }];
        } else {
          const rbacOrgs = await db
            .select({ id: organizations.id })
            .from(organizations)
            .where(and(eq(organizations.tenantId, tenantId), inArray(organizations.id, organizationIds!)));
          const validIds = new Set(rbacOrgs.map((o) => o.id));
          const scopeIdValue = Array.from(validIds).join(",");
          scopeEntries = [{ scopeId: scopeIdValue }];
        }
      } else {
        const useAll = projectIds?.includes(SCOPE_ID_ALL) || !projectIds?.length;
        if (useAll) {
          return res.status(400).json({
            error: "Select one or more synced projects. ALL project assignment is not allowed.",
          });
        } else if (projectIds?.length) {
          const scopeIdValue = projectIds.join(",");
          scopeEntries = [{ scopeId: scopeIdValue }];
        } else {
          return res.status(400).json({ error: "projectIds required when scope=project" });
        }
      }

      await db.transaction(async (tx) => {
        if (isRestore) {
          await tx
            .delete(userRoles)
            .where(
              and(
                eq(userRoles.userId, targetUserId),
                eq(userRoles.tenantId, tenantId),
                eq(userRoles.provider, provider),
                eq(userRoles.scopeType, scope),
              )
            );

          if (scope === "org") {
            await tx
              .delete(organizationMembers)
              .where(
                and(
                  eq(organizationMembers.userId, targetUserId),
                  eq(organizationMembers.tenantId, tenantId),
                  eq(organizationMembers.role, "member"),
                )
              );
          } else if (scope === "project") {
            await tx
              .delete(projectMembers)
              .where(
                and(
                  eq(projectMembers.userId, targetUserId),
                  eq(projectMembers.tenantId, tenantId),
                  eq(projectMembers.role, "member"),
                )
              );
          }
        }

        for (const entry of scopeEntries) {
          const userRoleId = randomUUID();
          await tx.insert(userRoles).values({
            id: userRoleId,
            userId: targetUserId,
            tenantId,
            provider,
            roleId: roleRow.id,
            scopeType: scope,
            scopeId: entry.scopeId,
            createdBy: authUser.id,
          });
        }

        // Audit log
        try {
          if (isRestore) {
            await tx.insert(auditLogs).values({
              id: randomUUID(),
              actorUserId: authUser.id,
              targetUserId,
              action: "USER_REACTIVATED",
              role: role,
              tenantId,
              projectId: null,
            });
          }
          for (const entry of scopeEntries) {
            await tx.insert(auditLogs).values({
              id: randomUUID(),
              actorUserId: authUser.id,
              targetUserId,
              action: "ROLE_ASSIGNED",
              role: role,
              tenantId,
              projectId: scope === "project" ? entry.scopeId : null,
            });
          }
        } catch (auditError) {
          console.warn("[Admin] Failed to write audit log for user creation:", auditError);
        }
      });

      console.log(isRestore ? "[Admin] User restored:" : "[Admin] New user created:", {
        userId: targetUserId,
        email,
        displayName,
        tenantId,
        role: role,
      });

      res.status(isRestore ? 200 : 201).json({
        userId: targetUserId,
        email,
        displayName,
        tenantId,
        role: role,
        scope: "org",
        restored: isRestore,
      });
    } catch (error: any) {
      console.error("[Admin] Error creating user:", error);
      res.status(500).json({
        error: "Failed to create user",
        message: error.message,
      });
    }
  });

  // -------------------------------------------------------------------------
  // Bulk user onboarding via Excel
  // -------------------------------------------------------------------------
  const bulkUserUpload = multer({
    storage: multer.memoryStorage(),
    limits: { fileSize: 5 * 1024 * 1024 },
  });

  // Gather the orgs/projects/roles the admin can assign, used for both the
  // template Reference sheet and name -> id resolution during validation.
  async function getBulkUserRefData(
    authUserId: string,
    tenantId: string,
  ): Promise<BulkRefData> {
    const visibleOrgs = await storage.getVisibleOrganizations(authUserId);
    const tenantOrgs = visibleOrgs
      .filter(
        (org) =>
          org.tenantId === tenantId &&
          org.name !== `Organization ${tenantId}` &&
          org.ownerUserId === authUserId,
      )
      .map((org) => ({ id: org.id, name: org.name }));
    const orgIds = new Set(tenantOrgs.map((o) => o.id));

    const visibleDevxProjects = await storage.getVisibleProjects(authUserId);
    const devxProjects = visibleDevxProjects
      .filter(
        (p) =>
          p.organizationId &&
          orgIds.has(p.organizationId) &&
          p.ownerUserId === authUserId,
      )
      .map((p) => ({ id: p.id, name: p.name }));

    let sdlcProjectsMapped: { id: string; name: string }[] = [];
    try {
      const visibleSdlcProjects = await sdlcService.getAllProjects(authUserId);
      sdlcProjectsMapped = visibleSdlcProjects
        .map((p) => {
          let orgId = p.jiraConnectionId;
          if (!orgId) {
            const matched = tenantOrgs.find((o) => o.name === p.organization);
            orgId = matched ? matched.id : undefined;
          }
          return { id: p.id, name: p.name, organizationId: orgId };
        })
        .filter((p) => !!p.organizationId && orgIds.has(p.organizationId!))
        .map((p) => ({ id: p.id, name: p.name }));
    } catch (err) {
      console.warn("[BulkUsers] Failed to load SDLC projects:", err);
    }

    const allProjects = [...devxProjects, ...sdlcProjectsMapped].filter(
      (p, i, self) => i === self.findIndex((t) => t.id === p.id),
    );

    const roleRows = await db.select({ name: roles.name }).from(roles);

    return {
      roles: roleRows.map((r) => r.name),
      organizations: tenantOrgs,
      projects: allProjects,
    };
  }

  // Download the onboarding Excel template.
  app.get(
    "/api/admin/users/template",
    requireRole(["TenantAdmin"]),
    async (req: any, res: Response) => {
      try {
        const authUser = req.user;
        if (!authUser?.id) return res.status(401).json({ error: "Unauthorized" });
        const { tenantId } = await getOrgAdminTenantContext(authUser.id);
        const refData = await getBulkUserRefData(authUser.id, tenantId);
        const buffer = await generateBulkUserTemplate(refData);
        res.setHeader(
          "Content-Type",
          "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        );
        res.setHeader(
          "Content-Disposition",
          'attachment; filename="user-onboarding-template.xlsx"',
        );
        res.send(buffer);
      } catch (error: any) {
        console.error("[BulkUsers] Error generating template:", error);
        res
          .status(500)
          .json({ error: "Failed to generate template", message: error.message });
      }
    },
  );

  // Upload + validate (no writes) -> per-row preview report.
  app.post(
    "/api/admin/users/bulk/preview",
    requireRole(["TenantAdmin"]),
    bulkUserUpload.single("file"),
    async (req: any, res: Response) => {
      try {
        const authUser = req.user;
        if (!authUser?.id) return res.status(401).json({ error: "Unauthorized" });
        if (!req.file?.buffer) {
          return res.status(400).json({ error: "No file uploaded" });
        }
        const { tenantId } = await getOrgAdminTenantContext(authUser.id);

        const rawRows = await parseUsersWorkbook(req.file.buffer);
        if (rawRows.length === 0) {
          return res.json({
            summary: { total: 0, valid: 0, errors: 0, duplicates: 0 },
            rows: [],
          });
        }

        const refData = await getBulkUserRefData(authUser.id, tenantId);
        const existingByEmail = await loadExistingByEmail(
          rawRows.map((r) => r.email),
          tenantId,
        );
        const rows = validateBulkUserRows(rawRows, {
          refData,
          tenantId,
          existingByEmail,
        });

        res.json({ summary: summarizeBulkUserRows(rows), rows });
      } catch (error: any) {
        console.error("[BulkUsers] Error in preview:", error);
        res
          .status(500)
          .json({ error: "Failed to process file", message: error.message });
      }
    },
  );

  // Re-validate the submitted rows and create the valid ones.
  app.post(
    "/api/admin/users/bulk",
    requireRole(["TenantAdmin"]),
    async (req: any, res: Response) => {
      try {
        const authUser = req.user;
        if (!authUser?.id) return res.status(401).json({ error: "Unauthorized" });
        const { tenantId, provider } = await getOrgAdminTenantContext(authUser.id);

        const bodySchema = z.object({
          rows: z
            .array(
              z.object({
                rowNumber: z.number().optional(),
                userName: z.string().optional().default(""),
                email: z.string().optional().default(""),
                role: z.string().optional().default(""),
                scope: z.string().optional().default(""),
                organization: z.string().optional().default(""),
                project: z.string().optional().default(""),
              }),
            )
            .min(1, "At least one row is required"),
        });

        const parsed = bodySchema.safeParse(req.body);
        if (!parsed.success) {
          return res.status(400).json({
            error: "Invalid payload",
            details: parsed.error.flatten(),
          });
        }

        const rawRows = parsed.data.rows.map((r, i) => ({
          rowNumber: r.rowNumber ?? i + 2,
          userName: r.userName,
          email: r.email,
          role: r.role,
          scope: r.scope,
          organization: r.organization,
          project: r.project,
        }));

        const refData = await getBulkUserRefData(authUser.id, tenantId);
        const existingByEmail = await loadExistingByEmail(
          rawRows.map((r) => r.email),
          tenantId,
        );
        const validated: BulkValidatedRow[] = validateBulkUserRows(rawRows, {
          refData,
          tenantId,
          existingByEmail,
        });

        let created = 0;
        let failed = 0;
        let skipped = 0;
        const results: Array<{
          rowNumber: number;
          email: string;
          status: "created" | "failed" | "skipped";
          userId?: string;
          reactivated?: boolean;
          error?: string;
        }> = [];

        for (const row of validated) {
          if (row.status !== "valid" || !row.payload) {
            skipped++;
            results.push({
              rowNumber: row.rowNumber,
              email: row.data.email,
              status: "skipped",
              error:
                row.status === "duplicate"
                  ? "User already exists"
                  : row.errors[0]?.message ?? "Invalid row",
            });
            continue;
          }
          try {
            const { userId, reactivated } = await createBulkUser(row.payload, {
              tenantId,
              provider,
              actorUserId: authUser.id,
            });
            created++;
            results.push({
              rowNumber: row.rowNumber,
              email: row.data.email,
              status: "created",
              userId,
              reactivated,
            });
          } catch (err: any) {
            failed++;
            results.push({
              rowNumber: row.rowNumber,
              email: row.data.email,
              status: "failed",
              error: err?.message ?? "Unknown error",
            });
          }
        }

        res.json({ created, failed, skipped, results });
      } catch (error: any) {
        console.error("[BulkUsers] Error in bulk create:", error);
        res
          .status(500)
          .json({ error: "Failed to create users", message: error.message });
      }
    },
  );

  // Soft-delete a user from the organization (sets is_deleted=true, preserves data)
  app.delete("/api/admin/users/:userId", requireRole(["TenantAdmin"]), async (req: any, res: Response) => {
    try {
      const authUser = req.user;
      if (!authUser?.id) {
        return res.status(401).json({ error: "Unauthorized" });
      }

      const { tenantId } = await getOrgAdminTenantContext(authUser.id);
      const { userId } = req.params as { userId: string };

      // Prevent deleting self
      if (userId === authUser.id) {
        return res.status(400).json({ error: "Cannot delete your own user account" });
      }

      // Ensure user belongs to this tenant and is not already deleted
      const userToDelete = await db
        .select({ id: users.id, email: users.email, isDeleted: users.isDeleted })
        .from(users)
        .where(
          and(
            eq(users.id, userId),
            eq(users.tenantId, tenantId)
          )
        )
        .limit(1);

      if (userToDelete.length === 0) {
        return res.status(404).json({ error: "User not found in this organization" });
      }

      if (userToDelete[0].isDeleted) {
        return res.status(400).json({ error: "User is already deleted" });
      }

      // Soft-delete: mark user as deleted without removing data
      await db.transaction(async (tx) => {
        await tx
          .update(users)
          .set({ isDeleted: true, deletedAt: new Date() })
          .where(eq(users.id, userId));

        // Audit log
        try {
          await tx.insert(auditLogs).values({
            id: randomUUID(),
            actorUserId: authUser.id,
            targetUserId: userId,
            action: "USER_SOFT_DELETED",
            role: "None",
            tenantId,
            projectId: null,
          });
        } catch (auditError) {
          console.warn("[Admin] Failed to write audit log for user soft-deletion:", auditError);
        }
      });

      console.log(`[Admin] User ${userId} soft-deleted from tenant ${tenantId}`);
      res.json({ success: true });
    } catch (error: any) {
      console.error("[Admin] Error soft-deleting user:", error);
      res.status(500).json({
        error: "Failed to delete user",
        message: error.message,
      });
    }
  });

  // ========== Phase 4: Admin Tenant & Subscription (visibility only, no enforcement) ==========

  // GET /api/admin/tenants — return the current OrgAdmin's tenant summary (no global listing)
  app.get("/api/admin/tenants", requireRole(["TenantAdmin"]), async (req: any, res: Response) => {
    try {
      const authUser = req.user;
      if (!authUser?.id) {
        return res.status(401).json({ error: "Unauthorized" });
      }

      const { tenantId } = await getOrgAdminTenantContext(authUser.id);
      const tenantRows = await db.select().from(tenants).where(eq(tenants.id, tenantId)).limit(1);

      if (tenantRows.length === 0) {
        return res.status(404).json({ error: "Tenant not found" });
      }

      const tenant = tenantRows[0];

      const subRows = await db
        .select({
          subscriptionType: subscriptionTypes.name,
          subscriptionTypeCode: subscriptionTypes.code,
          maxUsers: subscriptions.maxUsers,
          tokenQuota: subscriptions.tokenQuota,
          tokenUsed: subscriptions.tokenUsed,
          startDate: subscriptions.startDate,
          expiryDate: subscriptions.expiryDate,
          createdAt: subscriptions.createdAt,
        })
        .from(subscriptions)
        .leftJoin(subscriptionTypes, eq(subscriptions.subscriptionTypeId, subscriptionTypes.id))
        .where(
          and(
            eq(subscriptions.tenantId, tenantId),
            eq(subscriptions.isActive, true)
          )
        )
        .limit(1);

      const sub = subRows[0] ?? null;
      const userCountResult = await db
        .select({ count: count() })
        .from(users)
        .where(eq(users.tenantId, tenantId));
      const userCount = Number(userCountResult[0]?.count ?? 0);

      const subStart = sub ? getSubDate(sub, "startDate") : "";
      const subExpiry = sub ? getSubDate(sub, "expiryDate") : "";
      const subCreated = sub ? safeToISOString(sub.createdAt ?? (sub as any).created_at) : "";
      const startDate =
        subStart || subCreated || "";
      const expiryDate =
        subExpiry ||
        (subCreated ? (() => {
          const d = new Date(subCreated);
          d.setFullYear(d.getFullYear() + 1);
          return isNaN(d.getTime()) ? "" : d.toISOString();
        })() : "");

      res.json({
        tenant: {
          tenantId: tenant.id,
          name: tenant.name,
          description: (tenant as any).description ?? null,
          vertical: (tenant as any).vertical ?? null,
          status: tenant.status,
          createdAt: safeToISOString(tenant.createdAt),
        },
        subscription: sub
          ? {
            subscriptionType: sub.subscriptionType ?? sub.subscriptionTypeCode ?? "DEFAULT",
            maxUsers: sub.maxUsers,
            tokenQuota: Number(sub.tokenQuota ?? 0),
            tokenUsed: Number(sub.tokenUsed ?? 0),
            startDate,
            expiryDate,
          }
          : null,
        userCount,
      });
    } catch (error: any) {
      console.error("[Admin] Error fetching tenant overview:", error);
      res.status(500).json({
        error: "Failed to fetch tenant overview",
        message: error.message,
      });
    }
  });

