  // PUT /api/admin/subscriptions/:tenantId — update subscription (max_users, expiry_date only)
  app.put("/api/admin/subscriptions/:tenantId", requireRole(["TenantAdmin"]), async (req: any, res: Response) => {
    try {
      const { tenantId } = req.params;
      const authUser = req.user;
      if (!authUser?.id) {
        return res.status(401).json({ error: "Unauthorized" });
      }

      const { tenantId: adminTenantId } = await getOrgAdminTenantContext(authUser.id);
      if (tenantId !== adminTenantId) {
        return res.status(403).json({ error: "Forbidden" });
      }

      const body = req.body || {};
      const maxUsers = typeof body.maxUsers === "number" ? body.maxUsers : undefined;
      const expiryDateRaw = body.expiryDate != null ? String(body.expiryDate) : undefined;
      const expiryDate = expiryDateRaw ? new Date(expiryDateRaw) : undefined;

      const existing = await db
        .select()
        .from(subscriptions)
        .where(
          and(
            eq(subscriptions.tenantId, tenantId),
            eq(subscriptions.isActive, true)
          )
        )
        .limit(1);

      if (existing.length === 0) {
        return res.status(404).json({ error: "No active subscription found for tenant" });
      }

      const updates: Record<string, unknown> = {};
      if (maxUsers !== undefined) updates.maxUsers = maxUsers;
      if (expiryDate !== undefined) updates.expiryDate = expiryDate;

      if (Object.keys(updates).length > 0) {
        await db
          .update(subscriptions)
          .set(updates as any)
          .where(eq(subscriptions.id, existing[0].id));
      }

      const updated = await db
        .select()
        .from(subscriptions)
        .where(eq(subscriptions.id, existing[0].id))
        .limit(1);

      res.json(updated[0] ?? existing[0]);
    } catch (error: any) {
      console.error("[Admin] Error updating subscription:", error);
      res.status(500).json({
        error: "Failed to update subscription",
        message: error.message,
      });
    }
  });

