            // Ensure status is always a string
            const statusValue = brd.status ? String(brd.status).trim() : null;
            return {
              id: brd.id,
              title: brd.title,
              status: statusValue, // Always include status field
              updated_at: brd.updatedAt?.toISOString() || new Date().toISOString(),
            };
