  // GET /api/dev-brd/all
  // Returns all BRDs for a project with calculated status (draft, yetToReview, approved)
  app.get(
    "/api/dev-brd/all",
    requireActivity("SDLC_BRD_VIEW"),
    async (req: Request, res: Response) => {
      try {
        const projectId = req.query.projectId as string;
        if (!projectId) {
          return res.status(400).json({ error: "projectId is required" });
        }

        // Fetch all BRDs for the project
        const allBrds = await db
          .select({
            id: schema.devBrdDocuments.id,
            title: schema.devBrdDocuments.title,
            status: schema.devBrdDocuments.status,
            brdFile: schema.devBrdDocuments.brdFile,
            generatedMarkdown: schema.devBrdDocuments.generatedMarkdown,
            generatedBrdJson: schema.devBrdDocuments.generatedBrdJson,
            createdAt: schema.devBrdDocuments.createdAt,
            updatedAt: schema.devBrdDocuments.updatedAt,
          })
          .from(schema.devBrdDocuments)
          .where(eq(schema.devBrdDocuments.projectId, projectId))
          .orderBy(desc(schema.devBrdDocuments.updatedAt));

        // Calculate status for each BRD (matching counts API logic)
        const brdsWithStatus = allBrds.map((brd) => {
          const hasDocument = brd.brdFile || brd.generatedMarkdown || brd.generatedBrdJson;
          let calculatedStatus = "draft";

          // Check actual database status first (for generated statuses)
          if (brd.status === "generated") {
            calculatedStatus = "generated";
          } else if (brd.status === "partially_generated") {
            calculatedStatus = "partially_generated";
          } else if (brd.status === "approved") {
            calculatedStatus = "approved";
          } else if (hasDocument) {
            // Has document but not approved = yet to review
            calculatedStatus = "yetToReview";
          } else {
            // No document = draft
            calculatedStatus = "draft";
          }

          return {
            id: brd.id,
            title: brd.title,
            status: calculatedStatus,
            createdAt: brd.createdAt?.toISOString() || new Date().toISOString(),
            updatedAt: brd.updatedAt?.toISOString() || new Date().toISOString(),
          };
        });

        // Debug logging for generated/partially_generated BRDs
        const generatedBrds = brdsWithStatus.filter((b: any) => b.status === "generated" || b.status === "partially_generated");
        if (generatedBrds.length > 0) { }

        return res.json(brdsWithStatus);
      } catch (error) {
        console.error("[Routes][DEV-BRD] Error fetching all BRDs:", error);
        const message =
          error instanceof Error ? error.message : "Failed to fetch all BRDs";
        return res.status(500).json({
          error: "Failed to fetch all BRDs",
          details: message,
        });
      }
    });

  // POST /api/dev-brd/debug-extract-requirements
  // Parse requirements from generatedBrdJson and return + console the output (no DB write).
