  // Robustly parse a JSON object from an LLM response that may be wrapped in
  // markdown code fences, followed by trailing prose, or contain raw control
  // characters (newlines/tabs) inside string literals.
  function parseLooseJson(raw: string): any {
    if (!raw) throw new Error("Empty response");
    let s = raw.trim();
    // Strip surrounding ```json ... ``` fences (anywhere in the text).
    s = s.replace(/```(?:json)?/gi, "").trim();
    // Extract the outermost { ... } block, dropping any leading/trailing prose.
    const start = s.indexOf("{");
    const end = s.lastIndexOf("}");
    if (start !== -1 && end !== -1 && end > start) {
      s = s.slice(start, end + 1);
    }
    try {
      return JSON.parse(s);
    } catch {
      // Escape raw control characters that appear inside string literals.
      let result = "";
      let inString = false;
      let escaped = false;
      for (let i = 0; i < s.length; i++) {
        const ch = s[i];
        if (inString) {
          if (escaped) {
            result += ch;
            escaped = false;
          } else if (ch === "\\") {
            result += ch;
            escaped = true;
          } else if (ch === '"') {
            result += ch;
            inString = false;
          } else if (ch === "\n") {
            result += "\\n";
          } else if (ch === "\r") {
            result += "\\r";
          } else if (ch === "\t") {
            result += "\\t";
          } else if (ch.charCodeAt(0) < 0x20) {
            result += " ";
          } else {
            result += ch;
          }
        } else if (ch === '"') {
          inString = true;
          result += ch;
        } else {
          result += ch;
        }
      }
      return JSON.parse(result);
    }
  }

