      const epicProgress = epics.length > 0 ? Math.round((completedEpics.length / epics.length) * 100) : 0;
      const featureProgress = features.length > 0 ? Math.round((completedFeatures.length / features.length) * 100) : 0;

      // Calculate spillover metrics
