  // Generate code from user story
  app.post(
    "/api/sdlc/generate-code",
    requireActivity("SDLC_DEVELOPMENT_CREATE"),
    async (req: Request, res: Response) => {
      try {
        const {
          projectId,
          repositoryId,
          branchId,
          branchName,
          storyId,
          title,
          description,
          acceptanceCriteria
        } = req.body;

        if (!projectId || !repositoryId || !branchId || !title) {
          return res.status(400).json({ error: "Missing required parameters" });
        }

        try {
          await consumeTokensForRequest(req as any, CODE_GENERATION_TOKEN_COST);
        } catch (tokenErr) {
          if (tokenErr instanceof TokenQuotaExceededError) {
            return res.status(402).json({
              success: false,
              code: TOKEN_QUOTA_EXCEEDED_CODE,
              message: "Token quota exceeded for this tenant.",
            });
          }
          throw tokenErr;
        }

        // Get repository and branch details
        const [repository, branch] = await Promise.all([
          storage.getDevelopmentRepository(repositoryId),
          storage.getDevelopmentBranch(branchId)
        ]);

        if (!repository) {
          return res.status(404).json({ error: "Repository not found" });
        }

        if (!branch) {
          return res.status(404).json({ error: "Branch not found" });
        }

        // Generate code using OpenAI
        const { metricId: codeMetricId, startTime: codeStartTime } = await trackEventStart({
          artifactId: storyId ? String(storyId) : randomUUID(),
          useCase: "code generation",
          userId: (req as any).user?.id,
          projectId: projectId,
        });

        let generatedCode;
        try {
          generatedCode = await generateCodeFromUserStory({
            title,
            description,
            acceptanceCriteria,
            storyId
          });

          await trackEventSuccess(codeMetricId, codeStartTime, CODE_GENERATION_TOKEN_COST);
        } catch (codeErr) {
          await trackEventFailure(codeMetricId, codeStartTime);
          throw codeErr;
        }

        // Get next commit number for the branch
        const existingCommits = await storage.getCommits(repositoryId);
        const branchCommits = existingCommits.filter((c: any) => c.branchId === branchId);
        const nextCommitNumber = branchCommits.length + 1;

        // Create a safe filename from the title
        const sanitizedTitle = title.replace(/[^a-zA-Z0-9\s]/g, '').replace(/\s+/g, '-').toLowerCase();
        const fileName = `story-${storyId}-${sanitizedTitle}.ts`;
        const commitMessage = `feat: Implement ${title} (Story #${storyId})`;

        // Store commit in database
        const commit = await storage.createCommit({
          repositoryId,
          branchId,
          message: commitMessage,
          commitNumber: nextCommitNumber,
          author: "AI Code Generator"
        });

        // Update branch commit count
        await storage.updateBranchCommitCount(branchId, nextCommitNumber);// Optionally push to Azure DevOps if settings are configured
        // Get ADO settings for optional push
        const project = await storage.getProject(projectId);
        const settings = await storage.getAdoSettings();

        if (settings && settings.patToken && project) {
          try {
            // Decrypt PAT
            const decryptedPAT = decryptPAT(settings.patToken!);

            if (decryptedPAT && repository.repositoryUrl) {
              // Extract organization from URL
              const orgUrl = settings.organizationUrl.replace(/\/$/, '');
              const organization = orgUrl.split('/').pop()!;

              // Push commit to Azure DevOps
              const adoService = new AzureDevOpsService({
                organization,
                project: settings.projectName,
                pat: decryptedPAT
              });

              const adoCommit = await adoService.pushCommit({
                repositoryName: repository.name,
                branchName: branch.name,
                fileName,
                fileContent: generatedCode,
                commitMessage,
                authorName: "AI Code Generator"
              });
            }
          } catch (adoError) {
            console.warn('[Code Generation] Failed to push to Azure DevOps, but continuing:', adoError);
            // Don't fail the request if ADO push fails - the code is still generated
          }
        }

        res.json({
          code: generatedCode,
          commit: {
            id: commit.id,
            message: commitMessage,
            branch: branch.name,
            commitNumber: nextCommitNumber
          }
        });
      } catch (error) {
        console.error("Error generating code:", error);
        res.status(500).json({ error: "Failed to generate code" });
      }
    });

  // Development Repositories
  app.get(
    "/api/sdlc/projects/:projectId/repositories",
    requireActivity("SDLC_DEVELOPMENT_VIEW"),
    async (req: Request, res: Response) => {
      try {
        const { projectId } = req.params;
        const { organization: queryOrg, projectName: queryProjectName } = req.query;

        // If ADO project info is provided, fetch from Azure DevOps instead of database
        if (queryOrg && queryProjectName) {
          // Find the artifact organization matching the query params
          const artifactOrgs = await storage.getArtifactOrganizations();
          const targetOrg = artifactOrgs.find(org => {
            let orgName = org.organizationUrl;
            if (orgName.includes('dev.azure.com')) {
              orgName = orgName.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '').split('/')[0];
            } else if (orgName.includes('visualstudio.com')) {
              const match = orgName.match(/([^\.]+)\.visualstudio\.com/);
              if (match) {
                orgName = match[1];
              }
            }
            orgName = orgName.replace(/\/+$/, '').trim();
            return orgName === queryOrg && org.projectName === queryProjectName && org.patToken;
          });

          if (targetOrg && targetOrg.patToken) {
            const decryptedPAT = decryptPAT(targetOrg.patToken);
            if (decryptedPAT) {
              // Extract organization name from URL
              let organization = targetOrg.organizationUrl;
              if (organization.includes('dev.azure.com')) {
                organization = organization.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '').split('/')[0];
              } else if (organization.includes('visualstudio.com')) {
                const match = organization.match(/([^\.]+)\.visualstudio\.com/);
                if (match) {
                  organization = match[1];
                }
              }
              organization = organization.replace(/\/+$/, '').trim();

              const azureConfig = {
                organization,
                project: targetOrg.projectName,
                pat: decryptedPAT,
              };

              const adoService = new AzureDevOpsService(azureConfig);
              const repositories = await adoService.getRepositories();
              return res.json(repositories);
            }
          }
        }

        // Fallback to database repositories
        const repositories = await storage.getDevelopmentRepositories(projectId);
        res.json(repositories);
      } catch (error) {
        console.error("Error fetching repositories:", error);
        res.status(500).json({ error: "Failed to fetch repositories" });
      }
    });

