  // Push to Azure DevOps from SDLC page
  app.post("/api/sdlc/projects/:projectId/push-to-ado", async (req: Request, res: Response) => {
    try {
      const { projectId } = req.params;
      const { epics, features, userStories, phaseNumber, artifactId, config, brdId, requirementIds } = req.body;

      if (!epics || !features || !userStories) {
        return res.status(400).json({ error: "Epics, features, and user stories are required" });
      }

      // ---------------------------------------------------------------------
      // Always fetch BRD ID and requirement IDs from dev_brd_requirements using
      // the workflow artifact ID (artifactId). If artifactId is not provided,
      // try to find it by looking up which workflow artifact contains the artifacts being pushed.
      // This ensures traceability is always accurate from the source of truth.
      // ---------------------------------------------------------------------
      let effectiveBrdId: string | null = null;
      let effectiveRequirementIds: string[] = [];
      let effectiveArtifactId: string | null = artifactId || null;

      // If artifactId is not provided, try to find it from the artifacts being pushed
      if (!effectiveArtifactId && (userStories?.length > 0 || epics?.length > 0 || features?.length > 0)) {
        try {
          // Get all workflow artifacts for this project, ordered by most recent
          const workflowArtifacts = await db
            .select({
              id: schema.workflowArtifacts.id,
              epics: schema.workflowArtifacts.epics,
              features: schema.workflowArtifacts.features,
              userStories: schema.workflowArtifacts.userStories,
            })
            .from(schema.workflowArtifacts)
            .where(eq(schema.workflowArtifacts.projectId, projectId))
            .orderBy(sql`${schema.workflowArtifacts.createdAt} DESC`)
            .limit(10); // Check last 10 artifacts

          // Find the workflow artifact that contains any of the artifacts being pushed
          for (const artifact of workflowArtifacts) {
            const artifactEpics = (artifact.epics as any[]) || [];
            const artifactFeatures = (artifact.features as any[]) || [];
            const artifactStories = (artifact.userStories as any[]) || [];

            // Check if any epic/feature/story being pushed exists in this workflow artifact
            const hasMatchingEpic = epics.some((e: any) => artifactEpics.some((ae: any) => ae.id === e.id));
            const hasMatchingFeature = features.some((f: any) => artifactFeatures.some((af: any) => af.id === f.id));
            const hasMatchingStory = userStories.some((s: any) => artifactStories.some((as: any) => as.id === s.id));

            if (hasMatchingEpic || hasMatchingFeature || hasMatchingStory) {
              effectiveArtifactId = artifact.id; break;
            }
          }
        } catch (lookupError) {
          console.warn("[Push to ADO] Failed to lookup workflow artifact ID from artifacts:", lookupError);
        }
      }

      // If effectiveArtifactId is available, fetch BRD ID and requirement IDs from dev_brd_requirements
      // using effectiveArtifactId == workflow_id
      // If brdId is null or requirementIds are empty, fetch from dev_brd_requirements table
      if (effectiveArtifactId) {
        try {
          const requirementRows = await db
            .select({
              id: schema.devBrdRequirements.id,
              brdId: schema.devBrdRequirements.brdId,
            })
            .from(schema.devBrdRequirements)
            .where(eq(schema.devBrdRequirements.workflowId, effectiveArtifactId));

          if (requirementRows.length > 0) {
            effectiveBrdId = requirementRows[0].brdId;
            effectiveRequirementIds = requirementRows.map((row) => row.id);
          } else { }
        } catch (traceError) {
          console.warn("[Push to ADO] Failed to fetch BRD / requirement IDs from dev_brd_requirements:", traceError);
        }
      } else {
        console.log("[Push to ADO] No effectiveArtifactId available, cannot fetch BRD/requirement IDs from dev_brd_requirements");
      }

      // Fallback: use brdId and requirementIds from request body when DB lookup did not resolve them
      if (!effectiveBrdId && brdId) {
        effectiveBrdId = brdId;
        console.log("[Push to ADO] Using brdId from request body:", effectiveBrdId);
      }
      if (effectiveRequirementIds.length === 0 && Array.isArray(requirementIds) && requirementIds.length > 0) {
        effectiveRequirementIds = requirementIds;
        console.log("[Push to ADO] Using requirementIds from request body:", effectiveRequirementIds.length);
      }

      console.log("[Push to ADO] Traceability context:", {
        artifactIdFromRequest: artifactId,
        effectiveArtifactId: effectiveArtifactId,
        brdId: effectiveBrdId,
        requirementIds: effectiveRequirementIds,
        requirementCount: effectiveRequirementIds.length,
      });
      // Get Azure DevOps config (prefer from request, fallback to storage)
      let azureConfig: any = null;

      if (config && config.organization && config.project) {
        // Use config from request body (user-provided)
        azureConfig = {
          organization: config.organization,
          project: config.project,
          pat: config.pat || undefined,
        };
      } else {
        // Fallback to storage
        azureConfig = await getAzureDevOpsConfig(undefined, undefined);
      }

      if (!azureConfig || !azureConfig.organization || !azureConfig.project) {
        return res.status(400).json({
          error: "Azure DevOps organization and project are required. Please provide in the modal or configure in Settings > Central Settings."
        });
      }

      // If PAT is not provided in config, try to fetch from storage
      if (!azureConfig.pat) {
        const storedConfig = await getAzureDevOpsConfig(
          azureConfig.project,
          azureConfig.organization
        );
        if (storedConfig && storedConfig.pat) {
          azureConfig.pat = storedConfig.pat;
        }
      }

      if (azureConfig.pat) {
        const maskedPat =
          azureConfig.pat.length > 8
            ? `${azureConfig.pat.substring(0, 4)}***${azureConfig.pat.substring(
              azureConfig.pat.length - 4
            )}`
            : `${azureConfig.pat.substring(0, 2)}***`;
      } else {
        console.warn("[Push to ADO] No PAT found for current configuration");
      }

      if (!azureConfig.pat) {
        return res.status(400).json({
          error: "Personal Access Token is required. Please provide it in the modal or configure in Settings > Central Settings."
        });
      }

      // Fetch personas from workflow artifacts (primary) and global storage (fallback)
      let personas: Persona[] = [];
      try {
        // First, try to get personas from the workflow artifact
        if (artifactId) {
          const artifacts = await db
            .select()
            .from(schema.workflowArtifacts)
            .where(eq(schema.workflowArtifacts.id, artifactId))
            .limit(1);

          if (artifacts.length > 0 && artifacts[0].personas) {
            personas = artifacts[0].personas as Persona[];
          }
        }

        // If not found in artifact, try projectId
        if (personas.length === 0 && projectId) {
          const artifacts = await db
            .select()
            .from(schema.workflowArtifacts)
            .where(eq(schema.workflowArtifacts.projectId, projectId))
            .orderBy(sql`${schema.workflowArtifacts.createdAt} DESC`)
            .limit(1);

          if (artifacts.length > 0 && artifacts[0].personas) {
            personas = artifacts[0].personas as Persona[];
          }
        }

        // Fallback to global storage
        if (personas.length === 0) {
          personas = await storage.getPersonas();
        }
      } catch (error) {
        console.warn("[Push to ADO] Warning: Failed to fetch personas:", error);
        // Continue anyway - personas might not be required
      }
      // Build selected items array (all items are selected in this flow)
      const selectedItems = [
        ...(epics || []).map((e: any) => ({ type: "epic", id: e.id })),
        ...(features || []).map((f: any) => ({ type: "feature", id: f.id })),
        ...(userStories || []).map((s: any) => ({ type: "story", id: s.id })),
      ];

      if (selectedItems.length === 0) {
        return res.status(400).json({ error: "No items to push" });
      }

      // ASYNC-JOB PATTERN: Bulk ADO pushes (epics + features + stories,
      // many work-item creates) easily exceed AWS API Gateway's 29s timeout
      // and surface as 503 Service Unavailable. Move the actual push +
      // workflow-artifact update into a background job and have the client
      // poll `GET /api/jobs/sdlc-push-to-ado/status/:jobId`.
      const azureService = new AzureDevOpsService(azureConfig);
      const totalSelected = selectedItems.length;

      const { jobId } = asyncJobManager.start(
        "sdlc-push-to-ado",
        async ({ updateProgress }) => {
          updateProgress(10, `Pushing ${totalSelected} item(s) to Azure DevOps`);

          const workItemResult = await azureService.pushWorkItems(
            selectedItems,
            epics as Epic[],
            features as Feature[],
            userStories as UserStory[],
            personas as Persona[]
          );

          updateProgress(80, "Updating workflow artifacts with ADO IDs");

          const totalItems = workItemResult.workItemIds.length;
          const createdCount = workItemResult.createdItems?.length || totalItems;
          const skippedCount = workItemResult.skippedItems?.length || 0;

          if (createdCount === 0 && skippedCount === 0) {
            throw new Error("No items were successfully created in Azure DevOps");
          }

          // CRITICAL: Update workflow_artifacts table to save ADO work item IDs back to database
          // Update for BOTH created items AND skipped items (that already exist in ADO)
          if (createdCount > 0 || skippedCount > 0) {
            try {
              let artifactToUpdate = null;

              if (artifactId) {
                const artifacts = await db
                  .select()
                  .from(schema.workflowArtifacts)
                  .where(eq(schema.workflowArtifacts.id, artifactId))
                  .limit(1);
                if (artifacts.length > 0) {
                  artifactToUpdate = artifacts[0];
                }
              } else {
                // Try to find by projectId
                const artifacts = await db
                  .select()
                  .from(schema.workflowArtifacts)
                  .where(eq(schema.workflowArtifacts.projectId, projectId))
                  .orderBy(sql`${schema.workflowArtifacts.createdAt} DESC`)
                  .limit(1);
                if (artifacts.length > 0) {
                  artifactToUpdate = artifacts[0];
                }
              }

              if (artifactToUpdate) {
                // Parse existing artifacts
                const existingEpics = (artifactToUpdate.epics as any[]) || [];
                const existingFeatures = (artifactToUpdate.features as any[]) || [];
                const existingUserStories = (artifactToUpdate.userStories as any[]) || [];

                // Update ADO work item IDs for BOTH newly created AND skipped items (that already exist in ADO)
                const createdItemsMap = new Map(workItemResult.createdItems?.map(item => [item.id, item.adoWorkItemId]) || []);
                const skippedItemsMap = new Map(
                  workItemResult.skippedItems
                    ?.filter((item: any) => item.reason === 'already_exists' && item.adoWorkItemId)
                    .map((item: any) => [item.id, item.adoWorkItemId]) || []
                );

                // Merge both maps
                const allItemsMap = new Map([...createdItemsMap, ...skippedItemsMap]); const updatedEpics = existingEpics.map((epic: any) => {
                  if (allItemsMap.has(epic.id)) {
                    return { ...epic, adoWorkItemId: allItemsMap.get(epic.id) };
                  }
                  return epic;
                });

                const updatedFeatures = existingFeatures.map((feature: any) => {
                  if (allItemsMap.has(feature.id)) {
                    return { ...feature, adoWorkItemId: allItemsMap.get(feature.id) };
                  }
                  return feature;
                });

                const updatedUserStories = existingUserStories.map((story: any) => {
                  if (allItemsMap.has(story.id)) {
                    return { ...story, adoWorkItemId: allItemsMap.get(story.id) };
                  }
                  return story;
                });

                // Calculate approved vs not approved count
                const totalEpics = epics?.length || 0;
                const totalFeatures = features?.length || 0;
                const totalStories = userStories?.length || 0;
                const totalItemsCount = totalEpics + totalFeatures + totalStories;

                const approvedCount = selectedItems.length;
                const notApprovedCount = totalItemsCount - approvedCount;

                // Format approval status
                const approvalStatus = `${approvedCount} approved, ${notApprovedCount} not approved`;
                const approvalStatusTruncated = approvalStatus.length > 20
                  ? `${approvedCount}/${totalItemsCount}`
                  : approvalStatus;

                await db
                  .update(schema.workflowArtifacts)
                  .set({
                    epics: updatedEpics,
                    features: updatedFeatures,
                    userStories: updatedUserStories,
                    modified: true,
                    approvalStatus: approvalStatusTruncated,
                    updatedAt: new Date(),
                  })
                  .where(eq(schema.workflowArtifacts.id, artifactToUpdate.id));
              }
            } catch (updateError) {
              console.error("[Push to ADO] Error updating workflow artifact:", updateError);
              // Don't fail the request if DB update fails
            }
          }

          let responseMessage = '';
          if (createdCount > 0 && skippedCount > 0) {
            responseMessage = `Successfully created ${createdCount} work item(s) in Azure DevOps. ${skippedCount} item(s) were skipped (already exist in ADO).`;
          } else if (createdCount > 0) {
            responseMessage = `Successfully created ${createdCount} work item(s) in Azure DevOps.`;
          } else {
            responseMessage = `All ${skippedCount} selected item(s) already exist in Azure DevOps.`;
          }

          return {
            success: true,
            message: responseMessage,
            created: {
              epics: workItemResult.createdItems?.filter((i: any) => i.type === 'epic').length || 0,
              features: workItemResult.createdItems?.filter((i: any) => i.type === 'feature').length || 0,
              userStories: workItemResult.createdItems?.filter((i: any) => i.type === 'story').length || 0,
            },
            skipped: {
              epics: workItemResult.skippedItems?.filter((i: any) => i.type === 'epic').length || 0,
              features: workItemResult.skippedItems?.filter((i: any) => i.type === 'feature').length || 0,
              userStories: workItemResult.skippedItems?.filter((i: any) => i.type === 'story').length || 0,
            },
            workItemIds: workItemResult.workItemIds,
            url: workItemResult.url,
            createdItems: workItemResult.createdItems || [],
            skippedItems: workItemResult.skippedItems || [],
          };
        },
        `Pushing ${totalSelected} item(s) to Azure DevOps`,
      );

      res.status(202).json({
        success: true,
        jobId,
        status: "processing",
        message: `Push to ADO started. Poll /api/jobs/sdlc-push-to-ado/status/${jobId} for status.`,
      });
    } catch (error) {
      console.error("[Push to ADO] Error:", error);
      const errorMessage = error instanceof Error ? error.message : String(error);
      res.status(500).json({
        success: false,
        error: "Failed to push to Azure DevOps",
        details: errorMessage,
      });
    }
  });

  // Update existing ADO work item (for items synced from Azure DevOps)
  app.patch("/api/sdlc/projects/:projectId/ado-items/:workItemId", async (req: Request, res: Response) => {
    try {
      const { projectId, workItemId } = req.params;
      const { artifact, type, organization, projectName } = req.body;

      if (!artifact || !type) {
        return res.status(400).json({ error: "Artifact and type are required" });
      }

      // Get Azure DevOps config
      const azureConfig = await getAzureDevOpsConfig(projectName, organization);

      if (!azureConfig || !azureConfig.organization || !azureConfig.project || !azureConfig.pat) {
        return res.status(400).json({
          error: "Azure DevOps configuration is missing. Please configure in Settings > Central Settings."
        });
      }

      // Map artifact fields to Azure DevOps fields
      const updates: Record<string, any> = {};

      // Common fields for all work item types
      updates['System.Title'] = artifact.title;
      updates['System.Description'] = artifact.description || '';

      // Priority mapping (High/Medium/Low to 1/2/3)
      if (artifact.priority) {
        const priorityMap: Record<string, number> = {
          'High': 1,
          'Medium': 2,
          'Low': 3
        };
        updates['Microsoft.VSTS.Common.Priority'] = priorityMap[artifact.priority] || 2;
      }

      // Type-specific fields
      if (type === 'story') {
        // User Story specific fields
        if (artifact.storyPoints) {
          updates['Microsoft.VSTS.Scheduling.StoryPoints'] = artifact.storyPoints;
        }
        if (artifact.acceptanceCriteria) {
          // Format acceptance criteria as simple descriptive text without Given/When/Then structure
          let criteriaText = '';
          if (Array.isArray(artifact.acceptanceCriteria)) {
            criteriaText = artifact.acceptanceCriteria
              .map((c: any, i: number) => {
                // If it's a string, use it directly
                if (typeof c === 'string') {
                  return `<div><strong>Criteria ${i + 1}:</strong> ${c}</div><br/>`;
                }

                // If it's an object, use title or description, or combine all text fields
                let description = '';
                if (c.title && c.title.trim() && c.title !== 'undefined') {
                  description = c.title;
                } else if (c.description && c.description.trim() && c.description !== 'undefined') {
                  description = c.description;
                } else {
                  // Fallback: combine all text fields (excluding given/when/then/and structure)
                  const textParts = [];
                  if (c.title && c.title.trim() && c.title !== 'undefined') textParts.push(c.title);
                  if (c.description && c.description.trim() && c.description !== 'undefined') textParts.push(c.description);
                  description = textParts.join(' ') || `Acceptance Criterion ${i + 1}`;
                }

                return `<div><strong>Criteria ${i + 1}:</strong> ${description}</div><br/>`;
              })
              .join('');
          } else {
            criteriaText = artifact.acceptanceCriteria;
          }
          updates['Microsoft.VSTS.Common.AcceptanceCriteria'] = criteriaText;
        }
      }

      // Create Azure DevOps service and update work item
      const azureService = new AzureDevOpsService(azureConfig);
      const updatedWorkItem = await azureService.updateWorkItem(
        parseInt(workItemId),
        updates,
        azureConfig.project
      ); res.json({
        success: true,
        message: `Successfully updated ${type} in Azure DevOps`,
        workItem: updatedWorkItem
      });
    } catch (error) {
      console.error("[Update ADO Item] Error:", error);
      const errorMessage = error instanceof Error ? error.message : String(error);
      res.status(500).json({
        success: false,
        error: "Failed to update work item in Azure DevOps",
        details: errorMessage,
      });
    }
  });

