  // Update wiki page in workflow artifacts
  app.patch("/api/wiki-pages/:id", async (req: Request, res: Response) => {
    try {
      const wikiPageId = req.params.id;
      const { title, content, sessionId } = req.body;// 1) Update the primary wiki_pages row (source of truth for /api/wiki/session)
      const existingPages = await db
        .select()
        .from(schema.wikiPages)
        .where(eq(schema.wikiPages.id, wikiPageId))
        .limit(1);

      if (!existingPages[0]) {
        return res.status(404).json({ error: "Wiki page not found" });
      }

      const currentPage = existingPages[0];
      const updatedWikiPage = {
        ...currentPage,
        title: title || currentPage.title,
        content: content || currentPage.content,
        updatedAt: new Date(),
      };

      await db
        .update(schema.wikiPages)
        .set({
          title: updatedWikiPage.title,
          content: updatedWikiPage.content,
          updatedAt: updatedWikiPage.updatedAt,
        } as any)
        .where(eq(schema.wikiPages.id, wikiPageId));

      // 2) Best-effort sync into workflowArtifacts.wikiPages (if an artifact exists)
      if (sessionId) {
        try {
          const artifacts = await db
            .select()
            .from(schema.workflowArtifacts)
            .where(eq(schema.workflowArtifacts.sessionId, sessionId));

          if (artifacts && artifacts.length > 0) {
            const artifact = artifacts[0];
            const artifactWikiPages = artifact.wikiPages || [];

            const pageIndex = artifactWikiPages.findIndex(
              (page: any) => page.id === wikiPageId
            );

            if (pageIndex !== -1) {
              artifactWikiPages[pageIndex] = {
                ...artifactWikiPages[pageIndex],
                title: updatedWikiPage.title,
                content: updatedWikiPage.content,
                updatedAt: updatedWikiPage.updatedAt,
              };

              await db
                .update(schema.workflowArtifacts)
                .set({
                  wikiPages: artifactWikiPages as any,
                  updatedAt: new Date(),
                })
                .where(eq(schema.workflowArtifacts.id, artifact.id));
            }
          }
        } catch (syncError) {
          console.warn(
            "[Wiki Update] Failed to sync workflowArtifacts wikiPages for id",
            wikiPageId,
            syncError
          );
        }
      } res.json(updatedWikiPage);
    } catch (error) {
      console.error("Error updating wiki page:", error);
      res.status(500).json({ error: "Failed to update wiki page" });
    }
  });

  // Fetch requirement documents from Azure DevOps for design generation
  app.get("/api/sdlc/projects/:projectId/ado-requirements", async (req: Request, res: Response) => {
    try {
      const { projectId } = req.params;

      // Check project integration type
      const project = await sdlcService.getProject(projectId);
      if (project && (project as any).integrationType === 'jira') {
        const { handleGetJiraRequirements } = await import("./integrations/jira/jira-routes-handler");
        return handleGetJiraRequirements(req, res);
      }

      let requirements: any[] = [];
      let userStories: any[] = [];
      let tasks: any[] = [];
      let fetchSucceeded = false;

      const { AzureDevOpsService } = await import("./azure-devops-service");

      // Try 1: DevXPlatform with environment variable PAT
      const adoPAT = process.env.ADO_PAT;
      if (adoPAT && !fetchSucceeded) {
        try {
          const adoService = new AzureDevOpsService({
            organization: "DevXPlatform",
            project: "NousAugmentedDevX",
            pat: adoPAT,
          });

          [requirements, userStories, tasks] = await Promise.all([
            adoService.getWorkItemsByType('Requirement', "NousAugmentedDevX", 50),
            adoService.getWorkItemsByType('User Story', "NousAugmentedDevX", 50),
            adoService.getWorkItemsByType('Task', "NousAugmentedDevX", 50),
          ]);

          fetchSucceeded = true;
        } catch (devXError) { }
      }

      // Try 2: Fallback to central settings (artifact_organizations)
      if (!fetchSucceeded) {
        const artifactOrgs = await storage.getArtifactOrganizations();
        const firstOrg = artifactOrgs[0];

        if (!firstOrg || !firstOrg.patToken) {
          return res.status(400).json({
            error: "Azure DevOps not configured. Please set ADO_PAT environment variable or configure in Settings > Central Settings."
          });
        }

        const decryptedPAT = decryptPAT(firstOrg.patToken);
        if (!decryptedPAT) {
          return res.status(400).json({
            error: "Azure DevOps PAT could not be decrypted."
          });
        }

        const organization = firstOrg.organizationUrl.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '');
        const project = firstOrg.projectName; const adoService = new AzureDevOpsService({
          organization,
          project,
          pat: decryptedPAT,
        });

        [requirements, userStories, tasks] = await Promise.all([
          adoService.getWorkItemsByType('Requirement', project, 50),
          adoService.getWorkItemsByType('User Story', project, 50),
          adoService.getWorkItemsByType('Task', project, 50),
        ]);
      }

      // Helper function to extract assignee name from various ADO formats
      const getAssignedTo = (assignedToField: any): string => {
        if (!assignedToField) return 'Unassigned';

        // Handle string format: "Jane Doe <jane@contoso.com>"
        if (typeof assignedToField === 'string') {
          return assignedToField;
        }

        // Handle object format with displayName property
        if (assignedToField.displayName) {
          return assignedToField.displayName;
        }

        return 'Unassigned';
      };

      // Format the documents for the UI with enhanced fields
      const documents = [
        ...requirements.map((req: any) => ({
          id: req.fields['System.Id'],
          title: req.fields['System.Title'],
          description: req.fields['System.Description'] || '',
          acceptanceCriteria: req.fields['Microsoft.VSTS.Common.AcceptanceCriteria'] || '',
          assignedTo: getAssignedTo(req.fields['System.AssignedTo']),
          tags: req.fields['System.Tags'] || '',
          areaPath: req.fields['System.AreaPath'] || '',
          type: 'Requirement',
          state: req.fields['System.State'],
        })),
        ...userStories.map((story: any) => ({
          id: story.fields['System.Id'],
          title: story.fields['System.Title'],
          description: story.fields['System.Description'] || '',
          acceptanceCriteria: story.fields['Microsoft.VSTS.Common.AcceptanceCriteria'] || '',
          assignedTo: getAssignedTo(story.fields['System.AssignedTo']),
          tags: story.fields['System.Tags'] || '',
          areaPath: story.fields['System.AreaPath'] || '',
          type: 'User Story',
          state: story.fields['System.State'],
        })),
        ...tasks.map((task: any) => ({
          id: task.fields['System.Id'],
          title: task.fields['System.Title'],
          description: task.fields['System.Description'] || '',
          acceptanceCriteria: task.fields['Microsoft.VSTS.Common.AcceptanceCriteria'] || '',
          assignedTo: getAssignedTo(task.fields['System.AssignedTo']),
          tags: task.fields['System.Tags'] || '',
          areaPath: task.fields['System.AreaPath'] || '',
          type: 'Task',
          state: task.fields['System.State'],
        })),
      ];

      res.json({ documents });
    } catch (error) {
      console.error("Error fetching ADO requirements:", error);
      res.status(500).json({
        error: "Failed to fetch requirements from Azure DevOps",
        details: error instanceof Error ? error.message : String(error)
      });
    }
  });

  // Generate Design with AI
  app.post(
    "/api/sdlc/projects/:projectId/generate-design",
    requireActivity("SDLC_DESIGN_CREATE"),
    async (req: Request, res: Response) => {
      try {
        const { projectId } = req.params;
        const { designType, requirementDocument, guidelinesContent, selectedEpicIds } = req.body;

        try {
          await consumeTokensForRequest(req as any, DESIGN_GENERATION_TOKEN_COST);
        } catch (tokenErr) {
          if (tokenErr instanceof TokenQuotaExceededError) {
            return res.status(402).json({
              success: false,
              code: TOKEN_QUOTA_EXCEEDED_CODE,
              message: "Token quota exceeded for this tenant.",
            });
          }
          throw tokenErr;
        }

        // ASYNC-JOB PATTERN: Design generation runs multiple LLM calls
        // (generateDesignContent + Figma prompt) that can easily exceed AWS
        // API Gateway's 29s timeout (observed 503s). Return 202 + jobId
        // immediately and perform the work in the background; the client polls
        // `GET /api/jobs/sdlc-generate-design/status/:jobId` for the result.
        const { jobId } = asyncJobManager.start(
          "sdlc-generate-design",
          async ({ updateProgress }) => {
            updateProgress(5, "Starting design generation");

            const epicCount = Array.isArray(selectedEpicIds) ? selectedEpicIds.length : 1;
            const userJourneyInstruction = getDesignCardUserJourneyInstruction(epicCount);
            const requirementWithUserJourney = (userJourneyInstruction + (requirementDocument || "")).trim();
            const userJourneyTaskForFigma = getDesignCardUserJourneyTaskForFigma(epicCount);

            // Determine designCategory: prefer explicit field, otherwise derive from designType, default 'general'
            const rawDesignCategory = req.body.designCategory || designType || 'general';
            const designCategory = String(rawDesignCategory)
              .trim()
              .toLowerCase()
              .replace(/\s+/g, '-')
              .replace(/[^a-z0-9-_]/g, '');// Fetch existing Figma link from design guidelines
            let existingFigmaLink = null;
            let existingGuidelines: any[] = [];
            try {
              existingGuidelines = await db.select()
                .from(schema.designGuidelines)
                .where(eq(schema.designGuidelines.projectId, projectId))
                .orderBy(desc(schema.designGuidelines.createdAt))
                .limit(1); if (existingGuidelines.length > 0 && existingGuidelines[0].figmaLink) {
                  existingFigmaLink = existingGuidelines[0].figmaLink;
                } else { }
            } catch (guidelineError) {
              console.warn("[API] Could not fetch existing guidelines:", guidelineError);
              // Continue without existing link - not a fatal error
            }

            updateProgress(10, "Fetching backlog context");
            console.log("[GenerateDesign:backlog] Fetching backlog context");

            // Attempt to fetch backlog context (Jira or ADO depending on hosting)
            let adoBacklogContext = undefined;
            let adoDataAvailable = false;
            try {
              const { isAwsHosting: _isAwsDesign } = await import("./platform/hosting");
              if (_isAwsDesign()) {
                // Jira backlog enrichment for AWS mode
                const jiraConfig = await getJiraConfig(projectId);
                if (jiraConfig) {
                  const jiraService = await getJiraServiceForWrite(req, jiraConfig.projectKey, jiraConfig.instanceUrl);
                  // Enrichment only samples a handful of items (top 5 epics / 10
                  // features / 15 stories), so a small fetch is sufficient and
                  // avoids pulling the whole backlog (3×500 + N+1 detail calls).
                  const backlogContextRaw = await jiraService.getBacklogContext(30);
                  const backlogContext = backlogContextRaw as any;
                  adoBacklogContext = {
                    epics: backlogContext.epics || [],
                    features: backlogContext.features || [],
                    userStories: backlogContext.userStories || [],
                    tasks: [],
                    bugs: [],
                  };
                  adoDataAvailable = (backlogContext.epics?.length || 0) + (backlogContext.features?.length || 0) + (backlogContext.userStories?.length || 0) > 0;
                  console.log(`[API] Jira backlog enrichment: ${backlogContext.epics?.length ?? 0} epics, ${backlogContext.features?.length ?? 0} features, ${backlogContext.userStories?.length ?? 0} stories`);
                }
              } else {
                // ADO backlog enrichment for Azure mode
                const artifactOrgs = await storage.getArtifactOrganizations();
                const firstOrg = artifactOrgs[0];

                if (firstOrg?.patToken) {
                  const decryptedPAT = decryptPAT(firstOrg.patToken);

                  if (decryptedPAT) {
                    const organization = firstOrg.organizationUrl.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '');

                    const { AzureDevOpsService } = await import("./azure-devops-service");
                    const adoService = new AzureDevOpsService({
                      organization,
                      project: firstOrg.projectName,
                      pat: decryptedPAT,
                    });

                    // Enrichment only samples a handful of items, so cap the
                    // fetch instead of pulling 1000 of every type.
                    const backlogContext = await adoService.getBacklogContext(firstOrg.projectName, 30);

                    const enhancedUserStories = backlogContext.userStories?.map((story: any) => ({
                      ...story,
                      title: story.fields?.['System.Title'] || story.title,
                      description: story.fields?.['System.Description'] || story.description,
                      acceptanceCriteria: story.fields?.['Microsoft.VSTS.Common.AcceptanceCriteria'] || '',
                      state: story.fields?.['System.State'] || story.state,
                      tags: story.fields?.['System.Tags'] || story.tags
                    })) || [];

                    adoBacklogContext = {
                      epics: backlogContext.epics || [],
                      features: backlogContext.features || [],
                      userStories: enhancedUserStories,
                      tasks: backlogContext.tasks || [],
                      bugs: backlogContext.bugs || [],
                    };

                    const totalItems = (backlogContext.epics?.length || 0) +
                      (backlogContext.features?.length || 0) +
                      (backlogContext.userStories?.length || 0) +
                      (backlogContext.tasks?.length || 0) +
                      (backlogContext.bugs?.length || 0);
                    adoDataAvailable = totalItems > 0;
                  }
                }
              }
            } catch (adoError) {
              if (isUserJiraCredentialError(adoError)) {
                throw new Error(userJiraCredentialMessage(adoError));
              }
              console.warn("[API] Could not fetch backlog context for design:", adoError);
            }

            // Generate design content using AI
            const { generateDesignContent } = await import("./ai-service");

            // Prepare existing guidelines context
            let existingGuidelinesContext = '';
            if (existingGuidelines.length > 0) {
              const latestGuideline = existingGuidelines[0];
              existingGuidelinesContext = `
## Previous Design Guidelines

${latestGuideline.generatedPrompt || latestGuideline.content || ''}

## Original User Prompt
${latestGuideline.userPrompt || ''}

## Guidelines Content Used
${latestGuideline.guidelinesContent || ''}
`;
            }

            // Add uploaded guidelines content
            if (guidelinesContent && guidelinesContent.trim()) {
              existingGuidelinesContext += `\n\n## Current Guidelines Content\n${guidelinesContent}`;
            }

            updateProgress(30, "Generating design content (Bedrock)");
            console.log("[GenerateDesign:bedrock] Calling generateDesignContent", {
              designType,
              requirementChars: requirementWithUserJourney?.length ?? 0,
              guidelinesChars: existingGuidelinesContext?.length ?? 0,
              adoDataAvailable,
            });

            let designContent: string;
            try {
              designContent = await generateDesignContent(
                designType,
                requirementWithUserJourney,
                adoBacklogContext,
                existingGuidelinesContext
              );
            } catch (llmErr) {
              console.error("[GenerateDesign:bedrock] generateDesignContent failed:", llmErr);
              throw new Error(
                `Bedrock design generation failed: ${llmErr instanceof Error ? llmErr.message : String(llmErr)}`
              );
            }

            // Fail-fast: an empty/error LLM response would otherwise slide through
            // as a "successful" job with blank content, which shows to the user as
            // "instant completion with no design output". Surface it as a visible
            // failure instead so the poller's error field tells the client what
            // actually went wrong.
            const MIN_DESIGN_CONTENT_CHARS = 200;
            if (!designContent || designContent.trim().length < MIN_DESIGN_CONTENT_CHARS) {
              console.error("[GenerateDesign:bedrock] Empty/short content returned", {
                length: designContent?.length ?? 0,
                preview: designContent?.slice(0, 200) ?? "",
              });
              throw new Error(
                `Design generation returned empty/short content (${designContent?.length ?? 0} chars). ` +
                `Likely the Bedrock LLM call failed — check model access, quota, region, or IAM on AWS.`
              );
            }

            console.log(`[GenerateDesign:bedrock] Received ${designContent.length} chars of design content`);

            updateProgress(55, "Saving design asset");
            console.log("[GenerateDesign:asset] Creating design asset");

            // Create a temporary file URL (in production, this would be stored in cloud storage)
            const fileName = `${designCategory}-${Date.now()}.md`;
            const fileUrl = `data:text/markdown;base64,${Buffer.from(designContent).toString('base64')}`;

            // Save the generated design to design assets
            const asset = await sdlcService.createDesignAsset({
              projectId,
              phaseNumber: 2, // Design phase
              name: designType,
              description: `AI-generated ${designType} based on requirements`,
              fileUrl,
              fileType: "markdown",
              fileSize: designContent.length,
              source: "ai-generated",
              designCategory,
            });

            updateProgress(65, "Generating Figma prompt (Bedrock)");
            console.log("[GenerateDesign:figma] Building Figma prompt");

            // Generate Figma prompt using Bedrock Claude (same as generate-guidelines)
            let figmaPrompt: string;

            try {
              // Get base design context from existing guidelines
              let baseDesignContext = '';
              if (existingGuidelines && existingGuidelines.length > 0) {
                const guideline = existingGuidelines[0];
                baseDesignContext = guideline.content || guideline.generatedPrompt || '';
              }

              // Build a properly sanitized design intent for Phase-2
              let inferredDesignIntent = '';
              if (baseDesignContext && baseDesignContext.trim()) {
                // Phase-2: Create sanitized and abstracted design intent
                const designElements = [];

                if (designType) {
                  // Abstract the design type into UI patterns
                  switch (designType.toLowerCase()) {
                    case 'system design':
                    case 'architecture':
                      designElements.push('A system overview interface with hierarchical data visualization');
                      break;
                    case 'dashboard':
                      designElements.push('A data-centric dashboard with metrics panels and interactive charts');
                      break;
                    case 'form':
                    case 'crud':
                      designElements.push('A form-based interface with validation, input fields, and submission workflows');
                      break;
                    case 'list':
                    case 'table':
                      designElements.push('A data table interface with filtering, pagination, and row-level actions');
                      break;
                    default:
                      designElements.push(`A ${designType} interface with contextual UI elements`);
                  }
                }

                if (requirementWithUserJourney) {
                  const cleanRequirement = stripMarkdownHeaders(requirementWithUserJourney);
                  if (cleanRequirement.length > 0) {
                    // Extract acceptance criteria patterns for better UI design inference
                    const acceptanceCriteriaPattern = /##\s*Acceptance\s*Criteria\s*\n([^#]*?)(?=\n#|$)/gi;
                    let acceptanceCriteriaText = '';
                    let match;

                    while ((match = acceptanceCriteriaPattern.exec(cleanRequirement)) !== null) {
                      acceptanceCriteriaText += match[1].trim() + '\n';
                    }

                    // Analyze both requirements and acceptance criteria for UI patterns
                    const contentToAnalyze = cleanRequirement + ' ' + acceptanceCriteriaText;

                    // Abstract requirements into UI patterns based on content analysis
                    if (contentToAnalyze.toLowerCase().includes('manage') || contentToAnalyze.toLowerCase().includes('administration')) {
                      designElements.push('Management interface with status indicators and action controls');
                    }
                    if (contentToAnalyze.toLowerCase().includes('report') || contentToAnalyze.toLowerCase().includes('analytics') || contentToAnalyze.toLowerCase().includes('dashboard')) {
                      designElements.push('Analytics interface with data visualization components');
                    }
                    if (contentToAnalyze.toLowerCase().includes('workflow') || contentToAnalyze.toLowerCase().includes('process') || contentToAnalyze.toLowerCase().includes('step')) {
                      designElements.push('Process workflow interface with step indicators and progress tracking');
                    }
                    if (contentToAnalyze.toLowerCase().includes('form') || contentToAnalyze.toLowerCase().includes('input') || contentToAnalyze.toLowerCase().includes('submit')) {
                      designElements.push('Form interface with validation states and input field variations');
                    }
                    if (contentToAnalyze.toLowerCase().includes('list') || contentToAnalyze.toLowerCase().includes('table') || contentToAnalyze.toLowerCase().includes('filter')) {
                      designElements.push('Data table interface with filtering, sorting, and row-level actions');
                    }
                    if (contentToAnalyze.toLowerCase().includes('modal') || contentToAnalyze.toLowerCase().includes('dialog') || contentToAnalyze.toLowerCase().includes('popup')) {
                      designElements.push('Modal dialog interface with overlay and action buttons');
                    }
                    if (contentToAnalyze.toLowerCase().includes('notification') || contentToAnalyze.toLowerCase().includes('alert') || contentToAnalyze.toLowerCase().includes('message')) {
                      designElements.push('Notification system with different alert states and messaging');
                    }
                    if (contentToAnalyze.toLowerCase().includes('upload') || contentToAnalyze.toLowerCase().includes('file') || contentToAnalyze.toLowerCase().includes('attachment')) {
                      designElements.push('File upload interface with drag-drop area and progress indicators');
                    }

                    // Add acceptance criteria-specific UI patterns
                    if (acceptanceCriteriaText) {
                      if (acceptanceCriteriaText.toLowerCase().includes('validation') || acceptanceCriteriaText.toLowerCase().includes('error')) {
                        designElements.push('Validation interface with error states and user feedback');
                      }
                      if (acceptanceCriteriaText.toLowerCase().includes('permission') || acceptanceCriteriaText.toLowerCase().includes('access') || acceptanceCriteriaText.toLowerCase().includes('role')) {
                        designElements.push('Permission-based interface with conditional element visibility');
                      }
                      if (acceptanceCriteriaText.toLowerCase().includes('search') || acceptanceCriteriaText.toLowerCase().includes('filter')) {
                        designElements.push('Search and filtering interface with query input and result display');
                      }
                    }

                    // Add generic abstraction if no patterns match
                    if (designElements.length === 0) {
                      designElements.push('Content-specific interface elements using existing component patterns');
                    }
                  }
                }

                // Build design intent with acceptance criteria included
                let designIntentParts = [];

                if (designElements.length > 0) {
                  designIntentParts.push(
                    `Add UI elements that include:\n${designElements.map(e => `- ${e}`).join('\n')}`
                  );
                }

                // Extract and translate Acceptance Criteria into UI constraints (UI-safe only)
                if (requirementWithUserJourney) {
                  const acceptanceCriteriaPattern =
                    /##\s*Acceptance\s*Criteria\s*\n([^#]*?)(?=\n#|$)/gi;

                  const uiConstraints: string[] = [];
                  let match;

                  while ((match = acceptanceCriteriaPattern.exec(requirementWithUserJourney)) !== null) {
                    const acText = match[1];

                    if (!acText) continue;

                    // Split AC into logical statements (Given / When / Then / And)
                    const statements = acText
                      .split(/\n+/)
                      .map(s => s.trim())
                      .filter(Boolean);

                    statements.forEach(statement => {
                      const s = statement.toLowerCase();

                      // ❌ Ignore non-UI concerns explicitly
                      if (
                        s.startsWith('given') ||
                        s.includes('audit') ||
                        s.includes('analytics') ||
                        s.includes('log') ||
                        s.includes('monitor') ||
                        s.includes('api') ||
                        s.includes('websocket server')
                      ) {
                        return;
                      }

                      // ✅ Validation & submission states
                      if (s.includes('required') || s.includes('mandatory')) {
                        uiConstraints.push(
                          'Indicate required fields and prevent submission until inputs are valid'
                        );
                      }

                      if (s.includes('invalid') || s.includes('error')) {
                        uiConstraints.push(
                          'Display inline validation errors with corrective guidance'
                        );
                      }

                      if (s.includes('submit') || s.includes('save')) {
                        uiConstraints.push(
                          'Disable primary actions until validation conditions are satisfied'
                        );
                      }

                      // ✅ Permission & visibility states
                      if (s.includes('permission') || s.includes('role') || s.includes('access')) {
                        uiConstraints.push(
                          'Apply role-based visibility and read-only states with user-facing explanation'
                        );
                      }

                      if (s.includes('read-only') || s.includes('cannot edit')) {
                        uiConstraints.push(
                          'Render affected fields as read-only with clear visual distinction'
                        );
                      }

                      // ✅ Status-driven UI behavior
                      if (
                        s.includes('status') &&
                        (s.includes('open') || s.includes('in progress') || s.includes('pending') || s.includes('approved'))
                      ) {
                        uiConstraints.push(
                          'When entity status changes, update status badges and related timestamps dynamically without page reload'
                        );
                      }

                      // ✅ Error, empty & recovery states
                      if (s.includes('unable to load') || s.includes('failed')) {
                        uiConstraints.push(
                          'Show a prominent error banner with retry option while keeping the UI responsive'
                        );
                      }

                      if (s.includes('no data') || s.includes('no results')) {
                        uiConstraints.push(
                          'Display empty states with explanatory messaging and suggested next actions'
                        );
                      }

                      // ✅ Real-time updates
                      if (s.includes('real-time') || s.includes('live') || s.includes('without page reload')) {
                        uiConstraints.push(
                          'Reflect real-time data updates immediately using subtle, non-disruptive animation'
                        );
                      }

                      // ✅ Performance-related UX expectations
                      if (s.includes('within') && s.includes('ms')) {
                        uiConstraints.push(
                          'Use loading indicators or skeleton states to maintain perceived performance'
                        );
                      }
                    });
                  }

                  if (uiConstraints.length > 0) {
                    const uniqueConstraints = [...new Set(uiConstraints)];
                    designIntentParts.push(
                      `\nUI CONSTRAINTS:\n${uniqueConstraints.map(c => `- ${c}`).join('\n')}`
                    );
                  }
                }

                designIntentParts.push('\nUse existing components and maintain consistency with the established design system.');

                inferredDesignIntent = designIntentParts.join('\n');

                // Use buildPhase2DesignPrompt function (with user journey task for prompt start)
                // Pass the per-story requirement/acceptance-criteria content so the prompt
                // is unique per story, plus a concise epic/product domain backdrop so the
                // design stays grounded in real domain terminology instead of generic placeholders.
                const epicDomainContext = buildEpicDomainContext(adoBacklogContext);
                figmaPrompt = buildPhase2DesignPrompt(baseDesignContext, inferredDesignIntent, undefined, userJourneyTaskForFigma, requirementWithUserJourney, epicDomainContext);
              } else {
                // Fallback: No existing guidelines - create basic prompt
                const cleanRequirement = requirementWithUserJourney ? stripMarkdownHeaders(requirementWithUserJourney) : '';
                figmaPrompt = `Create Figma Make commands for ${designType || 'UI components'}.\n\nRequirements: ${cleanRequirement || 'Standard UI components'}\n\nOutput only clean Figma Make instructions.`;
              }// Send the figmaPrompt directly to Azure OpenAI
              const OpenAI = (await import("openai")).default;

              const { hasBedrock: _hasBedrock1, azureOpenAI: _bedrockLLM1, llmConfig: _llmCfg1 } = await import("./llm-config");
              const useAzureOpenAI = !_hasBedrock1 && process.env.AZURE_OPENAI_API_KEY && process.env.AZURE_OPENAI_ENDPOINT;
              const hasAIIntegrations = process.env.AI_INTEGRATIONS_OPENAI_API_KEY && process.env.AI_INTEGRATIONS_OPENAI_BASE_URL;
              const hasOpenAI = process.env.OPENAI_API_KEY;

              if (!_hasBedrock1 && !useAzureOpenAI && !hasAIIntegrations && !hasOpenAI) {
                throw new Error("AI integration not configured. Please set up Azure OpenAI, AI Integrations, or OpenAI API key.");
              }

              let openai: any;
              let modelName: string;

              if (_hasBedrock1 && _bedrockLLM1) {
                openai = _bedrockLLM1;
                modelName = _llmCfg1.azureOpenAIDeployment ?? "";
              } else if (useAzureOpenAI) {
                const { AzureOpenAI } = await import('openai');
                openai = new AzureOpenAI({
                  apiKey: process.env.AZURE_OPENAI_API_KEY!,
                  endpoint: process.env.AZURE_OPENAI_ENDPOINT!,
                  apiVersion: process.env.AZURE_OPENAI_API_VERSION || "2024-02-01",
                  deployment: process.env.AZURE_OPENAI_DEPLOYMENT!,
                });
                modelName = process.env.AZURE_OPENAI_DEPLOYMENT!;
              } else if (hasAIIntegrations) {
                openai = new OpenAI({
                  baseURL: process.env.AI_INTEGRATIONS_OPENAI_BASE_URL!,
                  apiKey: process.env.AI_INTEGRATIONS_OPENAI_API_KEY!,
                });
                modelName = "gpt-4o";
              } else {
                openai = new OpenAI({
                  apiKey: process.env.OPENAI_API_KEY!,
                });
                modelName = "gpt-4o";
              }

              console.log("[GenerateDesign:figma] Calling Bedrock", {
                modelName,
                promptChars: figmaPrompt?.length ?? 0,
              });

              const response = await openai.chat.completions.create({
                model: modelName,
                messages: [{ role: "user", content: figmaPrompt }],
                max_tokens: 1500,
                temperature: 0.7
              });

              const aiResponse = response.choices[0]?.message?.content?.trim();

              if (!aiResponse || aiResponse.trim() === '') {
                throw new Error("AI service returned empty response");
              }

              figmaPrompt = aiResponse.trim();
              console.log(`[GenerateDesign:figma] Received ${figmaPrompt.length} chars of Figma prompt`);
            } catch (promptError) {
              console.error("[GenerateDesign:figma] Error generating AI design prompt (falling back to simple prompt):", promptError);
              // Fallback to simple prompt — deliberate graceful degradation, not a
              // fatal failure. The job still completes with a usable (simpler)
              // figmaPrompt so the user at least gets the design content.
              const cleanRequirement = requirementWithUserJourney ? stripMarkdownHeaders(requirementWithUserJourney) : '';
              figmaPrompt = `Create ${designType || 'UI components'} for: ${cleanRequirement || 'the application'}`;
            }

            updateProgress(85, "Syncing to ADO (if configured)");

            // Sync to Azure DevOps if configured
            let adoWorkItemId = null;
            try {
              // Use central settings (artifact_organizations)
              const artifactOrgs = await storage.getArtifactOrganizations();
              const firstOrg = artifactOrgs[0];

              if (firstOrg?.patToken) {
                const decryptedPAT = decryptPAT(firstOrg.patToken);

                if (decryptedPAT) {
                  // Extract organization from URL
                  const organization = firstOrg.organizationUrl.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '');

                  const { AzureDevOpsService } = await import("./azure-devops-service");
                  const adoService = new AzureDevOpsService({
                    organization,
                    project: firstOrg.projectName,
                    pat: decryptedPAT,
                  });

                  // Create a Task work item in ADO for the design document
                  const workItemTitle = `${designType} - ${new Date().toLocaleDateString()}`;
                  const workItemDescription = `<h2>AI-Generated ${designType}</h2>
<p>Generated on: ${new Date().toLocaleString()}</p>
<p>Project: ${firstOrg.projectName}</p>
<h3>Design Content</h3>
<pre>${designContent.substring(0, 5000)}${designContent.length > 5000 ? '...\n\n(Full content available in Design Phase of DevPlatform)' : ''}</pre>`;

                  adoWorkItemId = await adoService.createWorkItemFromChat(
                    'Task',
                    workItemTitle,
                    workItemDescription,
                    undefined,
                    undefined,
                    undefined,
                    undefined,
                    ['design', 'ai-generated', designCategory].join(', ')
                  );
                }
              }
            } catch (adoError) {
              console.error('[API] Failed to sync to Azure DevOps (non-fatal):', adoError);
              // Don't fail the whole request if ADO sync fails
            }

            updateProgress(100, "Design generated");
            console.log("[GenerateDesign:done] Job completed successfully", {
              contentChars: designContent.length,
              figmaPromptChars: figmaPrompt?.length ?? 0,
              adoWorkItemId,
              adoDataUsed: adoDataAvailable,
            });
            return {
              success: true,
              content: designContent,
              designContent: designContent,
              figmaPrompt: figmaPrompt,
              figmaLink: existingFigmaLink,
              asset,
              adoWorkItemId,
              adoDataUsed: adoDataAvailable,
              message: `${designType} generated successfully${adoDataAvailable ? ' using Azure DevOps backlog context' : ''}${adoWorkItemId ? ` and synced to ADO (Work Item #${adoWorkItemId})` : ''}${existingFigmaLink ? ` with Figma link: ${existingFigmaLink}` : ''}`,
            };
          },
          "Generating design",
        );

        return res.status(202).json({
          success: true,
          jobId,
          status: "processing",
          message: `Design generation started. Poll /api/jobs/sdlc-generate-design/status/${jobId} for status.`,
        });
      } catch (error) {
        console.error("Error starting design generation:", error);
        res.status(500).json({
          error: "Failed to start design generation",
          details: error instanceof Error ? error.message : String(error)
        });
      }
    });

  /**
   * Strip markdown structure and headers from content to prevent duplication
   */
  function stripMarkdownHeaders(input: string): string {
    return input
      .replace(/^#{1,6}\s+.*$/gm, '')   // remove headings
      .replace(/Design Type:\s*.*$/gi, '')
      .replace(/^\s*[-*+]\s+/gm, '')  // remove bullet points
      .replace(/^\s*\d+\.\s+/gm, '')  // remove numbered lists
      .replace(/\*\*(.*?)\*\*/g, '$1')  // remove bold formatting
      .replace(/\*(.*?)\*/g, '$1')     // remove italic formatting
      .replace(/`(.*?)`/g, '$1')       // remove inline code formatting
      .replace(/^\s*>\s+/gm, '')       // remove blockquotes
      .trim();
  }

  /**
   * Phase-2: Build continuation prompt for Figma Make (template from prompts folder).
   * Extends Phase-1 base UI foundation WITHOUT redefining it.
   */
  function buildPhase2DesignPrompt(
    baseDesignContext: string,
    inferredDesignIntent: string,
    uiConstraints: string = '',
    userJourneyTask: string = '',
    storyContext: string = '',
    epicDomainContext: string = ''
  ): string {
    if (!baseDesignContext || !baseDesignContext.trim()) {
      throw new Error("Phase-1 base design context missing. Phase-2 cannot run.");
    }
    const combinedIntent = [inferredDesignIntent, uiConstraints]
      .filter((s) => s && s.trim())
      .join('\n\n');
    return buildPhase2DesignPromptTemplate(
      userJourneyTask,
      baseDesignContext,
      combinedIntent,
      storyContext,
      epicDomainContext,
    );
  }

  /**
   * Build a concise epic/product domain backdrop from the fetched backlog context.
   * Kept intentionally tight (few items, truncated descriptions) to protect the
   * token budget — this is supporting context, the user story stays primary.
   */
  function buildEpicDomainContext(backlog: {
    epics?: any[];
    features?: any[];
  } | undefined): string {
    if (!backlog) return '';
    const clean = (v: unknown) =>
      String(v ?? '')
        .replace(/<[^>]+>/g, ' ') // strip HTML (ADO descriptions are HTML)
        .replace(/\s+/g, ' ')
        .trim();
    const summarize = (items: any[] | undefined, label: string, max: number, descLen: number) =>
      (Array.isArray(items) ? items : [])
        .slice(0, max)
        .map((it: any) => {
          const title = clean(it?.title || it?.fields?.['System.Title']);
          const desc = clean(it?.description || it?.fields?.['System.Description']).slice(0, descLen);
          return title ? `- ${label}: ${title}${desc ? ` — ${desc}` : ''}` : '';
        })
        .filter(Boolean);

    const lines = [
      ...summarize(backlog.epics, 'Epic', 3, 200),
      ...summarize(backlog.features, 'Feature', 4, 140),
    ];
    return lines.join('\n').slice(0, 1200);
  }

  // Helper function to build Phase 1 Guideline Prompt for Figma Make
  function buildPhase1GuidelinePrompt(
    goldenRepoGuidelines: string,
    uploadedGuidelines: string,
    userDesignIntent: string
  ): string {
    // Inject guidelines and user design intent at the top
    let contextSection = '';

    if (goldenRepoGuidelines && goldenRepoGuidelines.trim()) {
      // Clean guidelines content, removing boilerplate headers
      const cleanGuidelines = goldenRepoGuidelines
        .replace(/## Golden Repository Guidelines:[\s\S]*?Corporate design standards and component library guidelines from golden repository\./g, '')
        .replace(/Selected guidelines from :\s*-\s*\/Design\/guidline\.txt/g, '')
        .trim();

      if (cleanGuidelines) {
        contextSection += `${cleanGuidelines}\n\n`;
      }
    }

    if (uploadedGuidelines && uploadedGuidelines.trim()) {
      contextSection += `${uploadedGuidelines.trim()}\n\n`;
    }

    if (userDesignIntent && userDesignIntent.trim()) {
      contextSection += `Design Intent: ${userDesignIntent.trim()}\n\n`;
    }

    return `${contextSection}You are acting as a DESIGN SYSTEM GENERATOR for WEB APPLICATIONS.

Your output will be used DIRECTLY in Figma Make to generate a reusable application foundation.
This is NOT a feature design task.
- The provided design guidelines are the SINGLE SOURCE OF TRUTH.
- Follow them strictly and literally.
- Do NOT invent, override, or reinterpret any rules.
- If something is not specified, infer conservatively using standard enterprise web patterns.
- Assume React-based web implementation.

════════════════════════════════════
INPUT DESIGN GUIDELINES
════════════════════════════════════
The following guidelines describe the product's UI/UX philosophy, layout rules, components, accessibility, and engineering constraints.

Read them fully and internalize them before generating output:

${goldenRepoGuidelines}

${uploadedGuidelines}

════════════════════════════════════
USER DESIGN INTENT
════════════════════════════════════
${userDesignIntent}

════════════════════════════════════
YOUR TASK
════════════════════════════════════
Generate a COMPLETE **FOUNDATION DESIGN SYSTEM** for a WEB APPLICATION.

This design system must be:
- Global
- Reusable
- Domain-agnostic but domain-aware
- Suitable for large-scale enterprise apps

DO NOT design:
- Feature flows
- User journeys
- Screens tied to a single use case
- Business logic

1. Global Application Layout
- Fixed header
- Collapsible sidebar
- Scrollable main content area
- Optional footer
- Responsive behavior for desktop, tablet, and mobile

2. Header Components
- Brand/logo area with domain-relevant name
- Global search input with placeholder text
- Notification icon with badge
- Theme toggle switch (light/dark)
- User profile dropdown menu

3. Sidebar Navigation
- Use DOMAIN-RELEVANT SEMANTIC LABELS
- Grouped navigation sections
- Maximum 3 levels of nesting
- Active, hover, focus, disabled states
- Keyboard accessible

4. Design Tokens (Web-Ready)
Define token categories clearly:
- Colors (primary, secondary, neutral, semantic)
- Typography scale (headings, body, labels)
- Spacing system (based on the defined base unit)
- Elevation (shadows / borders)
- Border radius
- Motion & animation timing

Tokens must be:
- CSS-variable friendly
- Theme-aware
- Free of hardcoded values

5. Component Library
Create components with DOMAIN-RELEVANT LABELS:
- Buttons (e.g. “Create Patient”, “Submit Claim” – domain dependent)
- Forms with labels and validation examples
- Tables with domain-style column headers
- Status badges with semantic meaning
- Modals and drawers

These are STRUCTURAL EXAMPLES ONLY.
No real workflows.

6. Accessibility
- WCAG 2.1 AA
- Keyboard navigation
- Visible focus indicators
- Semantic naming

════════════════════════════════════
OUTPUT RULES (CRITICAL)
════════════════════════════════════
- Output ONLY a Figma Make–compatible design instruction prompt
- NO explanations
- NO commentary
- NO markdown meta discussion
- NO references to "guidelines above"
- NO Figma UI terminology (frames, auto-layout, etc.)
- Describe components and structure in clear, declarative instructions
QUALITY BAR
The output should be good enough that:
- It can be pasted directly into Figma Make
- It generates a professional enterprise web app foundation
- Future epics and user stories can build on top of it without redesigning layout or components
`;
  }

  // Generate Guidelines with AI (async job — avoids API Gateway 29s → 503 on long LLM calls)
  app.post("/api/sdlc/projects/:projectId/generate-guidelines", async (req: Request, res: Response) => {
    try {
      const { projectId } = req.params;
      const {
        requirementDocument,
        userPrompt,
        guidelinesContent,
        figmaLink,
      } = req.body;

      const userDesignIntent = String(
        userPrompt ?? requirementDocument ?? "",
      ).trim();

      if (!userDesignIntent) {
        return res.status(400).json({
          error: "A design prompt or requirement description is required.",
        });
      }

      try {
        await consumeTokensForRequest(req as any, DESIGN_GENERATION_TOKEN_COST);
      } catch (tokenErr) {
        if (tokenErr instanceof TokenQuotaExceededError) {
          return res.status(402).json({
            success: false,
            code: TOKEN_QUOTA_EXCEEDED_CODE,
            message: "Token quota exceeded for this tenant.",
          });
        }
        throw tokenErr;
      }

      const { hasAnyChatLlm, llm } = await import("./llm-config");
      if (!hasAnyChatLlm() || !llm?.azureOpenAI) {
        return res.status(503).json({
          error: "AI integration not configured",
          details:
            "Configure Amazon Bedrock (AWS), Azure OpenAI, or Anthropic for this environment.",
        });
      }

      // VALIDATION: Check if guidelines with Figma link already exist for this project
      try {
        const existingGuidelines = await db.select()
          .from(schema.designGuidelines)
          .where(eq(schema.designGuidelines.projectId, projectId))
          .orderBy(desc(schema.designGuidelines.createdAt));
        const guidelineWithFigmaLink = existingGuidelines.find(g =>
          g.figmaLink &&
          g.figmaLink.trim().length > 0 &&
          g.figmaLink.trim() !== 'null' &&
          g.figmaLink.trim() !== 'undefined'
        );

        if (guidelineWithFigmaLink) {
          return res.status(409).json({
            error: "Guidelines already exist for this project"
          });
        }
      } catch (validationError) {
        console.error("[API] Validation check failed for guidelines:", validationError);
        return res.status(500).json({
          success: false,
          error: "Validation failed",
          message: "Unable to check existing guidelines. Please try again.",
          details: validationError instanceof Error ? validationError.message : 'Unknown validation error'
        });
      }

      const guidelinesPayload = guidelinesContent || '';
      const figmaLinkTrimmed = figmaLink?.trim() || null;

      const { jobId } = asyncJobManager.start(
        "sdlc-generate-guidelines",
        async ({ updateProgress }) => {
          updateProgress(10, "Building design guideline prompt");

          const figmaPrompt = buildPhase1GuidelinePrompt(
            '',
            guidelinesPayload,
            userDesignIntent,
          );

          updateProgress(30, "Generating design guidelines with AI");

          const modelName =
            llmConfig.azureOpenAIDeployment ||
            process.env.AZURE_OPENAI_DEPLOYMENT ||
            process.env.BEDROCK_MODEL_ID ||
            "gpt-4o";

          let baseDesignOutput: string;
          try {
            const response = await llm.azureOpenAI.chat.completions.create({
              model: modelName,
              messages: [{ role: "user", content: figmaPrompt }],
              max_tokens: 8000,
              temperature: 0.7,
            });

            const aiResponse = response.choices[0]?.message?.content?.trim();
            if (!aiResponse) {
              throw new Error("AI service returned empty or null response");
            }
            baseDesignOutput = aiResponse;
          } catch (aiError) {
            console.error('[API] AI call failed for guidelines generation:', aiError);
            if (aiError instanceof Error && aiError.message.includes('404')) {
              throw new Error(
                `AI deployment not found (${modelName}). Verify model/deployment configuration.`,
              );
            }
            throw aiError instanceof Error
              ? new Error(`AI service error: ${aiError.message}`)
              : new Error('AI failed to generate base design foundation');
          }

          updateProgress(80, "Saving design guidelines");

          const guidelineId = randomUUID();
          await db.insert(schema.designGuidelines).values({
            id: guidelineId,
            projectId,
            title: `Base Design System - ${new Date().toLocaleDateString()}`,
            type: 'Design Guidelines',
            content: baseDesignOutput,
            figmaLink: figmaLinkTrimmed,
            userPrompt: userDesignIntent,
            generatedPrompt: baseDesignOutput,
            guidelinesContent: guidelinesPayload || null,
            adoWorkItemId: null,
            status: 'active',
          });

          const createdGuideline = await db.select()
            .from(schema.designGuidelines)
            .where(eq(schema.designGuidelines.id, guidelineId))
            .limit(1);

          updateProgress(100, "Design guidelines ready");

          return {
            success: true,
            content: baseDesignOutput,
            guidelineContent: baseDesignOutput,
            figmaPrompt,
            guideline: createdGuideline[0],
            message: `Design Guidelines generated successfully${figmaLinkTrimmed ? ' with Figma link saved' : ''}`,
          };
        },
        "Generating design guidelines",
      );

      return res.status(202).json({
        success: true,
        jobId,
        status: "processing",
        message: `Design guideline generation started. Poll /api/jobs/sdlc-generate-guidelines/status/${jobId} for status.`,
      });
    } catch (error) {
      console.error("Error starting guideline generation:", error);
      res.status(500).json({
        error: "Failed to generate guidelines",
        details: error instanceof Error ? error.message : String(error)
      });
    }
  });

