  // Get pipeline builds

  app.get(
    "/api/sdlc/projects/:projectId/ado/repositories",
    async (req: Request, res: Response) => {
      try {
        const { projectId } = req.params;
        const { organization: queryOrgRaw, projectName: queryProjectNameRaw } = req.query;
        const queryOrg =
          Array.isArray(queryOrgRaw) && queryOrgRaw.length > 0
            ? String(queryOrgRaw[0])
            : (queryOrgRaw as string | undefined);
        const queryProjectName =
          Array.isArray(queryProjectNameRaw) && queryProjectNameRaw.length > 0
            ? String(queryProjectNameRaw[0])
            : (queryProjectNameRaw as string | undefined);

        const project = await sdlcService.getProject(projectId);

        if (!project) {
          console.error(
            "[SDLC][ADO Repos] Project not found in SDLC for id (continuing with artifact org + query params):",
            projectId
          );
          // Do NOT return here; we can still resolve PAT + org from artifact organizations
        }

        // Resolve PAT from Client Settings (artifact_organizations), preferring an entry
        // whose organization matches the provided query org (short name), just like
        // /api/sdlc/projects/:projectId/ado/backlog-context.
        const artifactOrgs = await storage.getArtifactOrganizations();

        let targetOrg: any = null;
        if (queryOrg) {
          targetOrg = artifactOrgs.find((org) => {
            let orgName = org.organizationUrl;
            if (orgName.includes("dev.azure.com")) {
              orgName = orgName
                .replace(/https?:\/\/dev\.azure\.com\//, "")
                .replace(/\/$/, "")
                .split("/")[0];
            } else if (orgName.includes("visualstudio.com")) {
              const match = orgName.match(/([^\.]+)\.visualstudio\.com/);
              if (match) {
                orgName = match[1];
              }
            }
            orgName = orgName.replace(/\/+$/, "").trim();
            return orgName === queryOrg && org.patToken;
          });
        }

        const firstOrg =
          targetOrg || artifactOrgs.find((org) => org.patToken) || artifactOrgs[0];

        if (!firstOrg || !firstOrg.patToken) {
          return res.status(400).json({
            error: "Azure DevOps not configured. Please configure in Settings > Client Settings.",
          });
        }

        const decryptedPAT = decryptPAT(firstOrg.patToken);
        if (!decryptedPAT) {
          return res.status(400).json({
            error: "Failed to decrypt Azure DevOps PAT token from Client Settings.",
          });
        }

        // Extract short organization name from URL
        let organization = firstOrg.organizationUrl;
        if (organization.includes("dev.azure.com")) {
          organization = organization
            .replace(/https?:\/\/dev\.azure\.com\//, "")
            .replace(/\/$/, "")
            .split("/")[0];
        } else if (organization.includes("visualstudio.com")) {
          const match = organization.match(/([^\.]+)\.visualstudio\.com/);
          if (match) {
            organization = match[1];
          }
        }
        organization = organization.replace(/\/+$/, "").trim();

        // Debug logging for PAT/org/project being used (PAT masked)
        const maskedPat =
          decryptedPAT.length > 8
            ? `${decryptedPAT.slice(0, 4)}****${decryptedPAT.slice(-4)}`
            : "****";
        console.log("[SDLC][ADO Repos] Using ADO config:", {
          queryOrg,
          queryProjectName,
          resolvedOrganization: organization,
          artifactOrgUrl: firstOrg.organizationUrl,
          artifactOrgProjectName: firstOrg.projectName,
          sdlcProjectId: projectId,
          sdlcProjectAdoProjectUrl: (project as any)?.adoProjecturl,
          patMasked: maskedPat,
        });

        // Prefer the project identifier from the SDLC project's adoProjecturl,
        // falling back to queryProjectName or artifact org's projectName.
        let projectIdentifier: string | undefined = undefined;
        const adoProjectUrl = (project as any)?.adoProjecturl as string | undefined;
        if (adoProjectUrl) {
          try {
            const u = new URL(adoProjectUrl);
            const segments = u.pathname.split("/").filter(Boolean);
            // Typical pattern: /{org}/_apis/projects/{projectId}
            const projectsIdx = segments.findIndex((s) => s.toLowerCase() === "projects");
            if (projectsIdx >= 0 && segments[projectsIdx + 1]) {
              projectIdentifier = segments[projectsIdx + 1];
            }
          } catch {
            // ignore parse errors and fall back below
          }
        }
        if (!projectIdentifier) {
          projectIdentifier = queryProjectName || firstOrg.projectName;
        }

        if (!projectIdentifier) {
          return res.status(400).json({
            error:
              "Unable to determine Azure DevOps project identifier. Please ensure adoProjecturl or project name is configured.",
          });
        }

        const azureConfig: AzureConfig = {
          organization,
          project: projectIdentifier,
          pat: decryptedPAT,
        };

        const adoService = new AzureDevOpsService(azureConfig);
        const repositories = await adoService.getRepositories(projectIdentifier);
        return res.json(repositories);
      } catch (error: any) {
        console.error("[SDLC] Failed to fetch ADO repositories:", error);
        res.status(500).json({
          error:
            error?.message ||
            "Failed to fetch Azure DevOps repositories for this project.",
        });
      }
    }
  );

  // Get releases
  app.get("/api/sdlc/projects/:projectId/ado/releases", async (req: Request, res: Response) => {
    try {
      const { projectId } = req.params;
      const { definitionId, top, organization: queryOrg, projectName: queryProjectName, sprintPath: sprintPathRaw } = req.query;

      // Disable caching when sprintPath is provided to ensure fresh filtered data
      if (req.query.sprintPath) {
        res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate');
        res.setHeader('Pragma', 'no-cache');
        res.setHeader('Expires', '0');
      }

      // Try to get SDLC project, but don't fail if it doesn't exist (could be ADO project ID)
      // This allows the route to work with both SDLC project IDs and ADO project IDs
      if (projectId !== "default") {
        try {
          const project = await sdlcService.getProject(projectId);
          if (!project) {
            // Project might not exist in SDLC table if it's an ADO project ID
          }
        } catch (error) {
          // Project might not exist in SDLC table if it's an ADO project ID
        }

        // Use client settings (Artifact Organizations) for Azure DevOps credentials
        // Pass both organization and projectName to match the correct artifact organization
        const azureConfig = await getAzureDevOpsConfig(queryProjectName as string | undefined, queryOrg as string | undefined);

        if (!azureConfig) {
          return res.status(400).json({
            error: "Azure DevOps not configured. Please configure in Settings > Central Settings."
          });
        }

        const adoService = new AzureDevOpsService(azureConfig);

        // Handle sprint filtering if sprintPath is provided
        let sprintStartDate: Date | null = null;
        let sprintEndDate: Date | null = null; if (sprintPathRaw) {
          try {
            let sprintPath = Array.isArray(sprintPathRaw) ? String(sprintPathRaw[0] || '') : String(sprintPathRaw || '');// Decode URL-encoded sprint path (URLSearchParams automatically decodes, but handle double-encoding)
            try {
              sprintPath = decodeURIComponent(sprintPath);
            } catch (e) {
              // If decoding fails, try decoding again (handles double-encoding)
              try {
                sprintPath = decodeURIComponent(decodeURIComponent(sprintPath));
              } catch (e2) {
                // If still fails, use as-is
                console.warn(`[ado/releases] Could not decode sprintPath, using as-is: ${sprintPath}`);
              }
            } const allIterations = await adoService.getAllIterations(queryProjectName as string | undefined);// Try multiple matching strategies
            let sprintInfo = allIterations.find((iter: any) => iter.path === sprintPath);

            if (!sprintInfo) {
              // Try case-insensitive match
              sprintInfo = allIterations.find((iter: any) =>
                iter.path.toLowerCase() === sprintPath.toLowerCase()
              );
            }

            if (!sprintInfo) {
              // Try matching by last part of path
              const sprintName = sprintPath.split('\\').pop() || sprintPath.split('/').pop() || sprintPath;
              sprintInfo = allIterations.find((iter: any) =>
                iter.name === sprintName ||
                iter.path.endsWith(sprintName) ||
                iter.path.toLowerCase().endsWith(sprintName.toLowerCase())
              );
            }

            if (sprintInfo && sprintInfo.startDate && sprintInfo.endDate) {
              sprintStartDate = new Date(sprintInfo.startDate);
              sprintEndDate = new Date(sprintInfo.endDate);
              // Set start date to beginning of day
              sprintStartDate.setHours(0, 0, 0, 0);
              // Set end date to end of day
              sprintEndDate.setHours(23, 59, 59, 999);
            } else {
              console.warn(`[ado/releases] Sprint not found: ${sprintPath}`);
              console.warn(`[ado/releases] Available sprints:`, allIterations.map((iter: any) => ({ path: iter.path, name: iter.name })));
            }
          } catch (error) {
            console.error(`[ado/releases] Error fetching sprint info:`, error);
          }
        }

        const releases = await adoService.getReleases(
          definitionId ? Number(definitionId) : undefined,
          top ? Number(top) : 50
        );

        // Handle both array and { value: [] } formats
        let releasesArray: any[] = Array.isArray(releases) ? releases : ((releases as any)?.value || []);

        // Filter releases by sprint date range if sprint dates are available
        if (sprintStartDate && sprintEndDate) {
          const beforeFilter = releasesArray.length; releasesArray = releasesArray.filter((release: any) => {
            // Use createdOn (when release was created) for filtering
            const releaseDateStr = release.createdOn;
            if (!releaseDateStr) {
              return false;
            }

            const releaseDate = new Date(releaseDateStr);

            // Ensure dates are valid
            if (isNaN(releaseDate.getTime())) {
              return false;
            }

            // Compare dates
            const isInRange = releaseDate >= sprintStartDate && releaseDate <= sprintEndDate;
            return isInRange;
          });
        } else { }

        // Enrich releases with stored user information
        const enrichedReleases = releasesArray.map((release: any) => {
          const userInfo = releaseUserInfo.get(release.id);
          if (userInfo) {
            // Override createdBy with stored user info
            if (userInfo.createdByName || userInfo.triggeredByName) {
              release.createdBy = {
                ...(release.createdBy || {}),
                displayName: userInfo.createdByName || userInfo.triggeredByName || release.createdBy?.displayName,
                uniqueName: userInfo.createdBy || userInfo.triggeredBy || release.createdBy?.uniqueName,
              };
            }
          }
          return release;
        });

        // Return in the same format as received
        if (Array.isArray(releases)) {
          res.json(enrichedReleases);
        } else {
          res.json({ ...(releases as any), value: enrichedReleases });
        }
      }
    } catch (error: any) {
      console.error("Error fetching releases:", error);
      const errorMessage = error.message || "Failed to fetch releases";
      // Check if error message contains HTML
      if (errorMessage.includes("<!DOCTYPE") || errorMessage.includes("<html")) {
        return res.status(500).json({
          error: "Azure DevOps API returned an error. Please check your PAT token and organization/project configuration."
        });
      }
      res.status(500).json({ error: errorMessage });
    }
  });

  // Get specific release by ID
