  // Get release details with linked user stories (work items, commits, builds, PRs, artifacts)
  app.get("/api/sdlc/projects/:projectId/ado/releases/:releaseId/details", async (req: Request, res: Response) => {
    // Ensure we always return JSON - set this immediately
    res.setHeader('Content-Type', 'application/json'); try {
      const { projectId, releaseId } = req.params;
      const { organization: queryOrg, projectName: queryProjectName } = req.query;

      if (!releaseId) {
        return res.status(400).json({
          error: "Release ID is required",
          releaseId: releaseId
        });
      }

      // Try to get SDLC project, but don't fail if it doesn't exist
      try {
        const project = await sdlcService.getProject(projectId);
        if (!project) { }
      } catch (error) { }

      // Use client settings (Artifact Organizations) for Azure DevOps credentials
      const azureConfig = await getAzureDevOpsConfig(queryProjectName as string | undefined, queryOrg as string | undefined);

      if (!azureConfig) {
        return res.status(400).json({
          error: "Azure DevOps not configured. Please configure in Settings > Central Settings."
        });
      }

      const adoService = new AzureDevOpsService(azureConfig);

      // Fetch release
      let release: any;
      try {
        release = await adoService.getRelease(Number(releaseId), queryProjectName as string | undefined);
      } catch (error: any) {
        console.error(`[Release Details] Error fetching release:`, error);
        const errorMessage = error.message || "Failed to fetch release";
        if (errorMessage.includes("<!DOCTYPE") || errorMessage.includes("<html")) {
          return res.status(500).json({
            error: "Azure DevOps API returned an error. Please check your PAT token and organization/project configuration.",
            details: "The API returned an HTML error page instead of JSON."
          });
        }
        throw error;
      }

      // Fetch work items from release
      let workItems: any[] = [];
      try {
        workItems = await adoService.getReleaseWorkItems(Number(releaseId), queryProjectName as string | undefined);
      } catch (err: any) {
        console.error(`[Release Details] Error fetching release work items:`, err.message);
        if (release.workItems && Array.isArray(release.workItems)) {
          workItems = release.workItems;
        }
      }

      // Extract build IDs from release artifacts
      const buildIds: number[] = [];
      if (release.artifacts) {
        for (const artifact of release.artifacts) {
          try {
            let buildId: number | null = null;

            if (artifact.type === 'Build') {
              if (artifact.definitionReference?.build?.id) {
                buildId = Number(artifact.definitionReference.build.id);
              } else if (artifact.definitionReference?.artifactSourceVersionUrl) {
                const urlValue = artifact.definitionReference.artifactSourceVersionUrl;
                if (typeof urlValue === 'string') {
                  const urlMatch = urlValue.match(/\/builds\/(\d+)/);
                  if (urlMatch) {
                    buildId = Number(urlMatch[1]);
                  }
                }
              } else if (artifact.definitionReference?.version?.id) {
                buildId = Number(artifact.definitionReference.version.id);
              } else if (artifact.artifactSourceVersionUrl) {
                const urlValue = artifact.artifactSourceVersionUrl;
                if (typeof urlValue === 'string') {
                  const urlMatch = urlValue.match(/\/builds\/(\d+)/);
                  if (urlMatch) {
                    buildId = Number(urlMatch[1]);
                  }
                }
              } else if (artifact.buildId) {
                buildId = Number(artifact.buildId);
              }
            }

            if (buildId) {
              buildIds.push(buildId);
            }
          } catch (artifactError: any) {
            console.error(`[Release Details] Error processing artifact:`, artifactError.message);
          }
        }
      }

      // Fetch work items and commits from builds
      const buildWorkItems: any[] = [];
      const allCommits: any[] = [];
      for (const buildId of buildIds) {
        try {
          const buildWIs = await adoService.getBuildWorkItems(buildId, queryProjectName as string | undefined);
          buildWorkItems.push(...buildWIs);

          const commits = await adoService.getBuildCommits(buildId, queryProjectName as string | undefined);
          allCommits.push(...commits);
        } catch (err: any) {
          console.error(`[Release Details] Error fetching work items/commits for build ${buildId}:`, err.message);
        }
      }

      // Combine all work items and deduplicate by ID
      const allWorkItems = [...workItems, ...buildWorkItems];
      const uniqueWorkItemsMap = new Map<number, any>();
      for (const wi of allWorkItems) {
        const id = wi.id || wi.fields?.['System.Id'];
        if (id && !uniqueWorkItemsMap.has(id)) {
          uniqueWorkItemsMap.set(id, wi);
        }
      }
      const uniqueWorkItems = Array.from(uniqueWorkItemsMap.values());

      // Filter for User Stories
      const userStories = uniqueWorkItems.filter((wi: any) => {
        const workItemType = wi.fields?.['System.WorkItemType'] || wi.fields?.System?.WorkItemType;
        return workItemType === 'User Story';
      });// Link user stories to PRs, commits, builds, and artifacts
      const linkedUserStories = userStories.map((userStory: any) => {
        const storyId = userStory.id || userStory.fields?.['System.Id'];
        const linkedPRs: any[] = [];
        const linkedCommits: any[] = [];
        const linkedBuilds: any[] = [];
        const linkedArtifacts: any[] = [];

        // Find commits linked to this user story
        allCommits.forEach(commit => {
          if (commit.workItems && Array.isArray(commit.workItems)) {
            const commitWorkItemIds = commit.workItems.map((wi: any) => wi.id || wi.fields?.['System.Id']).filter(Boolean);
            if (commitWorkItemIds.includes(storyId)) {
              linkedCommits.push(commit);
            }
          }
        });

        // Find builds linked to this user story
        buildIds.forEach(buildId => {
          const buildWorkItemIds = buildWorkItems
            .map(wi => wi.id || wi.fields?.['System.Id'])
            .filter(Boolean);

          if (buildWorkItemIds.includes(storyId)) {
            linkedBuilds.push({
              id: buildId,
              name: `Build ${buildId}`,
              url: `https://dev.azure.com/${azureConfig.organization}/${azureConfig.project}/_build/results?buildId=${buildId}`
            });
          }
        });

        // Find artifacts linked to this user story (through builds)
        if (release.artifacts) {
          release.artifacts.forEach((artifact: any) => {
            if (artifact.type === 'Build') {
              let artifactBuildId: number | null = null;
              if (artifact.definitionReference?.build?.id) {
                artifactBuildId = Number(artifact.definitionReference.build.id);
              }

              if (artifactBuildId && linkedBuilds.some(b => b.id === artifactBuildId)) {
                linkedArtifacts.push({
                  ...artifact,
                  buildId: artifactBuildId
                });
              }
            }
          });
        }

        // Find PRs linked to this user story (from commit messages)
        linkedCommits.forEach(commit => {
          const prMatch = commit.comment?.match(/#(\d+)|PR[:\s]*#?(\d+)/i);
          if (prMatch) {
            const prNumber = prMatch[1] || prMatch[2];
            if (!linkedPRs.find(pr => pr.number === prNumber)) {
              linkedPRs.push({
                number: prNumber,
                url: `https://dev.azure.com/${azureConfig.organization}/${azureConfig.project}/_git/${release.artifacts?.[0]?.alias || 'repository'}/pullrequest/${prNumber}`,
                commitId: commit.commitId
              });
            }
          }
        });

        return {
          ...userStory,
          linkedPRs,
          linkedCommits,
          linkedBuilds,
          linkedArtifacts
        };
      });

      // Ensure work items have URLs
      const workItemsWithUrls = uniqueWorkItems.map((wi: any) => {
        if (!wi.url) {
          const wiId = wi.id || wi.fields?.['System.Id'];
          if (wiId) {
            wi.url = `https://dev.azure.com/${azureConfig.organization}/${azureConfig.project}/_workitems/edit/${wiId}`;
          }
        }
        return wi;
      });

      // Format commits with URLs
      const commitsWithUrls = allCommits.map(commit => {
        if (!commit.url && commit.commitId) {
          commit.url = `https://dev.azure.com/${azureConfig.organization}/${azureConfig.project}/_git/${release.artifacts?.[0]?.alias || 'repository'}/commit/${commit.commitId}`;
        }
        return commit;
      });

      const responseData = {
        release,
        workItems: workItemsWithUrls,
        userStories: linkedUserStories,
        commits: commitsWithUrls,
        builds: buildIds.map(id => ({
          id,
          url: `https://dev.azure.com/${azureConfig.organization}/${azureConfig.project}/_build/results?buildId=${id}`
        })),
        artifacts: release.artifacts || [],
        stats: {
          totalWorkItems: uniqueWorkItems.length,
          totalUserStories: userStories.length,
          totalCommits: allCommits.length,
          totalBuilds: buildIds.length,
          totalArtifacts: (release.artifacts || []).length
        }
      }; res.json(responseData);
    } catch (error: any) {
      console.error("Error fetching release details:", error);
      const errorMessage = error.message || "Failed to fetch release details";

      if (errorMessage.includes("<!DOCTYPE") || errorMessage.includes("<html")) {
        console.error("[Release Details] Azure DevOps returned HTML error page");
        res.setHeader('Content-Type', 'application/json');
        return res.status(500).json({
          error: "Azure DevOps API returned an error. Please check your PAT token and organization/project configuration.",
          details: "The API returned an HTML error page instead of JSON."
        });
      }

      res.setHeader('Content-Type', 'application/json');
      res.status(500).json({
        error: errorMessage,
        releaseId: req.params.releaseId,
        projectId: req.params.projectId
      });
    }
  });

  // Get release artifacts and environments (for trigger release modal)
  app.get("/api/sdlc/projects/:projectId/ado/release-artifacts", async (req: Request, res: Response) => {
    try {
      const { projectId } = req.params;
      const { organization: queryOrg, projectName: queryProjectName } = req.query;

      try {
        if (projectId !== "default") {
          await sdlcService.getProject(projectId).catch(() => undefined);
        }
      } catch {
        // Project might not exist in SDLC table if it's an ADO project ID
      }

      const azureConfig = await getAzureDevOpsConfig(queryProjectName as string | undefined, queryOrg as string | undefined);

      if (!azureConfig) {
        return res.status(400).json({
          error: "Azure DevOps not configured. Please configure in Settings > Central Settings."
        });
      }

      const adoService = new AzureDevOpsService(azureConfig);
      let releasesResponse: any = [];
      let definitionsResponse: any = [];

      try {
        const results = await Promise.allSettled([
          adoService.getReleases(undefined, 50, queryProjectName as string | undefined),
          adoService.getReleaseDefinitions(queryProjectName as string | undefined)
        ]);

        if (results[0].status === 'fulfilled') {
          releasesResponse = results[0].value;
        } else {
          console.error("[Release Artifacts] Error fetching releases:", results[0].reason);
          releasesResponse = [];
        }

        if (results[1].status === 'fulfilled') {
          definitionsResponse = results[1].value;
        } else {
          console.error("[Release Artifacts] Error fetching release definitions:", results[1].reason);
          definitionsResponse = [];
        }

        if (results[0].status === 'rejected' && results[1].status === 'rejected') {
          const errorMsg = results[0].reason?.message || results[1].reason?.message || "Failed to fetch both releases and definitions";
          throw new Error(errorMsg);
        }
      } catch (error: any) {
        console.error("[Release Artifacts] Unexpected error:", error);
        throw error;
      }

      const releases = Array.isArray(releasesResponse) ? releasesResponse : (releasesResponse?.value || []);
      const definitions = Array.isArray(definitionsResponse) ? definitionsResponse : (definitionsResponse?.value || []);

      const releaseArtifacts = releases.map((release: any) => {
        const definition = definitions.find((def: any) => def.id === release.releaseDefinition?.id);
        const environments = release.environments?.map((env: any) => ({
          id: env.id,
          name: env.name,
          status: env.status,
          deploymentStatus: env.deploymentStatus
        })) || [];

        const definitionEnvironments = definition?.environments?.map((env: any) => ({
          id: env.id,
          name: env.name
        })) || [];

        return {
          id: release.id,
          name: release.name,
          version: release.name,
          definitionId: release.releaseDefinition?.id,
          definitionName: release.releaseDefinition?.name || 'Unknown',
          createdOn: release.createdOn,
          environments: environments.length > 0 ? environments : definitionEnvironments,
          artifacts: release.artifacts || [],
          status: release.status
        };
      });

      res.json(releaseArtifacts);
    } catch (error: any) {
      console.error("Error fetching release artifacts:", error);
      const errorMessage = error.message || "Failed to fetch release artifacts";
      // Check if error message contains HTML
      if (errorMessage.includes("<!DOCTYPE") || errorMessage.includes("<html")) {
        return res.status(500).json({
          error: "Azure DevOps API returned an error. Please check your PAT token and organization/project configuration."
        });
      }
      res.status(500).json({ error: errorMessage });
    }
  });

