  // Get ADO backlog items for context awareness (uses Conversational UI settings)
  app.get("/api/ado-settings/backlog", async (req: Request, res: Response) => {
    try {
      // Get central settings (artifact_organizations)
      const artifactOrgs = await storage.getArtifactOrganizations();
      const firstOrg = artifactOrgs[0];
      if (!firstOrg) {
        return res.status(404).json({ error: "Azure DevOps settings not configured. Please configure in Settings > Central Settings." });
      }

      // Decrypt the PAT from central settings
      if (!firstOrg.patToken) {
        return res.status(400).json({ error: "Azure DevOps Personal Access Token not configured. Please add it in Settings > Central Settings." });
      }

      const decryptedPAT = decryptPAT(firstOrg.patToken);
      if (!decryptedPAT) {
        return res.status(400).json({ error: "Failed to decrypt Azure DevOps PAT. Please reconfigure in Settings > Central Settings." });
      }

      // Extract organization name from URL
      const organization = firstOrg.organizationUrl.replace(/https?:\/\/dev\.azure\.com\//, '').replace(/\/$/, '');

      // Create Azure DevOps service instance using central settings
      const { AzureDevOpsService } = await import("./azure-devops-service");
      const azureService = new AzureDevOpsService({
        organization,
        project: firstOrg.projectName,
        pat: decryptedPAT
      });// Fetch all work items
      const workItems = await azureService.getWorkItems();

      // Transform work items into a simplified format for AI context
      const backlogContext = workItems.map((item: any) => ({
        id: item.id,
        type: item.fields["System.WorkItemType"],
        title: item.fields["System.Title"],
        state: item.fields["System.State"],
        priority: item.fields["Microsoft.VSTS.Common.Priority"],
        description: item.fields["System.Description"]?.substring(0, 200) || "", // Limit description length
      }));

      // Group by type for easier reference
      const grouped = {
        epics: backlogContext.filter((item: any) => item.type === "Epic"),
        features: backlogContext.filter((item: any) => item.type === "Feature"),
        userStories: backlogContext.filter((item: any) => item.type === "User Story"),
        tasks: backlogContext.filter((item: any) => item.type === "Task"),
        bugs: backlogContext.filter((item: any) => item.type === "Bug"),
      }; res.json({
        success: true,
        backlog: backlogContext,
        grouped: grouped,
        totalCount: backlogContext.length,
        counts: {
          epics: grouped.epics.length,
          features: grouped.features.length,
          userStories: grouped.userStories.length,
          tasks: grouped.tasks.length,
          bugs: grouped.bugs.length,
        }
      });
    } catch (error) {
      console.error("[Conversational UI] Error fetching ADO backlog:", error);
      res.status(500).json({
        error: "Failed to fetch ADO backlog",
        details: error instanceof Error ? error.message : String(error)
      });
    }
  });

  // Artifact Organizations Routes

  // Get all artifact organizations
  app.get(
    "/api/artifact-organizations",
    requireActivity("ARTIFACT_ORGANIZATION_LIST"),
    async (req: Request, res: Response) => {
      try {
        if (!isEncryptionAvailable()) {
          return res.status(503).json({
            error: "Artifact organizations feature is not available. PAT_ENCRYPTION_KEY environment variable must be configured."
          });
        }

        const organizations = await storage.getArtifactOrganizations((req as any).user?.id);
        const organizationIds = organizations.map((org) => org.id);
        const rbacOrganizations = organizationIds.length > 0
          ? await db
              .select({
                id: schema.organizations.id,
                ownerUserId: schema.organizations.ownerUserId,
              })
              .from(schema.organizations)
              .where(inArray(schema.organizations.id, organizationIds))
          : [];
        const ownerUserIds = Array.from(
          new Set(
            rbacOrganizations
              .map((org) => org.ownerUserId)
              .filter((ownerUserId): ownerUserId is string => Boolean(ownerUserId)),
          ),
        );
        const ownerRows = ownerUserIds.length > 0
          ? await db
              .select({
                id: schema.users.id,
                email: schema.users.email,
                displayName: schema.users.displayName,
              })
              .from(schema.users)
              .where(inArray(schema.users.id, ownerUserIds))
          : [];
        const ownerInfoByUserId = new Map(
          ownerRows.map((owner) => [
            owner.id,
            {
              id: owner.id,
              email: owner.email,
              displayName: owner.displayName,
            },
          ]),
        );
        const ownerUserIdByOrgId = new Map(
          rbacOrganizations.map((org) => [org.id, org.ownerUserId || null]),
        );

        // Don't send PAT tokens to the client, just send whether they're configured
        let sanitizedOrgs = organizations.map(org => ({
          id: org.id,
          projectName: org.projectName,
          organizationUrl: org.organizationUrl,
          patConfigured: !!org.patToken,
          ownerUserId: ownerUserIdByOrgId.get(org.id) || null,
          ownerInfo: ownerUserIdByOrgId.get(org.id)
            ? ownerInfoByUserId.get(ownerUserIdByOrgId.get(org.id) as string) || null
            : null,
          createdAt: org.createdAt,
          updatedAt: org.updatedAt,
        }));

        const search = req.query.search as string;
        if (search && search.trim() !== "") {
          const query = search.toLowerCase();
          sanitizedOrgs = sanitizedOrgs.filter(org =>
            org.projectName?.toLowerCase().includes(query) ||
            org.organizationUrl?.toLowerCase().includes(query)
          );
        }

        const totalCount = sanitizedOrgs.length;
        const page = parseInt(req.query.page as string);
        const pageSize = parseInt(req.query.pageSize as string);

        if (!isNaN(page) && !isNaN(pageSize) && page > 0 && pageSize > 0) {
          const startIndex = (page - 1) * pageSize;
          const endIndex = startIndex + pageSize;
          sanitizedOrgs = sanitizedOrgs.slice(startIndex, endIndex);
        }

        res.json({ organizations: sanitizedOrgs, totalCount });
      } catch (error) {
        console.error("Error fetching artifact organizations:", error);
        res.status(500).json({
          error: "Failed to fetch artifact organizations",
          details: error instanceof Error ? error.message : String(error),
        });
      }
    });

  // Create a new artifact organization
  app.post(
    "/api/artifact-organizations",
    requireActivity("ARTIFACT_ORGANIZATION_CREATE"),
    async (req: Request, res: Response) => {
      try {
        if (!isEncryptionAvailable()) {
          return res.status(503).json({
            error: "Artifact organizations feature is not available. PAT_ENCRYPTION_KEY environment variable must be configured."
          });
        }
        // Try to get global ADO settings (projectName may be configured there)
        const settings = await storage.getAdoSettings();

        // Validate request body with Zod. projectName is optional.
        const createOrgSchema = z.object({
          projectName: z.string().min(1).optional(),
          organizationUrl: z.string().url("Must be a valid URL"),
          patToken: z.string().optional(),
          selectedProject: z.object({
            id: z.string().min(1),
            name: z.string().min(1),
            description: z.string().optional().nullable(),
          }),
        });

        const parsed = createOrgSchema.safeParse(req.body);
        if (!parsed.success) {
          return res.status(400).json({ error: 'Validation error', details: parsed.error.errors });
        }

        const validatedData = parsed.data;
        const projectNameToUse =
          validatedData.projectName?.trim() ||
          validatedData.selectedProject.name.trim() ||
          settings?.projectName?.trim() ||
          deriveDefaultProjectName(validatedData.organizationUrl, settings?.organizationUrl);

        const authUserId = (req as any).user?.id;
        if (!authUserId) {
          return res.status(401).json({ error: "Not signed in" });
        }

        const [userRecord] = await db
          .select({ tenantId: schema.users.tenantId })
          .from(schema.users)
          .where(eq(schema.users.id, authUserId))
          .limit(1);
        if (!userRecord?.tenantId) {
          return res.status(400).json({
            error: "Missing tenant context",
            message: "Current user does not have a tenant_id, so the selected project cannot be registered.",
          });
        }

        const newOrg = await storage.createArtifactOrganization({
          projectName: projectNameToUse,
          organizationUrl: validatedData.organizationUrl,
          patToken: validatedData.patToken || null,
        });

        try {
          const rbacOrg = await storage.createOrganization({
            id: newOrg.id,
            name: newOrg.projectName || newOrg.organizationUrl,
            tenantId: userRecord.tenantId,
            ownerUserId: authUserId,
          });
          await storage.addOrganizationMember({
            organizationId: rbacOrg.id,
            userId: authUserId,
            tenantId: userRecord.tenantId,
            role: "owner",
          });
        } catch (rbacErr) {
          console.error("Failed to sync RBAC organization:", rbacErr);
        }

        const orgName = extractAdoOrganizationName(newOrg.organizationUrl) || newOrg.organizationUrl;
        const registeredProject = await sdlcService.registerProviderProject({
          integrationType: "ado",
          projectId: validatedData.selectedProject.id,
          name: validatedData.selectedProject.name,
          description: validatedData.selectedProject.description || null,
          organization: orgName,
          organizationUrl: newOrg.organizationUrl,
          ownerUserId: authUserId,
        });
        await storage.addProjectMember({
          projectId: registeredProject.id,
          userId: authUserId,
          tenantId: userRecord.tenantId,
          role: registeredProject.ownerUserId === authUserId ? "owner" : "member",
        });

        // Don't send PAT token back to client
        const sanitizedOrg = {
          id: newOrg.id,
          projectName: newOrg.projectName,
          organizationUrl: newOrg.organizationUrl,
          patConfigured: !!newOrg.patToken,
          createdAt: newOrg.createdAt,
          updatedAt: newOrg.updatedAt,
        };

        res.json({ organization: sanitizedOrg });
      } catch (error) {
        console.error("Error creating artifact organization:", error);
        res.status(500).json({
          error: "Failed to create artifact organization",
          details: error instanceof Error ? error.message : String(error)
        });
      }
    });

