  // POST /api/ado/push_figma_to_epic - add Figma link to Epic's description
  app.post("/api/ado/push_figma_to_epic", async (req, res) => {
    try {
      const { AzureDevOpsService } = await import("./azure-devops-service"); const { epicId, figmaLink, projectName, organization, artifactOrgId } = req.body;

      if (!epicId || !figmaLink) {
        return res.status(400).json({ error: "Both epicId and figmaLink are required" });
      }// Get PAT from hub artifacts configuration
      if (!isEncryptionAvailable()) {
        return res.status(503).json({
          error: "Artifact organizations feature is not available. PAT_ENCRYPTION_KEY environment variable must be configured."
        });
      }

      const artifactOrgs = await storage.getArtifactOrganizations();
      if (artifactOrgs.length === 0) {
        return res.status(404).json({ error: "No artifact organizations configured" });
      }

      // Find the organization to use
      let targetOrg = null;
      if (artifactOrgId) {
        targetOrg = artifactOrgs.find(org => org.id === artifactOrgId);
      } else if (organization) {// Match by full organizationUrl
        targetOrg = artifactOrgs.find(org => org.organizationUrl === organization);

        // If not found, try extracting org name and matching
        if (!targetOrg) {
          const orgName = organization.match(/https?:\/\/dev\.azure\.com\/([^\/\?]+)/)?.[1];
          if (orgName) {
            targetOrg = artifactOrgs.find(org => {
              const existingOrgName = org.organizationUrl?.match(/https?:\/\/dev\.azure\.com\/([^\/\?]+)/)?.[1];
              return existingOrgName === orgName;
            });
          }
        }
      }

      // Fallback to first org with PAT
      if (!targetOrg || !targetOrg.patToken) {
        targetOrg = artifactOrgs.find(org => org.patToken);
      }

      if (!targetOrg || !targetOrg.patToken) {
        return res.status(400).json({ error: "No artifact organization found with PAT configured" });
      }// Decrypt PAT token
      const pat = safeDecryptPAT(targetOrg.patToken);
      if (!pat) {
        return res.status(500).json({ error: "Failed to decrypt PAT token" });
      }

      // Prefer resolving ADO config via projectName (strict match) so UI can pass the selected project
      let azureConfig: AzureConfig | null = null;
      if (projectName && typeof projectName === 'string' && projectName.trim()) {
        azureConfig = await getAzureDevOpsConfig(projectName.trim());
      }

      // If not resolved via getAzureDevOpsConfig, fall back to selected artifact org (with decrypted PAT)
      if (!azureConfig && targetOrg) {
        azureConfig = {
          organization: targetOrg.organizationUrl || '',
          project: targetOrg.projectName || projectName || '',
          pat
        } as AzureConfig;
      }

      if (!azureConfig) {
        console.error('[ADO Push Figma] Could not resolve Azure DevOps configuration for pushing Figma link');
        return res.status(400).json({ error: 'Could not resolve Azure DevOps project. Please provide projectName or configure an artifact organization.' });
      }

      // Use AzureDevOpsService to fetch and update work item (avoids hardcoded dev.azure.com URLs)
      const adoService = new AzureDevOpsService(azureConfig);

      // Ensure epicId is a number
      const epicNumericId = parseInt(String(epicId), 10);
      if (isNaN(epicNumericId)) {
        return res.status(400).json({ error: 'Invalid epicId' });
      }

      // Fetch existing work item to get current description
      let currentDescription = '';
      try {
        const currentWorkItem = await adoService.getWorkItemById(epicNumericId, azureConfig.project);
        currentDescription = currentWorkItem.fields?.['System.Description'] || '';
      } catch (err) {
        console.warn('[ADO Push Figma] Failed to fetch existing work item via AzureDevOpsService:', err);
        // proceed — updateWorkItem will return a helpful error if needed
      }

      const figmaLinkHtml = `<p><b>Figma Design:</b> <a href='${figmaLink}' target='_blank'>${figmaLink}</a></p>`;
      const newDescription = currentDescription ? `${currentDescription}\n${figmaLinkHtml}` : figmaLinkHtml;

      // Update ONLY the description field - don't touch state or any other fields
      const updated = await adoService.updateWorkItem(epicNumericId, { 'System.Description': newDescription });
      res.json({ status: 'success', message: `Figma link added to Epic ${epicId}`, figmaLink, ado_response: updated });

    } catch (error) {
      console.error("[ADO Push Figma] Fatal error:", error);
      res.status(500).json({
        error: "Failed to push Figma link",
        details: error instanceof Error ? error.message : String(error)
      });
    }
  });

  // Hub API Routes - Artifacts

  // Get all projects from Azure DevOps organizations (using artifact organizations)
  app.get("/api/hub/artifacts/projects", async (req: Request, res: Response) => {
    try {
      const { isAwsHosting } = await import("./platform/hosting");
      const userId = (req as any).user?.id;

      const search = req.query.search as string;
      const pageQuery = req.query.page as string;
      const pageSizeQuery = req.query.pageSize as string;

      // Honour the org switcher: when a specific org is selected, only fetch
      // projects from the matching backing source (ADO orgs OR Jira
      // connections). When nothing / "__all__" is selected, behave as before.
      const selectedOrg = await getSelectedGlobalOrganizationFromRequest(req);
      const includeAdo = !selectedOrg || selectedOrg.sourceType === "ado";
      const includeJira = !selectedOrg || selectedOrg.sourceType === "jira";

      const orgParam = selectedOrg?.id || "all";
      const cacheKey = `hub-projects-${userId || 'default'}-${orgParam}`;
      const cached = adoProjectsCache.get(cacheKey);

      let uniqueProjects: any[] = [];
      let errors: any[] = [];

      if (cached && cached.expires > Date.now()) {
        console.log(`[Hub Artifacts API] Returning cached projects for ${cacheKey}`);
        uniqueProjects = cached.data;
      } else {
        const uniqueProjectsMap = new Map<string, any>();

      if (!isAwsHosting() && includeAdo) {
        if (!isEncryptionAvailable()) {
          return res.status(503).json({
            error: "Artifact organizations feature is not available. PAT_ENCRYPTION_KEY environment variable must be configured."
          });
        }

        const allArtifactOrgs = await storage.getArtifactOrganizations(req.user?.id);
        const artifactOrgs = selectedOrg
          ? allArtifactOrgs.filter((org) => org.id === selectedOrg.id)
          : allArtifactOrgs;
        const orgsWithPAT = artifactOrgs.filter(org => org.patToken);

        const allProjects: any[] = [];
        const errors: any[] = [];
        let credentialErrorCode: string | null = null;

        for (const org of orgsWithPAT) {
          try {
            const pat = safeDecryptPAT(org.patToken);
            if (!pat) {
              const errorMsg = `Skipping organization ${org.organizationUrl} - failed to decrypt PAT`;
              console.warn(`[Hub Artifacts] ${errorMsg}`);
              errors.push(errorMsg);
              continue;
            }

            let organization = '';
            if (org.organizationUrl && org.organizationUrl.includes('dev.azure.com')) {
              const orgMatch = org.organizationUrl.match(/https?:\/\/dev\.azure\.com\/([^\/\?]+)/);
              organization = orgMatch ? orgMatch[1].trim() : '';
            } else if (org.organizationUrl && org.organizationUrl.includes('visualstudio.com')) {
              const orgMatch = org.organizationUrl.match(/https?:\/\/([^\.]+)\.visualstudio\.com/);
              organization = orgMatch ? orgMatch[1].trim() : '';
            }

            if (!organization) {
              const errorMsg = `Invalid organization URL format: ${org.organizationUrl}. Expected format: https://dev.azure.com/{org} or https://{org}.visualstudio.com`;
              console.warn(`[Hub Artifacts] ${errorMsg}`);
              errors.push(errorMsg);
              continue;
            }
            const adoService = new AzureDevOpsService({
              organization,
              project: org.projectName,
              pat
            });
            const projects = await adoService.getProjects();
            const transformedProjects = projects.map((project: any) => ({
              id: project.id,
              name: project.name,
              description: project.description || '',
              organization: organization,
              organizationUrl: org.organizationUrl,
              artifactOrgId: org.id
            }));

            allProjects.push(...transformedProjects);
          } catch (error) {
            const errorMsg = `Error fetching projects from organization ${org.organizationUrl}: ${error instanceof Error ? error.message : String(error)}`;
            console.error(`[Hub Artifacts] ${errorMsg}`);
            errors.push(errorMsg);
          }
        }

        for (const project of allProjects) {
          const key = String(project.id);
          if (!uniqueProjectsMap.has(key)) {
            uniqueProjectsMap.set(key, { ...project, integrationType: 'ado' });
          }
        }
      }

      // Merge Jira-integrated projects from sdlcProjects table, scoped to
      // the selected Jira connection when applicable.
      if (includeJira) {
        try {
          const visibleOrgs = await storage.getVisibleOrganizations(req.user?.id);
          const visibleOrgIds = visibleOrgs.map((o) => o.id);

          const baseQuery = db
            .select({
              id: sdlcProjects.id,
              name: sdlcProjects.name,
              description: sdlcProjects.description,
              jiraProjectKey: sdlcProjects.jiraProjectKey,
              jiraInstanceUrl: sdlcProjects.jiraInstanceUrl,
              jiraConnectionId: sdlcProjects.jiraConnectionId,
              connectionInstanceUrl: jiraConnections.instanceUrl,
              connectionName: jiraConnections.name,
            })
            .from(sdlcProjects)
            .leftJoin(jiraConnections, sql`${sdlcProjects.jiraConnectionId} = ${jiraConnections.id} COLLATE utf8mb4_unicode_ci`)
            .where(
              and(
                eq(sdlcProjects.integrationType, 'jira'),
                visibleOrgIds.length > 0
                  ? inArray(sdlcProjects.jiraConnectionId, visibleOrgIds)
                  : sql`1 = 0`
              )
            );

          const allJiraProjects = await baseQuery;

          let jiraProjects = allJiraProjects;
          if (selectedOrg && selectedOrg.sourceType === 'jira') {
            const [conn] = await db
              .select()
              .from(jiraConnections)
              .where(eq(jiraConnections.id, selectedOrg.id))
              .limit(1);
            const targetUrls = new Set<string>();
            if (conn?.instanceUrl) {
              const stripped = conn.instanceUrl.replace(/\/+$/, '');
              targetUrls.add(conn.instanceUrl);
              targetUrls.add(stripped);
              targetUrls.add(stripped + '/');
            }
            jiraProjects = allJiraProjects.filter((p) =>
              p.jiraConnectionId === selectedOrg.id ||
              (p.jiraInstanceUrl && targetUrls.has(p.jiraInstanceUrl)),
            );
          }

          for (const project of jiraProjects) {
            if (!uniqueProjectsMap.has(project.id)) {
              // Use instance URL as organization name for better filtering by specific Jira instances
              const organizationName = project.jiraInstanceUrl || project.connectionInstanceUrl || project.connectionName || 'Jira';

              uniqueProjectsMap.set(project.id, {
                id: project.id,
                name: project.name,
                description: project.description || '',
                organization: organizationName,
                organizationUrl: project.jiraInstanceUrl || project.connectionInstanceUrl || '',
                integrationType: 'jira',
                projectKey: project.jiraProjectKey,
                jiraConnectionId: project.jiraConnectionId,
              });
            }
          }
        } catch (jiraError) {
          console.error("[Hub Artifacts] Error fetching Jira projects:", jiraError);
        }
      }

      uniqueProjects = Array.from(uniqueProjectsMap.values());
      if (userId) {
        const patReadiness = await getUserPatReadiness(userId);
        uniqueProjects = uniqueProjects.map((project) => {
          if (project.integrationType !== "jira") return project;
          return {
            ...project,
            ...getProjectPatStatus(
              {
                jiraInstanceUrl: project.organizationUrl,
                goldenRepoReference: null,
              },
              patReadiness,
            ),
          };
        });
      }
      adoProjectsCache.set(cacheKey, { data: uniqueProjects, expires: Date.now() + 5 * 60 * 1000 });
      } // End of else block for cache miss

      let filteredProjects = uniqueProjects;

      if (search && search.trim() !== "") {
        const query = search.toLowerCase();
        filteredProjects = filteredProjects.filter((project) => {
          const projectName = project.name?.toLowerCase() || "";
          const projectOrganization = project.organization?.toLowerCase() || "";
          const projectKey = project.projectKey?.toLowerCase() || "";
          const projectId = String(project.id).toLowerCase();
          return projectName.includes(query) ||
                 projectOrganization.includes(query) ||
                 projectKey.includes(query) ||
                 projectId.includes(query);
        });
      }

      // Apply server-side pagination if requested
      if (pageQuery) {
        const page = parseInt(pageQuery, 10) || 1;
        const pageSize = parseInt(pageSizeQuery, 10) || 20;
        const startIndex = (page - 1) * pageSize;
        const endIndex = startIndex + pageSize;
        const paginatedProjects = filteredProjects.slice(startIndex, endIndex);

        res.json({
          projects: paginatedProjects,
          totalCount: filteredProjects.length,
          page,
          pageSize,
          warnings: errors,
        });
      } else {
        res.json({
          projects: filteredProjects,
          totalCount: filteredProjects.length,
          warnings: errors,
        });
      }
    } catch (error) {
      console.error("Error fetching projects:", error);
      const errorMessage = error instanceof Error ? error.message : String(error);
      res.status(500).json({
        error: "Failed to fetch projects from Azure DevOps",
        details: errorMessage
      });
    }
  });

  // Get work items for a project (Artifacts)
  app.get("/api/hub/artifacts/:projectName/work-items", async (req: Request, res: Response) => {
    try {
      const { projectName } = req.params;
      const {
        organizationUrl,
        artifactOrgId,
        projectId,
        organization: orgFromQuery,
      } = req.query;

      // Handle Jira projects
      if (orgFromQuery === 'Jira' || (projectId && !artifactOrgId)) {
        try {
          const actualProjectId = projectId as string;
          const jiraConfig = await getJiraConfig(actualProjectId);

          if (!jiraConfig) {
            // Fallback: search by projectName if projectId didn't work
            const project = await (db as any).query.sdlcProjects.findFirst({
              where: eq(sdlcProjects.name, projectName as any)
            });
            if (project && project.integrationType === 'jira') {
              const config = await getJiraConfig(project.id);
              if (config) {
                const jiraService = await getJiraServiceForWrite(req, config.projectKey, config.instanceUrl);
                const backlog = (await jiraService.getBacklogContext()) as any;
                const allItems = [...backlog.epics, ...backlog.features, ...backlog.userStories];

                // Track children to build hierarchy. Tag every item with
                // `source: "Jira"` so the client renders the correct origin
                // badge instead of falling back to the default ADO label.
                const itemMap = new Map<string, any>();
                allItems.forEach(item => {
                  itemMap.set(item.id, { ...item, source: "Jira", linkedItems: [] });
                });

                const rootItems: any[] = [];
                const itemsAddedAsChildren = new Set<string>();

                itemMap.forEach((item, id) => {
                  if (item.parentId && itemMap.has(item.parentId)) {
                    itemMap.get(item.parentId).linkedItems.push(item);
                    itemsAddedAsChildren.add(id);
                  } else {
                    rootItems.push(item);
                  }
                });

                return res.json(rootItems.filter(item => !itemsAddedAsChildren.has(item.id)));
              }
            }
            return res.status(400).json({ error: "Jira project not configured or not found" });
          }

          const jiraService = await getJiraServiceForWrite(req, jiraConfig.projectKey, jiraConfig.instanceUrl);
          const backlog = (await jiraService.getBacklogContext()) as any;
          const allItems = [...backlog.epics, ...backlog.features, ...backlog.userStories];

          // Track children to build hierarchy. Tag every item with
          // `source: "Jira"` so the client renders the correct origin badge.
          const itemMap = new Map<string, any>();
          allItems.forEach(item => {
            itemMap.set(item.id, { ...item, source: "Jira", linkedItems: [] });
          });

          const rootItems: any[] = [];
          const itemsAddedAsChildren = new Set<string>();

          itemMap.forEach((item, id) => {
            if (item.parentId && itemMap.has(item.parentId)) {
              itemMap.get(item.parentId).linkedItems.push(item);
              itemsAddedAsChildren.add(id);
            } else {
              rootItems.push(item);
            }
          });

          return res.json(rootItems.filter(item => !itemsAddedAsChildren.has(item.id)));
        } catch (error) {
          console.error("[Hub Artifacts] Error fetching Jira artifacts:", error);
          if (respondWithJiraCredentialError(res, error)) return;
          return res.status(500).json({ error: "Failed to fetch Jira artifacts", details: error instanceof Error ? error.message : String(error) });
        }
      }

      if (!isEncryptionAvailable()) {
        return res.status(503).json({
          error: "Artifact organizations feature is not available. PAT_ENCRYPTION_KEY environment variable must be configured."
        });
      }

      const artifactOrgs = await storage.getArtifactOrganizations();

      if (artifactOrgs.length === 0) {
        return res.status(404).json({ error: "No artifact organizations configured. Please add organizations in Settings > Hub Artifacts." });
      }

      // Find the organization to use
      let targetOrg = null;

      if (artifactOrgId) {
        targetOrg = artifactOrgs.find(org => org.id === artifactOrgId);
      } else if (organizationUrl) {
        targetOrg = artifactOrgs.find(org => org.organizationUrl === organizationUrl);
      } else {
        // Try to find organization by project name, or use first one with PAT
        targetOrg = artifactOrgs.find(org => org.projectName === projectName && org.patToken)
          || artifactOrgs.find(org => org.patToken);
      }

      if (!targetOrg || !targetOrg.patToken) {
        return res.status(400).json({ error: "No artifact organization found with PAT configured for this project" });
      }

      // Decrypt PAT token
      const pat = safeDecryptPAT(targetOrg.patToken);
      if (!pat) {
        return res.status(500).json({ error: "Failed to decrypt PAT token" });
      }

      // Extract organization name from URL
      // Support both https://dev.azure.com/{org} and https://{org}.visualstudio.com formats
      let organization = '';
      if (targetOrg.organizationUrl.includes('dev.azure.com')) {
        const orgMatch = targetOrg.organizationUrl.match(/https?:\/\/dev\.azure\.com\/([^\/\?]+)/);
        organization = orgMatch ? orgMatch[1].trim() : '';
      } else if (targetOrg.organizationUrl.includes('visualstudio.com')) {
        const orgMatch = targetOrg.organizationUrl.match(/https?:\/\/([^\.]+)\.visualstudio\.com/);
        organization = orgMatch ? orgMatch[1].trim() : '';
      }

      if (!organization) {
        return res.status(400).json({
          error: `Invalid organization URL format: ${targetOrg.organizationUrl}. Expected format: https://dev.azure.com/{org} or https://{org}.visualstudio.com`
        });
      }

      // Use the requested projectName so work items are created in the
      // currently selected ADO project (not the default project on the org).
      const adoService = new AzureDevOpsService({
        organization,
        project: projectName,
        pat,
      });

      // Get limit from query params (default to no limit to fetch all items)
      // If limit is explicitly provided, use it; otherwise fetch all items
      const limit = req.query.limit ? parseInt(req.query.limit as string, 10) : undefined;
      const rawWorkItems = await adoService.getWorkItems(projectName, limit);

      // Build hierarchy from work items
      const workItemMap = new Map();
      const rootWorkItems: any[] = [];

      // First pass: Create all work items without relationships
      rawWorkItems.forEach((item: any) => {
        const workItem = {
          id: item.id.toString(),
          title: item.fields['System.Title'] || '',
          type: item.fields['System.WorkItemType'] || '',
          status: item.fields['System.State'] || '',
          state: item.fields['System.State'] || '',
          priority: item.fields['Microsoft.VSTS.Common.Priority'] ?
            (item.fields['Microsoft.VSTS.Common.Priority'] === 1 ? 'High' :
              item.fields['Microsoft.VSTS.Common.Priority'] === 2 ? 'Medium' : 'Low') :
            'Medium',
          description: item.fields['System.Description'] || '',
          acceptanceCriteria: item.fields['Microsoft.VSTS.Common.AcceptanceCriteria'] || '',
          storyPoints: item.fields['Microsoft.VSTS.Scheduling.StoryPoints'] || null,
          linkedItems: [],
          // Expose created date so UI can filter by "newly created"
          createdDate: item.fields['System.CreatedDate'] || null,
        };

        // Find parent relationship
        const parentRelation = item.relations?.find((rel: any) =>
          rel.rel === 'System.LinkTypes.Hierarchy-Reverse'
        );

        let parentId: number | undefined;
        if (parentRelation) {
          parentId = parseInt(parentRelation.url.split('/').pop() || '0');
          // Only set parentId if it's a valid number
          if (isNaN(parentId) || parentId === 0) {
            parentId = undefined;
          }
        }

        workItemMap.set(item.id, { raw: item, transformed: workItem, parentId });
      });

      // Second pass: Build hierarchy by linking children to parents
      // Track which items have been added as children to avoid duplicates
      const itemsAddedAsChildren = new Set<number>();

      workItemMap.forEach(({ transformed, parentId }, itemId) => {
        if (parentId !== undefined) {
          const parent = workItemMap.get(parentId);
          if (parent) {
            parent.transformed.linkedItems.push(transformed);
            itemsAddedAsChildren.add(itemId); // Track items added as children
          } else {
            // Parent not found in current batch, treat as root
            rootWorkItems.push(transformed);
          }
        } else {
          // No parent, it's a root item
          rootWorkItems.push(transformed);
        }
      });

      // Remove any items from rootWorkItems that were added as children
      // This ensures items only appear in their correct hierarchical position
      const filteredRootItems = rootWorkItems.filter(item => {
        const itemId = parseInt(item.id);
        return !itemsAddedAsChildren.has(itemId);
      });

      // Clear and repopulate rootWorkItems with filtered items
      rootWorkItems.length = 0;
      rootWorkItems.push(...filteredRootItems);

      // Sort linkedItems by ID to maintain consistent order
      const sortLinkedItems = (item: any) => {
        if (item.linkedItems && item.linkedItems.length > 0) {
          item.linkedItems.sort((a: any, b: any) => parseInt(a.id) - parseInt(b.id));
          item.linkedItems.forEach(sortLinkedItems);
        }
      };

      rootWorkItems.forEach(sortLinkedItems);

      res.json(rootWorkItems);
    } catch (error) {
      console.error("Error fetching work items:", error);
      res.status(500).json({ error: "Failed to fetch work items from Azure DevOps" });
    }
  });

