  // Generate prompt using AI
  app.post("/api/hub/prompts/generate", async (req: Request, res: Response) => {
    try {
      const { description, category, context } = req.body;

      if (!description) {
        return res.status(400).json({ error: "Description is required" });
      }

      // Check for AI configuration - use Azure OpenAI if configured, otherwise fall back to AI integrations or standard OpenAI
      const useAzure = process.env.AZURE_OPENAI_API_KEY && process.env.AZURE_OPENAI_ENDPOINT;
      const hasAIIntegrations = process.env.AI_INTEGRATIONS_OPENAI_API_KEY && process.env.AI_INTEGRATIONS_OPENAI_BASE_URL;
      const hasOpenAI = process.env.OPENAI_API_KEY;

      if (!useAzure && !hasAIIntegrations && !hasOpenAI) {
        return res.status(503).json({
          error: "AI integration not configured. Please set up Azure OpenAI (AZURE_OPENAI_API_KEY, AZURE_OPENAI_ENDPOINT, AZURE_OPENAI_DEPLOYMENT), AI Integrations (AI_INTEGRATIONS_OPENAI_API_KEY, AI_INTEGRATIONS_OPENAI_BASE_URL), or OPENAI_API_KEY."
        });
      }

      // Use centralized AI client (supports Anthropic, Azure OpenAI, or OpenAI)
      const { ai: openai } = await import("./ai-client");

      const systemPrompt = `You are an expert Prompt Engineer. Your task is to generate a practical, reusable prompt TEMPLATE that users can fill in for their specific tasks.

IMPORTANT - Match this exact style used by our prompt library:
- Use clean Markdown with ## section headers
- Use ☐ checkboxes for checklists (copy this character exactly: ☐)
- Use [PLACEHOLDER_NAME] in square brackets for all user-fillable fields
- Use inline code fences (\`\`\`) for code/log/JSON examples
- Keep language concise and practical — no verbose preamble
- Structure: Brief intro → Sections with headers → Checkboxes where applicable → Technical details at end
- The content should be a TEMPLATE the user fills in, not instructions TO an AI

EXAMPLE STYLE (User Story Generator):
"As a [USER_ROLE], I want to [ACTION] so that [BENEFIT].

## Acceptance Criteria
1. Given [CONTEXT] When [ACTION] Then [OUTCOME]

## Definition of Done
☐ Code implemented and reviewed
☐ Tests written and passing
☐ Documentation updated"

Return ONLY a JSON object with: "title", "description", "content", and "tags" (array of strings).
The "content" field must be the raw template text.`;

      const userPrompt = `Generate a prompt template for this use case:
- Goal: ${description}
- Category: ${category || "General"}
${context ? `- Additional Requirements: ${context}` : ""}

The template should be practical, directly usable, and follow the style guide above.`;

      // Use deployment name for Azure, model name for others
      // Ensure we never pass `undefined` to the OpenAI client by falling back to a safe default.
      const modelName = useAzure ? (process.env.AZURE_OPENAI_DEPLOYMENT ?? "gpt-4o-mini") : "gpt-4o-mini";

      const completion = await openai.chat.completions.create({
        model: modelName,
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userPrompt }
        ],
        response_format: { type: "json_object" },
        temperature: 0.7,
      });

      const responseContent = completion.choices[0]?.message?.content;
      if (!responseContent) {
        throw new Error("No response content from AI model");
      }

      let generatedPrompt;
      try {
        // Robust JSON parsing: strip markdown code blocks and whitespace
        let cleanContent = responseContent.trim();

        // Remove markdown code block markers if present
        cleanContent = cleanContent.replace(/^```(?:json)?\s*/i, "").replace(/\s*```$/i, "");

        // Find the first { and last } to isolate the JSON object
        const firstBrace = cleanContent.indexOf("{");
        const lastBrace = cleanContent.lastIndexOf("}");
        if (firstBrace !== -1 && lastBrace !== -1) {
          cleanContent = cleanContent.substring(firstBrace, lastBrace + 1);
        }

        try {
          // Attempt standard parse first
          generatedPrompt = JSON.parse(cleanContent);
        } catch (e) {
          // If standard parse fails, try jsonrepair
          console.warn("Standard JSON parse failed, attempting jsonrepair...");
          const repaired = jsonrepair(cleanContent);
          generatedPrompt = JSON.parse(repaired);
        }
      } catch (parseError) {
        console.error("Error parsing AI response:", parseError);
        console.error("Original response content:", responseContent);
        throw new Error("Failed to parse AI response. The model may not have returned valid JSON.");
      }

      // Validate required fields
      if (!generatedPrompt.title || !generatedPrompt.content) {
        console.warn("AI response missing required fields:", generatedPrompt);
        // Provide defaults if missing
        generatedPrompt = {
          title: generatedPrompt.title || "Generated Prompt",
          description: generatedPrompt.description || "AI-generated prompt template",
          content: generatedPrompt.content || description,
          tags: generatedPrompt.tags || []
        };
      }

      // Save the generated prompt to the database
      const savedPrompt = await storage.createPrompt({
        title: generatedPrompt.title,
        description: generatedPrompt.description,
        content: generatedPrompt.content,
        category: category || "General",
        tags: generatedPrompt.tags || []
      });

      res.json(savedPrompt);
    } catch (error) {
      console.error("Error generating prompt:", error);
      const errorMessage = error instanceof Error ? error.message : "Failed to generate prompt";
      res.status(500).json({
        error: errorMessage
      });
    }
  });

  // Dashboard API Routes
  app.get("/api/dashboard/metrics", async (req: Request, res: Response) => {
    const startedAt = Date.now();
    try {
      const projectId = req.query.projectId as string | undefined;
      const selectedOrganization = await getSelectedGlobalOrganizationFromRequest(req);
      const userId = (req as any).user?.id;
      const cacheKey = `${projectId ?? "__all__"}:${selectedOrganization?.id ?? "__all__"}:${userId ?? "nouser"}`;
      const cachedMetrics = getCachedValue(dashboardMetricsCache, cacheKey);
      if (cachedMetrics) {
        return res.json(cachedMetrics);
      }

      const metrics = await storage.getDashboardMetrics(projectId, selectedOrganization?.name, selectedOrganization, userId);

      // Show the real total count of organizations the user has access to
      let visibleOrgIds = new Set<string>();
      if (userId) {
        const visibleOrgs = await storage.getVisibleOrganizations(userId);
        visibleOrgs.forEach(org => visibleOrgIds.add(org.id));

        const { projectMembers, sdlcProjects } = await import("@shared/schema");
        const { matchesOrganizationValue } = await import("./utils/organization-matcher");

        const memberRows = await db.select({ projectId: projectMembers.projectId }).from(projectMembers).where(eq(projectMembers.userId, userId));
        const memberProjectIds = memberRows.map(r => r.projectId);

        const [allAdoOrganizations, allJiraConnections] = await Promise.all([
          db.select().from(artifactOrganizations),
          db.select().from(jiraConnections)
        ]);

        if (memberProjectIds.length > 0) {
          const explicitDevXProjects = await db.select({ organizationId: projects.organizationId }).from(projects).where(inArray(projects.id, memberProjectIds));
          explicitDevXProjects.forEach(p => { if (p.organizationId) visibleOrgIds.add(p.organizationId); });

          const explicitSdlcProjects = await db.select().from(sdlcProjects).where(inArray(sdlcProjects.id, memberProjectIds));
          explicitSdlcProjects.forEach(sp => {
            if (sp.jiraConnectionId) visibleOrgIds.add(sp.jiraConnectionId);
            if (sp.integrationType !== 'jira' && sp.organization) {
              const match = allAdoOrganizations.find(a => matchesOrganizationValue(sp.organization, a.organizationUrl));
              if (match) visibleOrgIds.add(match.id);
            }
          });
        }

        const adoOrgsCount = allAdoOrganizations.filter(org => visibleOrgIds.has(org.id)).length;
        const jiraOrgsCount = allJiraConnections.filter(org => visibleOrgIds.has(org.id)).length;
        metrics.organizations = adoOrgsCount + jiraOrgsCount;
      } else {
        const [totalAdoOrgs, totalJiraConns] = await Promise.all([
          db.select({ count: sql<number>`count(*)` }).from(artifactOrganizations),
          db.select({ count: sql<number>`count(*)` }).from(jiraConnections),
        ]);
        metrics.organizations = (totalAdoOrgs[0]?.count || 0) + (totalJiraConns[0]?.count || 0);
      }

      if (selectedOrganization) {
        metrics.recentOrganizations = [
          {
            id: selectedOrganization.id,
            name: selectedOrganization.name,
            description: selectedOrganization.description,
            industry: null,
            status: selectedOrganization.status,
            createdAt: new Date().toISOString(),
          },
        ];
      }

      setCachedValue(dashboardMetricsCache, cacheKey, metrics, DASHBOARD_METRICS_CACHE_TTL_MS);
      console.log(`[Dashboard] /api/dashboard/metrics completed in ${Date.now() - startedAt}ms`);
      res.json(metrics);
    } catch (error) {
      console.error("Error fetching dashboard metrics:", error);
      res.status(500).json({ error: "Failed to fetch dashboard metrics" });
    }
  });

  app.get("/api/dashboard/live-project-count", async (req: Request, res: Response) => {
    const startedAt = Date.now();
    try {
      const selectedOrganization = await getSelectedGlobalOrganizationFromRequest(req);
      if (!selectedOrganization) {
        return res.status(400).json({ error: "Select a specific organization to view live project count." });
      }

      const cacheKey = selectedOrganization.id;
      const cachedValue = getCachedValue<{ liveProjectCount: number; source: "live"; fetchedAt: string }>(
        liveProjectCountCache,
        cacheKey
      );
      if (cachedValue) {
        return res.json(cachedValue);
      }

      const userId = (req as any).user?.id;
      const liveProjectCount = await getLiveProjectCountForSelectedOrganization(selectedOrganization, userId);
      const payload = {
        liveProjectCount: typeof liveProjectCount === "number" ? liveProjectCount : 0,
        source: "live" as const,
        fetchedAt: new Date().toISOString(),
      };

      setCachedValue(liveProjectCountCache, cacheKey, payload, LIVE_PROJECT_COUNT_CACHE_TTL_MS);
      console.log(`[Dashboard] /api/dashboard/live-project-count completed in ${Date.now() - startedAt}ms`);
      res.json(payload);
    } catch (error) {
      console.error("Error fetching live dashboard project count:", error);
      res.status(500).json({ error: "Failed to fetch live dashboard project count" });
    }
  });

  app.get("/api/dashboard/live-golden-repo-count", async (req: Request, res: Response) => {
    const startedAt = Date.now();
    try {
      const { getTenantIdFromRequest } = await import("./services/github-config-resolver");
      const { getLiveGoldenRepositoriesCount } = await import("./routes/github-repos");
      const tenantId = await getTenantIdFromRequest(req);
      const cacheKey = tenantId ?? "global";
      const cachedValue = getCachedValue<{ liveGoldenRepoCount: number; source: "live"; fetchedAt: string }>(
        liveGoldenRepoCountCache,
        cacheKey
      );
      if (cachedValue) {
        return res.json(cachedValue);
      }

      const liveGoldenRepoCount = await getLiveGoldenRepositoriesCount(tenantId);
      const payload = {
        liveGoldenRepoCount: typeof liveGoldenRepoCount === "number" ? liveGoldenRepoCount : 0,
        source: "live" as const,
        fetchedAt: new Date().toISOString(),
      };

      setCachedValue(
        liveGoldenRepoCountCache,
        cacheKey,
        payload,
        LIVE_GOLDEN_REPO_COUNT_CACHE_TTL_MS
      );
      console.log(`[Dashboard] /api/dashboard/live-golden-repo-count completed in ${Date.now() - startedAt}ms`);
      res.json(payload);
    } catch (error) {
      console.error("Error fetching live golden repo count:", error);
      res.status(500).json({ error: "Failed to fetch live golden repo count" });
    }
  });

  app.get("/api/global-organizations", async (req: Request, res: Response) => {
    try {
      const { storage } = await import("./storage");
      const userId = (req as any).user?.id;
      let visibleOrgIds = new Set<string>();
      let effectiveUserIds = userId ? [userId] : [];

      if (userId) {
        const access = await resolveEffectiveUserAccess(userId);
        effectiveUserIds = access?.userIds ?? [userId];
        const visibleOrgs = await storage.getVisibleOrganizations(userId);
        visibleOrgs.forEach(org => visibleOrgIds.add(org.id));

        // Also add organizations for projects the user explicitly has access to
        const { projectMembers, sdlcProjects } = await import("@shared/schema");

        const memberRows = await db
          .select({ projectId: projectMembers.projectId })
          .from(projectMembers)
          .where(inArray(projectMembers.userId, effectiveUserIds));

        const memberProjectIds = memberRows.map(r => r.projectId);

        if (memberProjectIds.length > 0) {
          // 1. Get DevX projects to find their organizationIds
          const explicitDevXProjects = await db
            .select({ organizationId: projects.organizationId })
            .from(projects)
            .where(inArray(projects.id, memberProjectIds));

          explicitDevXProjects.forEach(p => {
            if (p.organizationId) visibleOrgIds.add(p.organizationId);
          });

          // 2. Get synced SDLC projects
          const explicitSdlcProjects = await db
            .select()
            .from(sdlcProjects)
            .where(inArray(sdlcProjects.id, memberProjectIds));

          // Add Jira connection IDs
          explicitSdlcProjects.forEach(sp => {
            if (sp.jiraConnectionId) visibleOrgIds.add(sp.jiraConnectionId);
          });

          // For ADO, we'll need to match by URL after fetching artifactOrgs, so we'll do it below
        }
      }

      const [allAdoOrganizations, allJiraOrganizationRows] = await Promise.all([
        db
          .select({
            id: artifactOrganizations.id,
            organizationUrl: artifactOrganizations.organizationUrl,
            projectName: artifactOrganizations.projectName,
            patToken: artifactOrganizations.patToken,
            createdAt: artifactOrganizations.createdAt,
            updatedAt: artifactOrganizations.updatedAt,
          })
          .from(artifactOrganizations),
        db
          .select({
            id: jiraConnections.id,
            name: jiraConnections.name,
            instanceUrl: jiraConnections.instanceUrl,
            email: jiraConnections.email,
            isActive: jiraConnections.isActive,
            createdAt: jiraConnections.createdAt,
            updatedAt: jiraConnections.updatedAt,
          })
          .from(jiraConnections),
      ]);

      if (userId) {
        const { projectMembers, sdlcProjects } = await import("@shared/schema");
        const { matchesOrganizationValue } = await import("./utils/organization-matcher");
        const memberRows = await db
          .select({ projectId: projectMembers.projectId })
          .from(projectMembers)
          .where(inArray(projectMembers.userId, effectiveUserIds));
        const memberProjectIds = memberRows.map(r => r.projectId);

        if (memberProjectIds.length > 0) {
          const explicitSdlcProjects = await db
            .select()
            .from(sdlcProjects)
            .where(inArray(sdlcProjects.id, memberProjectIds));

          explicitSdlcProjects.forEach(sp => {
            if (sp.integrationType !== 'jira' && sp.organization) {
              const match = allAdoOrganizations.find(a => matchesOrganizationValue(sp.organization, a.organizationUrl));
              if (match) visibleOrgIds.add(match.id);
            }
          });
        }
      }

      const integrationOrgIds = [
        ...allAdoOrganizations.map((org) => org.id),
        ...allJiraOrganizationRows.map((org) => org.id),
      ];
      const mirroredRbacOrganizations =
        userId && integrationOrgIds.length > 0
          ? (
              await db
                .select({
                  id: organizations.id,
                  ownerUserId: organizations.ownerUserId,
                })
                .from(organizations)
                .where(inArray(organizations.id, integrationOrgIds))
            )
          : [];
      const ownerUserIds = Array.from(
        new Set(
          mirroredRbacOrganizations
            .map((org) => org.ownerUserId)
            .filter((ownerUserId): ownerUserId is string => Boolean(ownerUserId)),
        ),
      );
      const ownerRows = ownerUserIds.length > 0
        ? await db
            .select({
              id: users.id,
              email: users.email,
              displayName: users.displayName,
            })
            .from(users)
            .where(inArray(users.id, ownerUserIds))
        : [];
      const ownerInfoByUserId = new Map(
        ownerRows.map((owner) => [
          owner.id,
          {
            id: owner.id,
            email: owner.email,
            displayName: owner.displayName,
          },
        ]),
      );
      const ownerUserIdByOrgId = new Map(
        mirroredRbacOrganizations.map((org) => [org.id, org.ownerUserId || null]),
      );
      const getOwnerInfo = (id: string) => {
        const ownerUserId = ownerUserIdByOrgId.get(id);
        return ownerUserId ? ownerInfoByUserId.get(ownerUserId) || null : null;
      };
      const canShowIntegrationOrg = (id: string) => !userId || visibleOrgIds.has(id);

      const adoOrganizations = allAdoOrganizations.filter(org => canShowIntegrationOrg(org.id));
      const jiraOrganizationRows = allJiraOrganizationRows.filter(org => canShowIntegrationOrg(org.id));

      const organizationsForSelector = [
        ...adoOrganizations.map((organization) => ({
          id: organization.id,
          name:
            extractOrganizationNameFromUrl(organization.organizationUrl) ||
            organization.projectName ||
            organization.organizationUrl,
          sourceType: "ado",
          organizationUrl: organization.organizationUrl,
          projectName: organization.projectName,
          patConfigured: Boolean(organization.patToken),
          description: organization.projectName || organization.organizationUrl,
          status: organization.patToken ? "active" : "inactive",
          createdAt: organization.createdAt,
          updatedAt: organization.updatedAt,
          ownerUserId: ownerUserIdByOrgId.get(organization.id) || null,
          ownerInfo: getOwnerInfo(organization.id),
        })),
        ...jiraOrganizationRows.map((organization) => ({
          id: organization.id,
          name: organization.name,
          sourceType: "jira",
          organizationUrl: organization.instanceUrl,
          projectName: organization.name,
          email: organization.email,
          patConfigured: Boolean(organization.isActive),
          description: organization.instanceUrl,
          status: organization.isActive ? "active" : "inactive",
          createdAt: organization.createdAt,
          updatedAt: organization.updatedAt,
          ownerUserId: ownerUserIdByOrgId.get(organization.id) || null,
          ownerInfo: getOwnerInfo(organization.id),
        })),
      ].sort((left, right) => left.name.localeCompare(right.name));

      res.json(organizationsForSelector);
    } catch (error) {
      console.error("Error fetching global organizations:", error);
      res.status(500).json({ error: "Failed to fetch global organizations" });
    }
  });

