  // Resolve (or create) a user by email within the inviter's tenant, mirroring
  // the admin invite flow so an invited person becomes a real user record that
  // gets fully provisioned on their first login.
  async function resolveOrCreateInvitee(email: string, inviterUserId: string) {
    const [inviter] = await db
      .select({ tenantId: users.tenantId, provider: users.provider })
      .from(users)
      .where(eq(users.id, inviterUserId))
      .limit(1);
    const tenantId = inviter?.tenantId ?? "";
    const provider = inviter?.provider ?? "microsoft";

    const [existing] = await db.select().from(users).where(eq(users.email, email)).limit(1);
    if (existing) return { userId: existing.id, tenantId: existing.tenantId ?? tenantId };

    const newUserId = randomUUID();
    await db.insert(users).values({
      id: newUserId,
      email,
      tenantId,
      provider,
      azureOid: email, // placeholder until they authenticate
      providerUserId: email,
      createdAt: new Date(),
    });
    return { userId: newUserId, tenantId };
  }

  // Invite a user to an organization (owner only).
  app.post("/api/organizations/:id/members", requireAuth, async (req: any, res: Response) => {
    try {
      const orgId = req.params.id;
      const org = await storage.getOrganization(orgId);
      if (!org) return res.status(404).json({ error: "Organization not found" });
      if (org.ownerUserId !== req.user.id) {
        return res.status(403).json({ error: "Only the organization owner can invite members" });
      }
      const email = (req.body?.email || "").trim();
      if (!email) return res.status(400).json({ error: "email is required" });

      const { userId, tenantId } = await resolveOrCreateInvitee(email, req.user.id);
      await storage.addOrganizationMember({
        organizationId: orgId,
        userId,
        tenantId: tenantId || org.tenantId,
        role: "member",
        invitedBy: req.user.id,
      });
      res.json({ success: true, userId });
    } catch (error) {
      console.error("Error inviting organization member:", error);
      res.status(500).json({ error: "Failed to invite member" });
    }
  });

