  app.get("/api/sdlc/projects/:id/available-members", requireAuth, async (req: any, res: Response) => {
    try {
      const projectId = req.params.id;
      const project = await sdlcService.getProject(projectId);
      if (!project || project.deletedFromAdo) {
        return res.status(404).json({ error: "Project not found" });
      }
      if (project.ownerUserId !== req.user.id) {
        return res.status(403).json({ error: "Only the project owner can invite members" });
      }

      const [owner] = await db
        .select({ tenantId: users.tenantId })
        .from(users)
        .where(eq(users.id, req.user.id))
        .limit(1);
      const tenantId = owner?.tenantId || "";
      if (!tenantId) {
        return res.status(400).json({ error: "Tenant could not be resolved" });
      }

      const [tenantUserRows, existingMemberRows] = await Promise.all([
        db
          .select({
            userId: users.id,
            displayName: users.displayName,
            email: users.email,
          })
          .from(users)
          .where(and(eq(users.tenantId, tenantId), eq(users.isDeleted, false))),
        db
          .select({ userId: projectMembers.userId })
          .from(projectMembers)
          .where(eq(projectMembers.projectId, projectId)),
      ]);

      const memberUserIds = new Set(existingMemberRows.map((member) => member.userId).filter(Boolean));
      const search = String(req.query.search || "").trim().toLowerCase();
      const systemUsers = tenantUserRows
        .filter((user) => user.userId && user.email)
        .filter((user) => {
          if (!search) return true;
          return [user.displayName, user.email]
            .filter(Boolean)
            .some((value) => String(value).toLowerCase().includes(search));
        })
        .map((user) => ({
          userId: user.userId,
          displayName: user.displayName || user.email,
          email: user.email,
          isOwner: user.userId === project.ownerUserId,
          isMember: memberUserIds.has(user.userId),
        }))
        .sort((a, b) => (a.displayName || a.email).localeCompare(b.displayName || b.email));

      res.json({ users: systemUsers });
    } catch (error) {
      console.error("Error fetching available SDLC project members:", error);
      res.status(500).json({ error: "Failed to fetch available members" });
    }
  });

  app.post("/api/sdlc/projects/:id/members", requireAuth, async (req: any, res: Response) => {
    try {
      const projectId = req.params.id;
      const project = await sdlcService.getProject(projectId);
      if (!project || project.deletedFromAdo) {
        return res.status(404).json({ error: "Project not found" });
      }
      if (project.ownerUserId !== req.user.id) {
        return res.status(403).json({ error: "Only the project owner can invite members" });
      }

      const requestedUserId = String(req.body?.userId || "").trim();
      const requestedEmail = String(req.body?.email || "").trim().toLowerCase();
      if (!requestedUserId && !requestedEmail) {
        return res.status(400).json({ error: "userId is required" });
      }

      const [owner] = await db
        .select({ tenantId: users.tenantId })
        .from(users)
        .where(eq(users.id, req.user.id))
        .limit(1);
      const tenantId = owner?.tenantId || "";
      if (!tenantId) {
        return res.status(400).json({ error: "Tenant could not be resolved" });
      }

      const userLookupCondition = requestedUserId
        ? eq(users.id, requestedUserId)
        : sql`lower(${users.email}) = ${requestedEmail}`;
      const [targetUser] = await db
        .select({
          userId: users.id,
          tenantId: users.tenantId,
          email: users.email,
        })
        .from(users)
        .where(and(userLookupCondition, eq(users.tenantId, tenantId), eq(users.isDeleted, false)))
        .limit(1);

      if (!targetUser) {
        return res.status(404).json({ error: "Select an existing active user in this tenant" });
      }
      if (targetUser.userId === project.ownerUserId) {
        return res.status(400).json({ error: "Project owner is already assigned to this project" });
      }

      await storage.addProjectMember({
        projectId,
        userId: targetUser.userId,
        tenantId: targetUser.tenantId || tenantId,
        role: "member",
        invitedBy: req.user.id,
      });
      res.json({ success: true, userId: targetUser.userId, email: targetUser.email });
    } catch (error) {
      console.error("Error inviting SDLC project member:", error);
      res.status(500).json({ error: "Failed to invite member" });
    }
  });

  app.delete("/api/sdlc/projects/:id/members/:userId", requireAuth, async (req: any, res: Response) => {
    try {
      const projectId = req.params.id;
      const targetUserId = req.params.userId;
      const project = await sdlcService.getProject(projectId);
      if (!project || project.deletedFromAdo) {
        return res.status(404).json({ error: "Project not found" });
      }
      if (project.ownerUserId !== req.user.id) {
        return res.status(403).json({ error: "Only the project owner can remove members" });
      }
      if (!targetUserId) {
        return res.status(400).json({ error: "userId is required" });
      }
      if (targetUserId === project.ownerUserId) {
        return res.status(400).json({ error: "Project owner cannot be removed from this project" });
      }

      await db
        .delete(projectMembers)
        .where(
          and(
            eq(projectMembers.projectId, projectId),
            eq(projectMembers.userId, targetUserId),
          ),
        );

      res.json({ success: true, userId: targetUserId });
    } catch (error) {
      console.error("Error removing SDLC project member:", error);
      res.status(500).json({ error: "Failed to remove member" });
    }
  });

