  // ============================================================================

  /**
   * GET /api/organizations
   * Fetch all stored artifact organizations from the database
   * Returns organizations with secure PAT token handling (token decrypted on server, never exposed to frontend)
   */
  app.get("/api/organizations", async (req, res) => {
    try {
      const orgs = await storage.getArtifactOrganizations();

      // Transform to return only necessary fields, never expose encrypted PAT to frontend
      const safeOrgs = orgs.map((org) => ({
        id: org.id,
        projectName: org.projectName,
        organizationUrl: org.organizationUrl,
      })); res.json(safeOrgs);
    } catch (error) {
      console.error("[API] Error fetching organizations:", error);
      res.status(500).json({
        error: "Failed to fetch organizations",
        details: error instanceof Error ? error.message : String(error),
      });
    }
  });

  /**
   * GET /api/ado-projects
   * Fetch projects from Azure DevOps based on selected organization
   * Query parameters:
   *   - org (optional): Organization ID or "all" for all organizations
   *   If org is not provided or empty, fetches from all organizations
   *   If org is "all", fetches from all stored organizations
   *   If org is an org ID, fetches only from that organization
   */
  app.get(
    "/api/ado-projects",
    requireActivity("ADO_PROJECT_LIST"),
    async (req, res) => {
      try {
        // Honour the org switcher even when the caller didn't pass ?org= in
        // the URL (e.g. the SDLC page uses queryKey ["/api/ado-projects"]
        // which becomes a bare GET with no query string). Explicit ?org=
        // always wins over the header.
        const orgFromHeader = (req.headers["x-organization-id"] as string | undefined)?.trim();
        let orgParam =
          (req.query.org as string) ||
          (orgFromHeader && orgFromHeader.length > 0 ? orgFromHeader : "all");

        if (orgParam === "__all__") orgParam = "all";

        let finalProjects: any[] = [];
        let errors: any[] = [];

        const userId = (req as any).user?.id;
        const patReadiness = userId
          ? await getUserPatReadiness(userId)
          : {
              projectManagementReadyInstanceUrls: new Set<string>(),
              hasAnyProjectManagementPat: false,
              repoReadyProviders: new Set<string>(),
              hasAnyRepoPat: false,
            };
        const paginated = String(req.query.paginated || "").toLowerCase() === "true";
        const page = Math.max(1, parseInt(String(req.query.page || "1"), 10) || 1);
        const limit = Math.min(100, Math.max(1, parseInt(String(req.query.limit || req.query.pageSize || "25"), 10) || 25));
        const normalizeProjectFilterValue = (value: unknown): string =>
          String(value || "").trim().toLowerCase();
        const formatProjectOrganizationDisplay = (project: any): string => {
          const raw = project.organization || project.organizationUrl || project.jiraInstanceUrl || "";
          if (!raw) return "Unknown Organization";
          try {
            const url = new URL(String(raw).startsWith("http") ? String(raw) : `https://${raw}`);
            return url.hostname;
          } catch {
            return String(raw).replace(/^https?:\/\//, "").replace(/\/+$/, "");
          }
        };
        const getProjectOrganizationCandidates = (project: any): Set<string> => {
          const candidates = new Set<string>();
          [
            project.organization,
            project.organizationUrl,
            project.jiraInstanceUrl,
            formatProjectOrganizationDisplay(project),
          ].forEach((value) => {
            const normalized = normalizeProjectFilterValue(value);
            if (!normalized) return;
            candidates.add(normalized);
            try {
              const url = new URL(normalized.startsWith("http") ? normalized : `https://${normalized}`);
              candidates.add(normalizeProjectFilterValue(url.hostname));
              candidates.add(normalizeProjectFilterValue(url.hostname.replace(/\.atlassian\.net$/i, "")));
              const adoOrgName = url.hostname === "dev.azure.com" ? url.pathname.split("/").filter(Boolean)[0] : "";
              if (adoOrgName) candidates.add(normalizeProjectFilterValue(adoOrgName));
            } catch {
              candidates.add(normalizeProjectFilterValue(normalized.replace(/^https?:\/\//, "").replace(/\/+$/, "")));
            }
          });
          return candidates;
        };
        const cacheKey = `ado-projects-${userId || 'default'}-${orgParam}`;
        const cached = adoProjectsCache.get(cacheKey);

        if (cached && cached.expires > Date.now()) {
          console.log(`[API] Returning cached ADO projects for ${cacheKey}`);
          finalProjects = cached.data;
        } else {
          // Only fetch organizations the user is allowed to see. Keep this
          // visibility rule aligned with /api/global-organizations so a
          // row shown in the global selector can also be resolved here.
          const visibleOrgs = await storage.getVisibleOrganizations(userId);
          const visibleOrgIds = new Set(visibleOrgs.map(org => org.id));
          const [allAdoOrgsRaw, allJiraConnsRaw] = await Promise.all([
            db.select().from(schema.artifactOrganizations),
            db.select().from(schema.jiraConnections),
          ]);
          const canResolveIntegrationOrg = (id: string) => !userId || visibleOrgIds.has(id);

          const allAdoOrgs = allAdoOrgsRaw.filter((org) => canResolveIntegrationOrg(org.id));
          const allJiraConns = allJiraConnsRaw.filter((conn) => canResolveIntegrationOrg(conn.id));

          if (allAdoOrgs.length === 0 && allJiraConns.length === 0) {
            return res.json({
              error: "No organizations or Jira connections configured",
              details: "Please configure at least one organization (ADO) or Jira connection in Client Settings",
              projects: [],
              warnings: [],
              page: 1,
              limit: Math.min(100, Math.max(1, parseInt(String(req.query.limit || "25"), 10) || 25)),
              total: 0,
              totalUnfiltered: 0,
              totalPages: 1,
              hasMore: false,
            });
          }

          let adoOrgsToFetch = allAdoOrgs;
          let jiraConnsToFetch = allJiraConns;

        // Filter to specific organization if requested
        if (orgParam !== "all" && orgParam !== "") {
          adoOrgsToFetch = allAdoOrgs.filter((org) => org.id === orgParam);
          jiraConnsToFetch = allJiraConns.filter((conn) => conn.id === orgParam);

          if (adoOrgsToFetch.length === 0 && jiraConnsToFetch.length === 0) {
            const selectedAdoOrg = allAdoOrgsRaw.find((org) => org.id === orgParam);
            const selectedJiraConn = allJiraConnsRaw.find((conn) => conn.id === orgParam);
            const selectedIntegration = selectedAdoOrg
              ? {
                  sourceType: "ado",
                  name:
                    extractOrganizationNameFromUrl(selectedAdoOrg.organizationUrl) ||
                    selectedAdoOrg.projectName ||
                    selectedAdoOrg.organizationUrl,
                  setupUrl: "/organizations",
                }
              : selectedJiraConn
                ? {
                    sourceType: "jira",
                    name: selectedJiraConn.name,
                    setupUrl: "/connect-jira",
                  }
                : null;

            const isKnownButNotVisible = Boolean(selectedIntegration);
            return res.status(404).json({
              code: isKnownButNotVisible
                ? "ORGANIZATION_NOT_ACCESSIBLE"
                : "ORGANIZATION_NOT_FOUND",
              error: isKnownButNotVisible
                ? "Selected organization is not accessible"
                : "Selected organization was not found",
              message: isKnownButNotVisible
                ? `The selected ${selectedIntegration?.sourceType === "jira" ? "Jira connection" : "Azure DevOps organization"} exists, but your account does not currently have access to load its projects.`
                : "The selected organization is no longer available. It may have been deleted or the global selector is showing stale data.",
              details: isKnownButNotVisible
                ? "Ask an admin or organization owner to add you to this organization or one of its projects, then retry."
                : "Choose another organization from the global selector or reconnect the organization.",
              selectedOrgId: orgParam,
              selectedOrganization: selectedIntegration,
              action: isKnownButNotVisible ? "REQUEST_ACCESS" : "RESELECT_OR_RECONNECT",
              links: [
                {
                  label: isKnownButNotVisible ? "Manage access" : "Manage organizations",
                  href: "/organizations",
                },
                ...(selectedIntegration?.sourceType === "jira"
                  ? [{ label: "Reconnect Jira", href: "/connect-jira" }]
                  : []),
              ],
            });
          }
        }

        const allProjects: any[] = [];
        const errors: any[] = [];
        let credentialErrorCode: string | null = null;

        // Fetch Jira projects: try per-user PAT (live API) per connection, fall back to DB-only
        if (jiraConnsToFetch.length > 0) {
          const userId = (req as any).user?.id;

          if (userId) {
	            const { getJiraServiceForUser } = await import("./integrations/jira/user-credential-resolver");
	            const visibleJiraSdlcRows = (await sdlcService.getAllProjects(userId))
	              .filter((row) => row.integrationType === "jira" && !row.deletedFromAdo);

	            const seenProjectKeys = new Set<string>();
	            const normalizeUrl = (u: string) => u.replace(/^https?:\/\//, "").replace(/\/+$/, "").toLowerCase();

	            for (const conn of jiraConnsToFetch) {
	              try {
	                const jiraService = await getJiraServiceForUser(userId, undefined, conn.instanceUrl);

	                const liveProjects = await jiraService.getProjects();
	                const normalizedInstanceUrl = normalizeUrl(conn.instanceUrl);
	                const allowLegacyUrlFallback =
	                  allJiraConnsRaw.filter((candidate) => normalizeUrl(candidate.instanceUrl) === normalizedInstanceUrl).length <= 1;
	                const sdlcByKey = new Map<string, typeof visibleJiraSdlcRows[0]>();
	                for (const row of visibleJiraSdlcRows) {
	                  const rowUrl = normalizeUrl(row.jiraInstanceUrl || row.organization || "");
	                  const belongsToConnection =
	                    row.jiraConnectionId === conn.id ||
	                    (allowLegacyUrlFallback && !row.jiraConnectionId && rowUrl === normalizedInstanceUrl);
	                  if (!belongsToConnection) continue;
	                  if (row.jiraProjectKey) sdlcByKey.set(row.jiraProjectKey.toUpperCase(), row);
	                  if (row.projectId) sdlcByKey.set(row.projectId.toUpperCase(), row);
	                  sdlcByKey.set(row.id, row);
	                }

                const mappedJiraProjects = liveProjects
                  .filter(project => {
                    if (!project.key) return false;
                    const scopedKey = `${normalizedInstanceUrl}-${project.key.toUpperCase()}`;
                    return !seenProjectKeys.has(scopedKey);
                  })
	                  .map(project => {
	                    const key = project.key!;
	                    seenProjectKeys.add(`${normalizedInstanceUrl}-${key.toUpperCase()}`);
	                    const sdlcProject =
	                      sdlcByKey.get(key.toUpperCase()) ||
	                      (project.id ? sdlcByKey.get(String(project.id).toUpperCase()) : undefined) ||
	                      null;

	                    // Determine organization name to display
	                    // If we're filtering by a specific connection, use its name.
	                    let projectOrg = conn.name || conn.instanceUrl;

                    return {
                      id: key,
                      name: project.name,
                      description: (project as any).description || "",
                      organization: projectOrg,
                      organizationUrl: conn.instanceUrl,
	                      jiraProjectKey: key,
	                      jiraConnectionId: conn.id,
	                      jiraInstanceUrl: conn.instanceUrl,
	                      sdlcProject,
	                      integrationType: "jira",
	                    };
	                  });

                allProjects.push(...mappedJiraProjects);
              } catch (liveErr: any) {
                const message =
                  liveErr instanceof Error ? liveErr.message : String(liveErr);
                const errorMsg = `Error fetching Jira projects from ${conn.name || conn.instanceUrl}: ${message}`;
                console.log(`[API] Live Jira API failed for connection ${conn.id} (${conn.instanceUrl}): ${message}`);
                errors.push(errorMsg);
                if (liveErr?.code === "JIRA_PAT_MISSING" || liveErr?.code === "JIRA_PAT_INVALID") {
                  credentialErrorCode = liveErr.code;
                }
              }
            }
          }

          {
            const normalizeUrl = (u: string) => u.replace(/^https?:\/\//, "").replace(/\/+$/, "").toLowerCase();
            const selectedJiraConn = orgParam === "all"
              ? null
              : jiraConnsToFetch.find((conn) => conn.id === orgParam) || null;
            const selectedJiraUrl = selectedJiraConn ? normalizeUrl(selectedJiraConn.instanceUrl) : null;
            const allowLegacyUrlFallback = selectedJiraUrl
              ? allJiraConnsRaw.filter((conn) => normalizeUrl(conn.instanceUrl) === selectedJiraUrl).length <= 1
              : false;
            const existingJiraProjectKeys = new Set(
              allProjects
                .filter((project) => project.integrationType === "jira")
                .flatMap((project) => [
                  project.sdlcProject?.id,
                  project.id,
                  project.jiraConnectionId && project.jiraProjectKey
                    ? `${project.jiraConnectionId}:${String(project.jiraProjectKey).toUpperCase()}`
                    : null,
                ])
                .filter(Boolean)
                .map(String),
            );
            const jiraProjects = userId
              ? (await sdlcService.getAllProjects(userId)).filter((project) => {
                if (project.integrationType !== "jira" || project.deletedFromAdo) return false;
                if (orgParam === "all") return true;
                if (project.jiraConnectionId) return project.jiraConnectionId === orgParam;
                if (!allowLegacyUrlFallback || !selectedJiraUrl) return false;
                const projectUrl = normalizeUrl(project.jiraInstanceUrl || project.organization || "");
                return projectUrl === selectedJiraUrl;
              })
              : [];

            const mappedJiraProjects = jiraProjects
              .map(project => ({
                id: project.id,
                name: project.name,
                description: project.description || "",
                organization: project.organization || "Jira",
                organizationUrl: project.jiraInstanceUrl || "",
                jiraProjectKey: project.jiraProjectKey,
                jiraConnectionId: project.jiraConnectionId || selectedJiraConn?.id || jiraConnsToFetch[0]?.id,
                jiraInstanceUrl: project.jiraInstanceUrl,
                sdlcProject: project,
                integrationType: "jira",
              }))
              .filter((project) => {
                const keys = [
                  project.sdlcProject?.id,
                  project.id,
                  project.jiraConnectionId && project.jiraProjectKey
                    ? `${project.jiraConnectionId}:${String(project.jiraProjectKey).toUpperCase()}`
                    : null,
                ]
                  .filter(Boolean)
                  .map(String);
                return keys.every((key) => !existingJiraProjectKeys.has(key));
              });

            allProjects.push(...mappedJiraProjects);
          }
        }

        // Fetch projects from each ADO organization
        await Promise.all(
          adoOrgsToFetch.map(async (org) => {
            try {
              // Extract organization name from URL
              const organization = org.organizationUrl
                .replace(/https?:\/\/dev\.azure\.com\//, "")
                .replace(/\/$/, "");

              if (!org.patToken) {
                throw new Error("PAT token not configured for this organization");
              }

              // Decrypt PAT token securely on server
              const { decryptPAT } = await import("./crypto-utils");
              const decryptedPAT = decryptPAT(org.patToken);

              if (!decryptedPAT) {
                throw new Error("Failed to decrypt PAT token for this organization");
              }

              // Create Azure DevOps service with decrypted PAT
              const { AzureDevOpsService } = await import("./azure-devops-service");
              const adoService = new AzureDevOpsService({
                organization,
                project: org.projectName,
                pat: decryptedPAT,
              });

              // Fetch projects from Azure DevOps API
              const projects = await adoService.getProjects();

              // Transform projects to include organization context
              const transformedProjects = projects.map((project: any) => ({
                id: project.id,
                name: project.name,
                description: project.description || "",
                organization: organization,
                organizationUrl: org.organizationUrl,
                artifactOrgId: org.id,
              }));

              allProjects.push(...transformedProjects);
            } catch (error) {
              const message =
                error instanceof Error ? error.message : String(error);
              const errorMsg = `Error fetching projects from ${org.organizationUrl}: ${message}`;
              console.error(`[API] ${errorMsg}`);
              errors.push(errorMsg);
              // Continue with next organization even if one fails
            }
          })
        );

        if (allProjects.length === 0) {
          // No projects came back from either source.
          if (errors.length === 0) {
            return res.json({
              projects: [],
              warnings: [],
            });
          }

          const baseMessage =
            (adoOrgsToFetch.length + jiraConnsToFetch.length) === 1
              ? "Failed to fetch projects for this organization. Verification of credentials or URL may be required."
              : "Failed to fetch projects from any configured organization.";

          console.warn(
            `[API] No projects fetched for org: ${orgParam}. Errors: ${errors.join(
              " | ",
            )}`,
          );

          return res.status(400).json({
            code: credentialErrorCode || undefined,
            provider: credentialErrorCode ? "jira" : undefined,
            error: baseMessage,
            details: errors,
          });
        }
        // For each ADO project, attach linked SDLC project (batch query for ADO; preserve Jira payloads)
        const adoProjectIds = allProjects.map((p) => p.id);
        const sdlcProjects =
          await sdlcService.getProjectsByAdoProjectIds(adoProjectIds);
        const sdlcMap = new Map(
          sdlcProjects.map((p) => [p.projectId || p.id, p]),
        );
        const visibleJiraSdlcProjects = userId
          ? (await sdlcService.getAllProjects(userId)).filter(
              (project) => project.integrationType === "jira" && !project.deletedFromAdo,
            )
          : [];
        const jiraSdlcByConnectionAndKey = new Map<string, typeof visibleJiraSdlcProjects[0]>();
        const jiraSdlcByConnectionAndProjectId = new Map<string, typeof visibleJiraSdlcProjects[0]>();
        const normalizeJiraProjectKey = (value: unknown) => String(value || "").trim().toUpperCase();
        for (const project of visibleJiraSdlcProjects) {
          const connectionId = project.jiraConnectionId || "";
          if (!connectionId) continue;
          if (project.jiraProjectKey) {
            jiraSdlcByConnectionAndKey.set(
              `${connectionId}:${normalizeJiraProjectKey(project.jiraProjectKey)}`,
              project,
            );
          }
          if (project.projectId) {
            jiraSdlcByConnectionAndProjectId.set(
              `${connectionId}:${normalizeJiraProjectKey(project.projectId)}`,
              project,
            );
          }
        }
        const findJiraSdlcProject = (project: any) => {
          const connectionId = project.jiraConnectionId || project.sdlcProject?.jiraConnectionId || "";
          if (!connectionId) return null;
          const key =
            normalizeJiraProjectKey(project.jiraProjectKey) ||
            normalizeJiraProjectKey(project.key) ||
            normalizeJiraProjectKey(project.id);
          const projectId =
            normalizeJiraProjectKey(project.projectId) ||
            normalizeJiraProjectKey(project.id);
          return (
            (key ? jiraSdlcByConnectionAndKey.get(`${connectionId}:${key}`) : undefined) ||
            (projectId ? jiraSdlcByConnectionAndProjectId.get(`${connectionId}:${projectId}`) : undefined) ||
            null
          );
        };
        const projectsWithSdlc = await Promise.all(allProjects.map(async (project) => {
          const projectIntegrationType = project.integrationType || "ado";
          if (projectIntegrationType === "jira") {
            const sdlcProject = project.sdlcProject || findJiraSdlcProject(project);
            return {
              ...project,
              sdlcProject,
              ...(sdlcProject
                ? await getProjectPatStatusForUser(sdlcProject, patReadiness, userId)
                : getProjectPatStatus(project, patReadiness)),
            };
          }
          const sdlcProject = sdlcMap.get(project.id) || null;
          return {
            ...project,
            sdlcProject,
            ...(sdlcProject
              ? await getProjectPatStatusForUser(sdlcProject, patReadiness, userId)
              : getProjectPatStatus(project, patReadiness)),
          };
        }));

        // Filter projects based on user's actual access level
        finalProjects = projectsWithSdlc;

        if (userId) {
          const access = await resolveEffectiveUserAccess(userId);
          const effectiveUserIds = access?.userIds ?? [userId];
          const effectiveUserIdSet = new Set(effectiveUserIds);
          // Check org-level access
          const { organizationMembers, organizations, projectMembers } = await import("@shared/schema");
          const memberOrgRows = await db
            .select({ organizationId: organizationMembers.organizationId })
            .from(organizationMembers)
            .where(inArray(organizationMembers.userId, effectiveUserIds));
          const memberOrgIds = new Set(memberOrgRows.map(r => r.organizationId));

          const ownedOrgs = await db
            .select({ id: organizations.id })
            .from(organizations)
            .where(inArray(organizations.ownerUserId, effectiveUserIds));
          ownedOrgs.forEach(o => memberOrgIds.add(o.id));

          // Check explicit project access
          const projectMemberRows = await db
            .select({ projectId: projectMembers.projectId })
            .from(projectMembers)
            .where(inArray(projectMembers.userId, effectiveUserIds));
          const explicitProjectIds = new Set(projectMemberRows.map(r => r.projectId));

          // A user can see a project if:
          // 1. They have full access to its organization (via memberOrgIds)
          // 2. They have explicit access to the project (via explicitProjectIds)
          finalProjects = projectsWithSdlc.filter(project => {
            const orgId = project.artifactOrgId || project.jiraConnectionId;
            const hasOrgAccess = orgId && memberOrgIds.has(orgId);

            const projectId = project.sdlcProject?.id;
            const hasProjectAccess = projectId && explicitProjectIds.has(projectId);
            const isProjectOwner =
              project.sdlcProject?.ownerUserId &&
              effectiveUserIdSet.has(project.sdlcProject.ownerUserId);

            // Also check if they have explicit access to the ADO project ID directly (fallback)
            const hasDirectProjectAccess = explicitProjectIds.has(project.id);

            return hasOrgAccess || hasProjectAccess || isProjectOwner || hasDirectProjectAccess;
          });
        }

        adoProjectsCache.set(cacheKey, { data: finalProjects, expires: Date.now() + 5 * 60 * 1000 });
      } // End of else block for cache miss

        const ownerUserIds = Array.from(
          new Set(
            finalProjects
              .map((project) => project.sdlcProject?.ownerUserId)
              .filter((ownerUserId): ownerUserId is string => typeof ownerUserId === "string" && ownerUserId.trim().length > 0),
          ),
        );
        const currentUserProjectRoles = new Map<string, string>();
        if (userId) {
          const projectIdsForRoleLookup = Array.from(
            new Set(
              finalProjects
                .map((project) => project.sdlcProject?.id)
                .filter((projectId): projectId is string => typeof projectId === "string" && projectId.trim().length > 0),
            ),
          );
          if (projectIdsForRoleLookup.length > 0) {
            const roleRows = await db
              .select({
                projectId: schema.projectMembers.projectId,
                role: schema.projectMembers.role,
              })
              .from(schema.projectMembers)
              .where(
                and(
                  eq(schema.projectMembers.userId, userId),
                  inArray(schema.projectMembers.projectId, projectIdsForRoleLookup),
                ),
              );
            for (const row of roleRows) {
              currentUserProjectRoles.set(row.projectId, row.role || "member");
            }
          }
        }
        const ownerInfoByUserId = new Map<string, { id: string; email: string | null; displayName: string | null }>();
        if (ownerUserIds.length > 0) {
          const ownerRows = await db
            .select({
              id: schema.users.id,
              email: schema.users.email,
              displayName: schema.users.displayName,
            })
            .from(schema.users)
            .where(inArray(schema.users.id, ownerUserIds));
          for (const row of ownerRows) {
            ownerInfoByUserId.set(row.id, {
              id: row.id,
              email: row.email || null,
              displayName: row.displayName || null,
            });
          }
        }

        finalProjects = await Promise.all(
          finalProjects.map(async (project) => {
            const sdlcProjectId = project.sdlcProject?.id;
            const repoIntegrationConfig = await getProjectRepoIntegrationConfig(sdlcProjectId);
            const ownerUserId = project.sdlcProject?.ownerUserId || null;
            const isOwner = Boolean(userId && ownerUserId && ownerUserId === userId);
            const currentUserRole =
              isOwner
                ? "owner"
                : sdlcProjectId
                  ? currentUserProjectRoles.get(sdlcProjectId) || "member"
                  : null;
            const refreshedPatStatus = project.sdlcProject
              ? await getProjectPatStatusForUser(
                  {
                    ...project.sdlcProject,
                    repoIntegrationConfig,
                  },
                  patReadiness,
                  userId,
                )
              : getProjectPatStatus({ ...project, repoIntegrationConfig }, patReadiness);
            return {
              ...project,
              ...refreshedPatStatus,
              ownerUserId,
              isOwner,
              currentUserRole,
              ownerInfo: ownerUserId ? ownerInfoByUserId.get(ownerUserId) || null : null,
              repoIntegrationConfig,
            };
          }),
        );

        const effectiveSearch = String(req.query.search || "").trim().toLowerCase();
        const effectiveSyncStatus = String(req.query.syncStatus || req.query.syncFilter || "all").toLowerCase();
        const effectiveOrganizationFilter = String(
          req.query.organization || req.query.organizationFilter || "all",
        ).trim().toLowerCase();
        const effectiveSortBy = String(req.query.sortBy || req.query.sortField || "name");
        const effectiveSortDirection =
          String(req.query.sortDirection || "asc").toLowerCase() === "desc" ? "desc" : "asc";
        const effectiveLimit = Math.min(
          100,
          Math.max(1, parseInt(String(req.query.limit || req.query.pageSize || limit || "25"), 10) || 25),
        );
        const effectivePaginated = paginated || Boolean(req.query.page);

        if (effectivePaginated) {
          const totalUnfiltered = finalProjects.length;
          const filteredProjects = finalProjects
            .filter((project) => {
              if (effectiveSyncStatus !== "synced" && effectiveSyncStatus !== "unsynced") return true;
              const synced = !!project.sdlcProject && (project.credentialStatus?.readyForUser ?? project.userPatConfigured) === true;
              return effectiveSyncStatus === "synced" ? synced : !synced;
            })
            .filter((project) => {
              if (!effectiveOrganizationFilter || effectiveOrganizationFilter === "all") return true;
              return getProjectOrganizationCandidates(project).has(effectiveOrganizationFilter);
            })
            .filter((project) => {
              const effectiveOwnership = String(req.query.ownership || "all").toLowerCase();
              if (effectiveOwnership !== "owner" && effectiveOwnership !== "member") return true;
              return effectiveOwnership === "owner" ? project.isOwner === true : project.isOwner !== true;
            })
            .filter((project) => {
              if (!effectiveSearch) return true;
              return [
                project.name,
                project.description,
                project.organization,
                project.organizationUrl,
                project.jiraInstanceUrl,
                project.jiraProjectKey,
                project.ownerInfo?.displayName,
                project.ownerInfo?.email,
              ]
                .filter(Boolean)
                .some((value) => String(value).toLowerCase().includes(effectiveSearch));
            })
            .sort((a, b) => {
              let comparison = 0;
              switch (effectiveSortBy) {
                case "organization":
                  comparison = formatProjectOrganizationDisplay(a).localeCompare(
                    formatProjectOrganizationDisplay(b),
                    undefined,
                    { sensitivity: "base" },
                  );
                  break;
                case "projectKey":
                  comparison = String(a.jiraProjectKey || "").localeCompare(
                    String(b.jiraProjectKey || ""),
                    undefined,
                    { sensitivity: "base" },
                  );
                  break;
                case "status": {
                  const aSynced = !!a.sdlcProject && (a.credentialStatus?.readyForUser ?? a.userPatConfigured) === true;
                  const bSynced = !!b.sdlcProject && (b.credentialStatus?.readyForUser ?? b.userPatConfigured) === true;
                  comparison = Number(aSynced) - Number(bSynced);
                  break;
                }
                case "name":
                default:
                  comparison = String(a.name || "").localeCompare(String(b.name || ""), undefined, { sensitivity: "base" });
                  break;
              }
              return effectiveSortDirection === "asc" ? comparison : -comparison;
            });
          const total = filteredProjects.length;
          const totalPages = Math.max(1, Math.ceil(total / effectiveLimit));
          const offset = (page - 1) * effectiveLimit;
          return res.json({
            projects: filteredProjects.slice(offset, offset + effectiveLimit),
            warnings: errors,
            page,
            limit: effectiveLimit,
            pageSize: effectiveLimit,
            total,
            totalCount: total,
            totalUnfiltered,
            totalPages,
            hasMore: page < totalPages,
          });
        }

        // When some organizations fail but others succeed, return successful projects
        // along with non-fatal warnings so the UI can surface them.
        res.json({
          projects: finalProjects,
          warnings: errors,
          totalCount: finalProjects.length,
        });
      } catch (error) {
        console.error("[API] Error fetching ADO projects:", error);
        res.status(500).json({
          error: "Failed to fetch ADO projects",
          details: error instanceof Error ? error.message : String(error),
        });
      }
    });

  /**
   * PATCH /api/ado-projects/:projectId
   * Update/edit a project in Azure DevOps
   */
  app.patch(
    "/api/ado-projects/:projectId",
    requireActivity("ADO_PROJECT_UPDATE"),
    async (req: Request, res: Response) => {
      try {
        const { projectId } = req.params;
        const {
          name,
          description,
          organization,
          organizationUrl,
          repositoryId,
          repository_id,
          repositoryCount,
          linkedGoldenRepoOrg,
          linkedGoldenRepoProject,
          linkedGoldenRepoName,
          status,
          golden_repo_reference,
        } = req.body;

        if (!name && !description) {
          return res.status(400).json({
            error: "At least one field (name or description) is required to update"
          });
        }

        const { sdlcService } = await import("./sdlc/service");
        const authUserId = (req as any).user?.id;
        const existingSdlcProject = await sdlcService.getProjectByAdoProjectId(projectId);
        if (
          existingSdlcProject?.ownerUserId &&
          existingSdlcProject.ownerUserId !== authUserId
        ) {
          return res.status(403).json({
            error: "Only the project owner can edit project metadata and integration configuration. Project members can update only their personal PAT/API tokens.",
          });
        }

        // If this is a Jira project, handled by the service to avoid ADO-specific logic
        if (await sdlcService.handleJiraProjectUpdate(projectId, req.body)) {
          return res.json({ success: true, message: "Jira project updated successfully" });
        }

        if (!organization && !organizationUrl) {
          return res.status(400).json({
            error: "Organization or organizationUrl is required"
          });
        }

        // Find the organization to get PAT token
        const artifactOrgs = await storage.getArtifactOrganizations();
        let targetOrg = null;

        if (organizationUrl) {
          targetOrg = artifactOrgs.find(org => org.organizationUrl === organizationUrl);
        } else if (organization) {
          // Extract org name from organization string
          const orgName = organization.replace(/https?:\/\/dev\.azure\.com\//, "").replace(/\/$/, "");
          targetOrg = artifactOrgs.find(org => {
            const orgUrlName = org.organizationUrl.replace(/https?:\/\/dev\.azure\.com\//, "").replace(/\/$/, "");
            return orgUrlName === orgName && org.patToken;
          });
        }

        if (!targetOrg || !targetOrg.patToken) {
          return res.status(400).json({
            error: "No artifact organization found with PAT configured for this project"
          });
        }

        // Decrypt PAT token
        const { decryptPAT } = await import("./crypto-utils");
        const decryptedPAT = decryptPAT(targetOrg.patToken);
        if (!decryptedPAT) {
          return res.status(500).json({ error: "Failed to decrypt PAT token" });
        }

        // Extract organization name
        const orgName = targetOrg.organizationUrl.replace(/https?:\/\/dev\.azure\.com\//, "").replace(/\/$/, "");

        // Create Azure DevOps service
        const { AzureDevOpsService } = await import("./azure-devops-service");
        const adoService = new AzureDevOpsService({
          organization: orgName,
          project: targetOrg.projectName || "temp", // Project name not needed for project-level operations
          pat: decryptedPAT,
        });

        // Update the project in Azure DevOps
        await adoService.updateProject(projectId, { name, description });

        // Validate golden_repo_reference if provided
        let validatedGoldenRepoReference: {
          repoId: string;
          repoName: string;
          filePaths: string[];
        } | null = null;

        if (golden_repo_reference) {
          const { validateGoldenRepoReference } = await import("./golden-repos/validate-reference");
          const validation = validateGoldenRepoReference(golden_repo_reference);
          if (!validation.ok) {
            return res.status(validation.status).json({ error: validation.error });
          }
          validatedGoldenRepoReference = validation.value;
        }

        // Also update the project in DevX database if it exists
        try {
          const { sdlcService } = await import("./sdlc/service");
          const sdlcProject = await sdlcService.getProjectByAdoProjectId(projectId);

          if (sdlcProject) {
            // Update the SDLC project with new name and/or description
            const updateData: any = {};
            if (name) {
              updateData.name = name;
            }
            if (description !== undefined) {
              updateData.description = description;
            }
            // Handle repository_id update
            const repoIdToUse = repositoryId !== undefined ? repositoryId : repository_id;
            if (repoIdToUse !== undefined) {
              updateData.repository_id = repoIdToUse || null;

              // When repository_id is set to null (not linked), clear all related fields
              if (!repoIdToUse || repositoryId === null) {
                updateData.repository_id = null;
                updateData.linkedGoldenRepoOrg = null;
                updateData.linkedGoldenRepoProject = null;
                updateData.linkedGoldenRepoName = null;
              } else {
                // Only update linked fields if repository_id is being set to a valid value
                if (linkedGoldenRepoOrg !== undefined) {
                  updateData.linkedGoldenRepoOrg = linkedGoldenRepoOrg;
                }
                if (linkedGoldenRepoProject !== undefined) {
                  updateData.linkedGoldenRepoProject = linkedGoldenRepoProject;
                }
                if (linkedGoldenRepoName !== undefined) {
                  updateData.linkedGoldenRepoName = linkedGoldenRepoName;
                }
              }
            }
            if (repositoryCount !== undefined) {
              updateData.repositoryCount = repositoryCount;
            }
            if (status !== undefined) {
              updateData.status = status;
            }
            // Handle golden_repo_reference update
            if (golden_repo_reference !== undefined) {
              if (validatedGoldenRepoReference !== null) {
                // Valid reference object (even if filePaths is empty)
                updateData.goldenRepoReference = validatedGoldenRepoReference;
              } else {
                // Explicitly set to null if the client wants to clear the reference
                updateData.goldenRepoReference = null;
              }
            }
            // If golden_repo_reference is undefined, don't update it (preserve existing value)

            await sdlcService.updateProject(sdlcProject.id, updateData);
          } else { }
        } catch (dbError) {
          // Log error but don't fail the request - ADO update was successful
          console.error("[API] Error updating project in database:", dbError);
          // Continue with success response since ADO update succeeded
        }

        res.json({
          success: true,
          message: "Project updated successfully"
        });
      } catch (error) {
        console.error("[API] Error updating project:", error);
        res.status(500).json({
          error: "Failed to update project",
          details: error instanceof Error ? error.message : String(error)
        });
      }
    });

