  // Resolve assignee name to Azure DevOps identity
  app.post("/api/ado/resolve-assignee", async (req: Request, res: Response) => {
    try {
      const { organizationUrl, projectName, assigneeName } = req.body; if (!assigneeName) {
        return res.json({
          success: true,
          resolved: false,
          reason: "missing_field",
          message: "assigneeName is required"
        });
      }

      if (!organizationUrl || !projectName) {
        return res.json({
          success: true,
          resolved: false,
          reason: "missing_field",
          message: "organizationUrl and projectName are required"
        });
      }

      const orgName = organizationUrl.replace(/https?:\/\/dev\.azure\.com\//, "").replace(/\/$/, "");
      const artifactOrgs = await storage.getArtifactOrganizations();
      const org = artifactOrgs.find(o =>
        o.organizationUrl === organizationUrl ||
        o.projectName?.toLowerCase() === projectName.toLowerCase()
      );

      if (!org?.patToken) {
        return res.json({
          success: true,
          resolved: false,
          reason: "org_not_configured",
          message: "No PAT token found for this organization."
        });
      }

      const pat = safeDecryptPAT(org.patToken);
      if (!pat) {
        return res.json({
          success: true,
          resolved: false,
          reason: "encryption_error",
          message: "Unable to decrypt PAT token."
        });
      }

      const adoService = new AzureDevOpsService({
        organization: orgName,
        project: projectName,
        pat
      });

      const resolvedIdentity = await adoService.resolveIdentity(assigneeName);

      if (resolvedIdentity) {
        res.json({
          success: true,
          resolved: true,
          identity: {
            displayName: resolvedIdentity.displayName,
            uniqueName: resolvedIdentity.uniqueName,
            mailAddress: resolvedIdentity.mailAddress
          }
        });
      } else {
        res.json({
          success: true,
          resolved: false,
          reason: "not_found",
          message: `Could not find a matching user for "${assigneeName}"`
        });
      }
    } catch (error) {
      res.status(500).json({
        success: false,
        resolved: false,
        reason: "server_error",
        message: error instanceof Error ? error.message : String(error)
      });
    }
  });

  // Create work item in ADO from Story Agent
  app.post("/api/ado/create-work-item", async (req: Request, res: Response) => {
    try {
      const {
        organizationUrl,
        projectName,
        title,
        description,
        acceptanceCriteria,
        priority,
        storyPoints,
        assigneeAction,
        assigneeQuery,
        assigneeResolved,
        userStory,
        testCases
      } = req.body;// Validation
      if (!organizationUrl || !projectName || !title) {
        return res.status(400).json({
          success: false,
          error: "Missing required fields",
          details: "organizationUrl, projectName, and title are required"
        });
      }

      // Extract org name from URL
      const orgName = organizationUrl.replace(/https?:\/\/dev\.azure\.com\//, "").replace(/\/$/, "");

      // Helper to normalize URLs for comparison
      const normalizeUrl = (url: string): string => {
        if (!url) return "";
        return url.toLowerCase().replace(/\/$/, "").replace(/https?:\/\//, "");
      };

      // ===== GET PAT TOKEN =====
      const artifactOrgs = await storage.getArtifactOrganizations();
      const normalizedRequestUrl = normalizeUrl(organizationUrl);// Find matching organization by URL (normalized comparison)
      const org = artifactOrgs.find(o => {
        const normalizedOrgUrl = normalizeUrl(o.organizationUrl || "");
        const matches = normalizedOrgUrl === normalizedRequestUrl ||
          normalizedOrgUrl.includes(orgName.toLowerCase()) ||
          orgName.toLowerCase().includes(normalizedOrgUrl.split("/").pop() || ""); return matches;
      }); if (!org?.patToken) {
        return res.status(400).json({
          success: false,
          error: "Organization not configured",
          details: "No PAT token found for this organization. Please configure Azure DevOps in Settings."
        });
      }

      // Decrypt the PAT token
      const pat = safeDecryptPAT(org.patToken);
      if (!pat) {
        return res.status(500).json({
          success: false,
          error: "Encryption error",
          details: "Unable to decrypt PAT token. Please reconfigure the organization."
        });
      }
      // ===== END PAT TOKEN RETRIEVAL =====

      // Create ADO service with the decrypted PAT
      const adoService = new AzureDevOpsService({
        organization: orgName,
        project: projectName,
        pat  // Now this is defined!
      });

      // Format acceptance criteria as HTML for proper ADO display
      let acHtml = "";
      if (Array.isArray(acceptanceCriteria) && acceptanceCriteria.length > 0) {
        acHtml = "<ol>" + acceptanceCriteria.map(c => `<li>${c}</li>`).join("") + "</ol>";
      } else if (typeof acceptanceCriteria === "string" && acceptanceCriteria.trim()) {
        // Handle string input - split by newlines or numbered items and format as HTML list
        const lines = acceptanceCriteria
          .split(/\n|(?=\d+\.\s)/)
          .map(line => line.replace(/^\d+\.\s*/, '').trim())
          .filter(line => line.length > 0);
        if (lines.length > 0) {
          acHtml = "<ol>" + lines.map(c => `<li>${c}</li>`).join("") + "</ol>";
        }
      }

      // Build description as HTML for proper ADO display
      let fullDescriptionHtml = "";
      if (userStory) {
        fullDescriptionHtml = `<p><strong>User Story:</strong> ${userStory}</p>`;
      }
      if (description) {
        // Convert newlines in description to HTML paragraphs/line breaks
        const descParagraphs = description.split(/\n\n+/).map((p: string) => p.trim()).filter((p: string) => p);
        if (descParagraphs.length > 0) {
          fullDescriptionHtml += descParagraphs.map((p: string) => `<p>${p.replace(/\n/g, '<br/>')}</p>`).join("");
        }
      }

      // Convert priority string to number
      let priorityNum = 2;
      if (typeof priority === "string") {
        const p = priority.toLowerCase();
        if (p === "critical" || p === "highest" || p === "high") priorityNum = 1;
        else if (p === "medium") priorityNum = 2;
        else if (p === "low") priorityNum = 3;
        else if (p === "lowest") priorityNum = 4;
      } else if (typeof priority === "number") {
        priorityNum = priority;
      }

      // Determine final assignee based on action
      let finalAssignee: string | undefined;
      const action = assigneeAction || "leave_unassigned"; if (action === "leave_unassigned") {
        finalAssignee = undefined;
      } else if (action === "assign_resolved" && assigneeResolved?.uniqueName) {
        finalAssignee = assigneeResolved.uniqueName;
      } else if (action === "assign_manual" && assigneeQuery) {
        const resolvedIdentity = await adoService.resolveIdentity(assigneeQuery);
        finalAssignee = resolvedIdentity?.uniqueName;
      }

      // Create the work item
      const workItem = await adoService.createWorkItemFromChat(
        "User Story",
        title,
        fullDescriptionHtml,
        acHtml,
        finalAssignee,
        storyPoints,
        priorityNum
      );

      const workItemUrl = `${organizationUrl}/${projectName}/_workitems/edit/${workItem.id}`;

      // Create Test Cases if provided - with validation and sanitization
      let testCaseResult: { created: number; ids: number[]; errors?: string[] } = { created: 0, ids: [] };

      if (testCases && Array.isArray(testCases)) {
        // Sanitize: filter to only valid non-empty strings
        const validTestCases = testCases
          .filter((tc): tc is string => typeof tc === "string" && tc.trim().length > 0)
          .map(tc => tc.trim());

        if (validTestCases.length > 0) {
          try {
            const result = await adoService.createTestCasesForStory(validTestCases, workItem.id, title);
            testCaseResult = {
              created: result.testCaseIds.length,
              ids: result.testCaseIds,
              errors: result.errors.length > 0 ? result.errors : undefined
            }; if (testCaseResult.errors) {
              console.warn(`[API] ${testCaseResult.errors.length} test cases failed to create:`, testCaseResult.errors);
            }
          } catch (tcError) {
            console.error("[API] Error creating test cases:", tcError);
            testCaseResult = { created: 0, ids: [], errors: [String(tcError)] };
          }
        }
      }

      res.json({
        success: true,
        workItemId: workItem.id,
        workItemUrl,
        title: workItem.fields?.["System.Title"],
        assignedTo: workItem.fields?.["System.AssignedTo"]?.displayName || null,
        message: `User Story #${workItem.id} created successfully`,
        testCases: testCaseResult
      });
    } catch (error) {
      console.error("[API] Error creating work item:", error);
      res.status(500).json({
        success: false,
        error: "Failed to create work item",
        details: error instanceof Error ? error.message : String(error)
      });
    }
  });

  // Super Agent Chat Endpoint
  app.post("/api/super-agent/chat", async (req: Request, res: Response) => {
    const { sessionId, message, conversationId, summary, projectId, projectName } = req.body as {
      sessionId: string;
      message: string;
      conversationId?: string | null;
      summary?: string | null;
      projectId?: string | null;
      projectName?: string | null;
    };

    const superAgent = getOrCreateSuperAgent(sessionId);
    const userId = (req as any).user?.id;
    superAgent.updateContext({
      userId: typeof userId === "string" ? userId : undefined,
    });
    if (typeof projectId === "string" && projectId.trim()) {
      // Map the incoming projectId (often an ADO project GUID from the SDLC page)
      // to the DevX SDLC project uuid (sdlc_projects.id) so JiraAgent/getJiraConfig
      // can resolve project-scoped configuration.
      try {
        const [sdlcProject] = await db
          .select({
            id: schema.sdlcProjects.id,
            name: schema.sdlcProjects.name,
          })
          .from(schema.sdlcProjects)
          .where(
            or(
              eq(schema.sdlcProjects.id, projectId),
              eq(schema.sdlcProjects.projectId, projectId),
            ),
          )
          .limit(1);

        if (sdlcProject?.id) {
          superAgent.setSelectedProject({
            id: sdlcProject.id,
            name: sdlcProject.name || "Selected project",
          });
        } else {
          superAgent.setSelectedProject({
            id: projectId,
            name:
              typeof projectName === "string" && projectName.trim()
                ? projectName
                : "Selected project",
          });
        }
      } catch (e) {
        superAgent.setSelectedProject({
          id: projectId,
          name:
            typeof projectName === "string" && projectName.trim()
              ? projectName
              : "Selected project",
        });
      }
    }
    const resolvedProjectId = superAgent.getContext().selectedProject?.id || (req.body as any).projectId || "00000000-0000-0000-0000-000000000000";

    // Track AI Bot query start — standalone Super-Agent chat screen (feature='bot').
    const { metricId, startTime } = await trackEventStart({
      artifactId: sessionId,
      useCase: "AI Bot Queries",
      userId,
      projectId: resolvedProjectId,
      feature: "bot",
    });

    try {
      const response = await superAgent.chat({
        message,
        conversationId: conversationId ?? undefined,
        summary: typeof summary === "string" ? summary : undefined,
      });

      // Track successful completion
      await trackEventSuccess(metricId, startTime, WORKFLOW_CONVERSATION_TOKEN_COST);
      res.json(response);
    } catch (error) {
      // Track failure
      await trackEventFailure(metricId, startTime);
      console.error("[Super Agent] Chat error:", error);
      res.status(500).json({ error: "Failed to process chat query" });
    }
  });


