  // ===========================================================================
  // Create and return HTTP server
  // Created for Conversation UI History feature to access server instance -- Sri hari
  // ==========================================================================

  // ------------------------------------------------------------------------
  // 1) GET /api/conversations/titles
  //    Load all conversation titles for a user (history sidebar)
  //    Query: ?userId=u_001
  // ------------------------------------------------------------------------


  app.get("/api/conversations/titles", async (req: Request, res: Response) => {
    try {
      const userId = req.query.userId as string | undefined;

      if (!userId) {
        return res.status(400).json({ error: "userId is required" });
      }

      const titles = await db
        .select({
          conversationId: schema.conversationTitles.conversationId,
          title: schema.conversationTitles.title,
          createdAt: schema.conversationTitles.createdAt,
          updatedAt: schema.conversationTitles.updatedAt,
        })
        .from(schema.conversationTitles)
        .where(eq(schema.conversationTitles.userId, userId))
        .orderBy(desc(schema.conversationTitles.updatedAt));

      return res.json({ conversations: titles });
    } catch (error) {
      console.error("[GET /api/conversations/titles] Error:", error);
      const msg =
        error instanceof Error ? error.message : "Failed to load titles";
      return res.status(500).json({
        error: "Failed to load conversation titles",
        details: msg,
      });
    }
  });

  // ------------------------------------------------------------------------
  // 2) POST /api/conversations
  //    Create a new conversation (ConversationTitles owner + empty summary)
  //    Body: { userId: string, firstMessage: string }
  // ------------------------------------------------------------------------
  app.post("/api/conversations", async (req: Request, res: Response) => {
    try {
      const { userId, firstMessage } = req.body as {
        userId?: string;
        firstMessage?: string;
      };

      if (!userId || !firstMessage) {
        return res.status(400).json({
          error: "Missing required fields",
          details: "userId and firstMessage are required",
        });
      }

      const conversationId = crypto.randomUUID();
      const now = unixNow();

      // Create conversation immediately with a temporary title
      const tempTitle = fallbackTitle(firstMessage);

      // 1) Insert into ConversationTitles (owner) with temporary title
      await db.insert(schema.conversationTitles).values({
        conversationId,
        userId,
        title: tempTitle,
        createdAt: now,
        updatedAt: now,
      });

      // 2) Create empty summary row
      await db.insert(schema.conversationSummaries).values({
        conversationId,
        summary: null,
        createdAt: now,
        updatedAt: now,
      });

      // 3) Start background job to generate proper title with LLM
      const jobId = randomUUID();
      const job: ConversationTitleJob = {
        jobId,
        conversationId,
        status: "pending",
        progress: 0,
        step: "Queued",
        createdAt: new Date(),
      };
      conversationTitleJobs.set(jobId, job);

      // Return immediately with conversation info
      res.status(201).json({
        conversationId,
        title: tempTitle,
        titleJobId: jobId,
        message: "Conversation created. Title is being generated by AI and will be updated shortly."
      });

      // Background processing for title generation
      (async () => {
        try {
          job.status = "processing";
          job.step = "Generating AI title...";
          job.progress = 25;

          const aiTitle = await generateConversationTitleWithLLM(firstMessage);

          job.step = "Updating conversation title...";
          job.progress = 75;

          // Update the title in the database
          await db.update(schema.conversationTitles)
            .set({
              title: aiTitle,
              updatedAt: unixNow(),
            })
            .where(eq(schema.conversationTitles.conversationId, conversationId));

          job.status = "completed";
          job.step = "Completed";
          job.progress = 100;
          job.completedAt = new Date();
          job.result = {
            title: aiTitle,
          };
        } catch (err: any) {
          console.error("[ConversationTitle] Error generating title for", conversationId, ":", err);
          job.status = "failed";
          job.error =
            err instanceof Error ? err.message : "Unknown error during title generation";
          job.step = "Failed";
          job.completedAt = new Date();
          // Keep the fallback title in the database - don't update on failure
        }
      })();
    } catch (err: any) {
      console.error("[POST /api/conversations] error:", err);
      return res.status(500).json({
        error: "Failed to create conversation",
        details: err?.message ?? String(err),
      });
    }
  });

  // Poll conversation title generation job status
  app.get("/api/conversations/title-job/:jobId", async (req: Request, res: Response) => {
    const { jobId } = req.params;
    const job = conversationTitleJobs.get(jobId);

    if (!job) {
      return res.status(404).json({
        error: "Conversation title job not found",
        jobId,
      });
    }

    res.json({
      jobId: job.jobId,
      conversationId: job.conversationId,
      status: job.status,
      progress: job.progress,
      step: job.step,
      result: job.result,
      error: job.error,
      createdAt: job.createdAt,
      completedAt: job.completedAt,
    });
  });

  // ------------------------------------------------------------------------
  // 3) GET /api/conversations/:id/messages
  //    Load all messages for a conversation (for main chat view)
  //    Optional query: ?limit=50
  // ------------------------------------------------------------------------
  app.get(
    "/api/conversations/:id/messages",
    async (req: Request, res: Response) => {
      try {
        const conversationId = req.params.id;
        const limitParam = req.query.limit as string | undefined;
        const limit = limitParam ? Number(limitParam) : undefined;

        if (!conversationId) {
          return res
            .status(400)
            .json({ error: "conversationId parameter is required" });
        }

        // Base query
        const baseQuery = db
          .select({
            id: schema.messages.id,
            role: schema.messages.role,
            content: schema.messages.content,
            createdAt: schema.messages.createdAt,
            isSummarised: schema.messages.isSummarised,
          })
          .from(schema.messages)
          .where(eq(schema.messages.conversationId, conversationId))
          .orderBy(schema.messages.createdAt);

        // Apply limit only if valid
        const rows = await (
          limit && !Number.isNaN(limit)
            ? baseQuery.limit(limit)
            : baseQuery
        );

        return res.json({ messages: rows });
      } catch (error) {
        console.error("[GET /api/conversations/:id/messages] Error:", error);
        const msg =
          error instanceof Error ? error.message : "Failed to load messages";
        return res.status(500).json({
          error: "Failed to load messages",
          details: msg,
        });
      }
    },
  );

  // ------------------------------------------------------------------------
  // 4) POST /api/conversations/:id/messages
  //    Append a message (user/assistant/system) into Messages table
  //    Body: { role: 'user' | 'assistant' | 'system', content: string }
  // ------------------------------------------------------------------------
  // ------------------------------------------------------------------------
  // 4) POST /api/conversations/:id/messages
  //    Body: { role: 'user' | 'assistant' | 'system', content: string }
  // ------------------------------------------------------------------------
  app.post(
    "/api/conversations/:id/messages",
    async (req: Request, res: Response) => {
      try {
        const conversationId = req.params.id;
        const { role, content } = req.body as {
          role: "user" | "assistant" | "system";
          content: string;
        };

        if (!conversationId) {
          return res
            .status(400)
            .json({ error: "conversationId parameter is required" });
        }
        if (!role || !content) {
          return res
            .status(400)
            .json({ error: "role and content are required" });
        }

        const now = unixNow();
        const id = crypto.randomUUID(); // we generate the PK ourselves

        await db.insert(schema.messages).values({
          id,
          conversationId,
          role,
          content,
          createdAt: now,
          isSummarised: false,
        });

        // Update ConversationSummary.updatedAt
        await db
          .update(schema.conversationSummaries)
          .set({ updatedAt: now })
          .where(eq(schema.conversationSummaries.conversationId, conversationId));

        // Also keep ConversationTitles.updatedAt in sync
        await db
          .update(schema.conversationTitles)
          .set({ updatedAt: now })
          .where(eq(schema.conversationTitles.conversationId, conversationId));

        // NEW: try to summarise when we have at least 10 unsummarised messages
        await summariseConversation(conversationId, {
          force: false,   // only when >= batchSize unsummarised
          batchSize: 10,  // your "last 10 messages" rule
        });

        // Manually return the inserted row shape
        return res.status(201).json({
          message: {
            id,
            role,
            content,
            createdAt: now,
            isSummarised: false,
          },
        });
      } catch (error) {
        console.error("[POST /api/conversations/:id/messages] Error:", error);
        const msg =
          error instanceof Error ? error.message : "Failed to save message";
        return res.status(500).json({
          error: "Failed to save message",
          details: msg,
        });
      }
    },
  );


  // ------------------------------------------------------------------------
  // 5) GET /api/conversations/:id/summary
  //    Get summary + meta for a conversation (to inject into LLM system prompt)
  //    Returns: { conversationId, title, summary, createdAt, updatedAt }
  // ------------------------------------------------------------------------
  app.get(
    "/api/conversations/:id/summary",
    async (req: Request, res: Response) => {
      try {
        const conversationId = req.params.id;

        if (!conversationId) {
          return res
            .status(400)
            .json({ error: "conversationId parameter is required" });
        }

        const rows = await db
          .select({
            conversationId: schema.conversationSummaries.conversationId,
            title: schema.conversationTitles.title,
            summary: schema.conversationSummaries.summary,
            createdAt: schema.conversationSummaries.createdAt,
            updatedAt: schema.conversationSummaries.updatedAt,
          })
          .from(schema.conversationSummaries)
          .leftJoin(
            schema.conversationTitles,
            eq(
              schema.conversationSummaries.conversationId,
              schema.conversationTitles.conversationId,
            ),
          )
          .where(
            eq(schema.conversationSummaries.conversationId, conversationId),
          )
          .limit(1);

        if (rows.length === 0) {
          return res.status(404).json({ error: "Conversation not found" });
        }

        return res.json({ conversation: rows[0] });
      } catch (error) {
        console.error("[GET /api/conversations/:id/summary] Error:", error);
        const msg =
          error instanceof Error
            ? error.message
            : "Failed to load conversation summary";
        return res.status(500).json({
          error: "Failed to load conversation summary",
          details: msg,
        });
      }
    },
  );

