  // [RAG ORCHESTRATOR] Production-Grade RAG Pipeline
  // ============================================================================
  // ragOrchestrator is initialized above with BRD routes for BRD-generation RAG support

  // POST /api/rag/process-dynamic - Dynamic RAG processing endpoint that can be used anywhere
  app.post("/api/rag/process-dynamic", async (req: Request, res: Response) => {
    try {
      const { content, guidelines, sessionId, query, requirementIds, projectId } = req.body;

      // Validate projectId for caching
      if (!projectId || typeof projectId !== 'string') {
        return res.status(400).json({
          error: "projectId is required for optimized RAG processing"
        });
      }

      // Validate that at least one input is provided (content OR query)
      const hasContent = content && typeof content === 'string' && content.trim().length > 0;
      const hasQuery = query && typeof query === 'string' && query.trim().length > 0;

      if (!hasContent && !hasQuery) {
        return res.status(400).json({
          error: "At least one input is required: 'content' (BRD requirements) OR 'query' (user question) OR both"
        });
      }

      if (!guidelines || !Array.isArray(guidelines) || guidelines.length === 0) {
        return res.status(400).json({
          error: "Guidelines array is required for RAG processing"
        });
      }

      const ragSessionId = randomUUID(); // Always generate new unique session ID

      // Build dynamic content and query based on what's provided
      let finalContent = '';
      let finalQuery = '';

      if (hasContent && hasQuery) {
        // Case 1: Both BRD requirements and user query provided
        finalContent = content;
        finalQuery = `User Question: ${query}\n\nBased on the provided business requirements and this specific question, provide comprehensive guidance for generating high-quality epics, features, and user stories.`;
      } else if (hasContent) {
        // Case 2: Only BRD requirements provided
        finalContent = content;
        finalQuery = "Analyze these business requirements and provide comprehensive guidance for generating high-quality epics, features, and user stories. Focus on compliance requirements, best practices, and any specific organizational guidelines that should be incorporated.";
      } else if (hasQuery) {
        // Case 3: Only user query provided
        finalContent = `General Business Context: The user has asked a specific question about agile artifact generation. Please provide guidance based on organizational guidelines and best practices.\n\nUser Query: ${query}`;
        finalQuery = "Based on the user's question and organizational guidelines, provide comprehensive guidance for generating high-quality epics, features, and user stories. Focus on best practices and compliance requirements.";
      }

      // Prepare guideline documents for orchestrator
      const guidelineDocuments: Record<string, string> = {};

      for (const guideline of guidelines) {
        guidelineDocuments[guideline.name] = guideline.content;
      }

      // Run RAG orchestration with dynamically built content and query (optimized version)
      const response = await ragOrchestrator.processBrdWithGuidelines(
        ragSessionId,
        finalContent,
        guidelineDocuments,
        projectId, // Now includes projectId for caching
        finalQuery
      );

      // Add metadata about the processing mode
      const enhancedResponse = {
        ...response,
        processingMode: hasContent && hasQuery ? 'content_and_query' : hasContent ? 'content_only' : 'query_only',
        ...(requirementIds && Array.isArray(requirementIds) && {
          requirementIds: requirementIds,
          processedRequirementsCount: requirementIds.length
        })
      };

      return res.json(enhancedResponse);

    } catch (error) {
      console.error("[POST /api/rag/process-dynamic] Error:", error);
      const msg = error instanceof Error ? error.message : "Failed to process dynamic RAG pipeline";
      return res.status(500).json({
        error: "Failed to process dynamic RAG pipeline",
        details: msg
      });
    }
  });

