  // POST /api/requirements/fetch-content - Get requirements content by IDs for RAG processing
  app.post("/api/requirements/fetch-content", async (req: Request, res: Response) => {
    try {
      const { requirementIds } = req.body;

      if (!requirementIds || !Array.isArray(requirementIds) || requirementIds.length === 0) {
        return res.status(400).json({
          error: "requirementIds array is required"
        });
      }

      // Fetch requirements from devBrdRequirements table
      const requirements = await db
        .select({
          id: schema.devBrdRequirements.id,
          name: schema.devBrdRequirements.requirementName,
          description: schema.devBrdRequirements.description,
          priority: schema.devBrdRequirements.priority,
          status: schema.devBrdRequirements.status,
          projectId: schema.devBrdRequirements.projectId,
          brdTitle: schema.devBrdDocuments.title
        })
        .from(schema.devBrdRequirements)
        .leftJoin(
          schema.devBrdDocuments,
          eq(schema.devBrdRequirements.brdId, schema.devBrdDocuments.id)
        )
        .where(inArray(schema.devBrdRequirements.id, requirementIds));

      if (requirements.length === 0) {
        return res.status(404).json({
          error: "No requirements found in devBrdRequirements table",
          requirementIds: requirementIds,
          searchedIn: "devBrdRequirements table"
        });
      }

      // Create structured content for each requirement
      const requirementsContent = requirements.map(req => ({
        id: req.id,
        name: req.name,
        description: req.description,
        priority: req.priority,
        status: req.status,
        brdTitle: req.brdTitle,
        projectId: req.projectId,
        content: `## Requirement: ${req.name}\n\n**ID:** ${req.id}\n\n**Description:** ${req.description}\n\n**Priority:** ${req.priority}\n\n**Status:** ${req.status}\n\n**Source BRD:** ${req.brdTitle}\n\n**Project ID:** ${req.projectId}\n\n---\n\n`
      }));

      // Combined content string for RAG processing
      const combinedContent = requirementsContent.map(req => req.content).join('\n');

      return res.json({
        success: true,
        requirements: requirementsContent,
        combinedContent: combinedContent,
        count: requirements.length,
        requirementIds: requirementIds
      });

    } catch (error) {
      console.error("[POST /api/requirements/fetch-content] Error:", error);
      const msg = error instanceof Error ? error.message : "Failed to fetch requirements content";
      return res.status(500).json({
        error: "Failed to fetch requirements content",
        details: msg
      });
    }
  });

