  /**
   * Generate manual test cases (async with polling)
   */
  app.post("/api/manual-test-cases/generate", requireActivity("SDLC_TEST_CREATE"), async (req: Request, res: Response) => {
    const { userStory, projectId, testCaseTypes } = req.body;

    if (!userStory || !projectId) {
      return res.status(400).json({
        error: "Missing required parameters: userStory, projectId",
      });
    }

    try {
      const { jobManager } = await import("./services/test-generation-job-manager");

      // Create job
      const jobId = jobManager.createJob(userStory, testCaseTypes, projectId);

      // Start processing in background (don't await - let it run async)
      jobManager.processJob(jobId).catch(error => {
        console.error(`[API] Background job ${jobId} failed:`, error);
      });

      return res.json({
        success: true,
        jobId,
        message: "Test generation started. Poll for status using the jobId.",
      });
    } catch (error) {
      console.error("[API] Error starting test generation job:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to start test generation job",
        details: msg,
      });
    }
  });

