  /**
   * Generate specs.md and requirements.md for selected Features & User Stories using Azure OpenAI.
   *
   * The client sends an array of "features", each containing its selected user stories.
   * We treat each feature as a separate "chunk" and generate two markdown files per feature:
   * - specs.md          (full specification)
   * - requirements.md   (requirements quality checklist)
   *
   * The templates in server/specs_format/spec.md and
   * server/specs_format/checklists/requirements.md are used as structural guides.
   */
  app.post(
    "/api/sdlc/projects/:projectId/specs/generate-from-backlog",
    // requireActivity("SDLC_SPECS_CREATE"), // TODO: Re-enable after setting up activities
    async (req: Request, res: Response) => {
      try {
        const { projectId } = req.params;
        const { features } = req.body as {
          features?: Array<{
            id: number;
            title: string;
            state?: string;
            description?: string;
            userStories?: Array<{
              id: number;
              title: string;
              state?: string;
              description?: string;
              acceptanceCriteria?: string;
              storyPoints?: number | null;
            }>;
          }>;
        };

        if (!projectId) {
          return res
            .status(400)
            .json({ error: "projectId is required in route params" });
        }

        if (!Array.isArray(features) || features.length === 0) {
          return res.status(400).json({
            error:
              "No features provided. Please send a non-empty 'features' array.",
          });
        }

        const { SpecsGenerator } = await import("./services/specs-generator");
        const generator = new SpecsGenerator();

        const normalizedFeatures = features.map((f) => ({
          id: Number(f.id),
          title: String(f.title || `Feature ${f.id}`),
          state: f.state,
          description: f.description,
          userStories: (f.userStories || []).map((s) => ({
            id: Number(s.id),
            title: String(s.title || `User Story ${s.id}`),
            state: s.state,
            description: s.description,
            acceptanceCriteria: s.acceptanceCriteria,
            storyPoints:
              typeof s.storyPoints === "number" ? s.storyPoints : null,
          })),
        }));

        const results = await generator.generateForFeatures(
          normalizedFeatures
        );

        // Persist generated files to database so they can be restored later
        try {
          const rows = results.flatMap((r) => {
            const featureTitle = r.featureTitle || `Feature ${r.featureId}`;
            const baseSlug = featureTitle
              .toLowerCase()
              .replace(/[^a-z0-9]+/g, "-")
              .replace(/^-+|-+$/g, "") || `feature-${r.featureId}`;
            const basePath = `specs/${baseSlug}`;

            return [
              {
                projectId,
                featureId: r.featureId,
                featureTitle,
                fileType: "specs",
                fileName: "specs.md",
                path: `${basePath}/specs.md`,
                content: r.specsContent,
              },
              {
                projectId,
                featureId: r.featureId,
                featureTitle,
                fileType: "requirements",
                fileName: "requirements.md",
                path: `${basePath}/requirements.md`,
                content: r.requirementsContent,
              },
            ];
          });

          if (rows.length > 0) {
            console.log("[DEBUG GENERATION] Attempting to save", rows.length, "files to database");
            console.log("[DEBUG GENERATION] Sample row:", rows[0]);
            await db.insert(schema.sdlcSpecsFiles).values(rows);
            console.log("[DEBUG GENERATION] Successfully saved files to database");
          } else {
            console.log("[DEBUG GENERATION] No rows to save");
          }
        } catch (dbError) {
          console.error(
            "[SDLC Specs] Failed to persist generated specs to database:",
            dbError
          );
          // Don't fail the whole request if persistence fails
        }

        return res.json({
          projectId,
          totalFeatures: results.length,
          files: results.map((r) => ({
            featureId: r.featureId,
            featureTitle: r.featureTitle,
            specsContent: r.specsContent,
            requirementsContent: r.requirementsContent,
          })),
        });
      } catch (error: any) {
        console.error(
          "[SDLC Specs] Failed to generate specs from backlog:",
          error
        );
        const message =
          error?.message ||
          "Failed to generate specs and requirements from selected features.";
        return res.status(500).json({ error: message });
      }
    }
  );

  // Async (job-based) specs generation with polling, chunked per feature
  app.post(
    "/api/sdlc/projects/:projectId/specs/generate-from-backlog/async",
    // requireActivity("SDLC_SPECS_CREATE"), // TODO: Re-enable after setting up activities
    async (req: Request, res: Response) => {
      try {
        const { projectId } = req.params;
        const { features, enableTdd } = req.body as {
          features?: Array<{
            id: number;
            title: string;
            state?: string;
            description?: string;
            userStories?: Array<{
              id: number;
              title: string;
              state?: string;
              description?: string;
              acceptanceCriteria?: string;
              storyPoints?: number | null;
            }>;
          }>;
          enableTdd?: boolean;
        };

        if (!projectId) {
          return res
            .status(400)
            .json({ error: "projectId is required in route params" });
        }

        if (!Array.isArray(features) || features.length === 0) {
          return res.status(400).json({
            error:
              "No features provided. Please send a non-empty 'features' array.",
          });
        }

        const normalizedFeatures = features.map((f) => ({
          id: Number(f.id),
          title: String(f.title || `Feature ${f.id}`),
          state: f.state,
          description: f.description,
          userStories: (f.userStories || []).map((s) => ({
            id: Number(s.id),
            title: String(s.title || `User Story ${s.id}`),
            state: s.state,
            description: s.description,
            acceptanceCriteria: s.acceptanceCriteria,
            storyPoints:
              typeof s.storyPoints === "number" ? s.storyPoints : null,
          })),
        }));

        const jobId = randomUUID();
        // NOTE: SpecsGenerationJob, specsGenerationJobs, specsJobQueue, processSpecsQueue
        // live in ./routes/specs and are registered via registerSpecsRoutes(app).
        // This duplicate handler is shadowed by that registration, but kept for now;
        // typed as any to satisfy the compiler without changing behavior.
        const SpecsGenerationJob = {} as any;
        const specsGenerationJobs = (globalThis as any).__specsGenerationJobs ?? ((globalThis as any).__specsGenerationJobs = new Map<string, any>());
        const specsJobQueue = (globalThis as any).__specsJobQueue ?? ((globalThis as any).__specsJobQueue = [] as any[]);
        const processSpecsQueue: () => Promise<void> = (globalThis as any).__processSpecsQueue ?? (async () => {});
        void SpecsGenerationJob;
        const job: any = {
          jobId,
          projectId,
          status: "pending",
          progress: 0,
          step: "Queued...",
          createdAt: new Date(),
          result: {
            totalFeatures: normalizedFeatures.length,
            processedFeatures: 0,
            files: [],
          },
        };

        specsGenerationJobs.set(jobId, job);

        // Persist TDD preference at project level
        if (enableTdd !== undefined) {
          try {
            await db
              .update(schema.sdlcProjects)
              .set({ enableTdd: !!enableTdd })
              .where(eq(schema.sdlcProjects.id, projectId));
          } catch (tddErr) {
            console.error(
              "[SDLC Specs] Failed to persist TDD preference:",
              tddErr
            );
          }
        }

        // Enqueue into unified in-process queue (A, B, ... all go through here)
        specsJobQueue.push({
          jobId,
          projectId,
          enableTdd: !!enableTdd,
          features: normalizedFeatures,
        });
        void processSpecsQueue();

        res.json({
          success: true,
          jobId,
          status: job.status,
          message:
            "Specs generation started. Use /api/sdlc/specs/generate/status/:jobId to poll for results.",
        });
      } catch (error: any) {
        console.error(
          "[SDLC Specs] Failed to start async specs generation from backlog:",
          error
        );
        const message =
          error?.message ||
          "Failed to start async specs and requirements generation from selected features.";
        return res.status(500).json({ error: message });
      }
    }
  );

  // Polling endpoint for specs generation status
  app.get(
    "/api/sdlc/specs/generate/status/:jobId",
    // requireActivity("SDLC_SPECS_VIEW"), // TODO: Re-enable after setting up activities
    async (req: Request, res: Response) => {
      try {
        const { jobId } = req.params;
        const specsGenerationJobs = (globalThis as any).__specsGenerationJobs ?? ((globalThis as any).__specsGenerationJobs = new Map<string, any>());
        const job: any = specsGenerationJobs.get(jobId);

        if (!job) {
          console.error(
            `[SDLC Specs][Job] Status request for non-existent job: ${jobId}`
          );
          return res.status(404).json({ error: "Job not found", jobId });
        }

        if (job.status === "failed") {
          const errorMessage =
            job.error ||
            "Specs generation failed for selected features from backlog.";
          console.error(`[SDLC Specs][Job] Job ${jobId} failed: ${errorMessage}`);
          return res.status(500).json({
            jobId: job.jobId,
            projectId: job.projectId,
            status: job.status,
            progress: job.progress,
            step: job.step,
            createdAt: job.createdAt.toISOString(),
            completedAt: job.completedAt?.toISOString(),
            result: job.result,
            error: errorMessage,
          });
        }

        return res.json({
          jobId: job.jobId,
          projectId: job.projectId,
          status: job.status,
          progress: job.progress,
          step: job.step,
          createdAt: job.createdAt.toISOString(),
          completedAt: job.completedAt?.toISOString(),
          result: job.result,
          error: job.error,
        });
      } catch (error: any) {
        console.error(
          `[SDLC Specs][Job] Error getting job status for jobId ${req.params.jobId}:`,
          error
        );
        res.status(500).json({
          error: "Failed to get specs generation job status",
          details: error instanceof Error ? error.message : String(error),
        });
      }
    }
  );

  /**
   * Fetch previously generated specs/requirements files for an SDLC project.
   * Used to rebuild the file tree and "Generated" indicators.
   */
  app.get(
    "/api/sdlc/projects/:projectId/specs/files",
    async (req: Request, res: Response) => {
      try {
        const { projectId } = req.params;
        if (!projectId) {
          return res
            .status(400)
            .json({ error: "projectId is required in route params" });
        }

        const [rows, projectRows] = await Promise.all([
          db
            .select()
            .from(schema.sdlcSpecsFiles)
            .where(eq(schema.sdlcSpecsFiles.projectId, projectId)),
          db
            .select({ enableTdd: schema.sdlcProjects.enableTdd })
            .from(schema.sdlcProjects)
            .where(eq(schema.sdlcProjects.id, projectId))
            .limit(1),
        ]);

        return res.json({
          projectId,
          files: rows,
          enableTdd: projectRows[0]?.enableTdd ?? false,
        });
      } catch (error: any) {
        console.error(
          "[SDLC Specs] Failed to load specs files from database:",
          error
        );
        const message =
          error?.message || "Failed to load generated specs and requirements.";
        return res.status(500).json({ error: message });
      }
    }
  );

  /**
   * Download all generated specs/requirements for a project as a ZIP archive.
   * Preserves the logical folder structure defined by sdlc_specs_files.path.
   */
  app.get(
    "/api/sdlc/projects/:projectId/specs/export-zip",
    async (req: Request, res: Response) => {
      try {
        const { projectId } = req.params;
        if (!projectId) {
          return res
            .status(400)
            .json({ error: "projectId is required in route params" });
        }

        const files = await db
          .select({
            path: schema.sdlcSpecsFiles.path,
            content: schema.sdlcSpecsFiles.content,
          })
          .from(schema.sdlcSpecsFiles)
          .where(eq(schema.sdlcSpecsFiles.projectId, projectId));

        if (!files.length) {
          return res.status(404).json({
            error:
              "No generated specs or requirements were found for this project.",
          });
        }

        const { default: archiver } = await import("archiver");

        const safeProjectId = String(projectId).replace(
          /[^a-zA-Z0-9_-]/g,
          "_"
        );
        const zipFilename = `specs-${safeProjectId}.zip`;

        res.setHeader("Content-Type", "application/zip");
        res.setHeader(
          "Content-Disposition",
          `attachment; filename="${zipFilename}"`
        );

        const archive = archiver("zip", {
          zlib: { level: 9 },
        });

        archive.on("error", (err: Error) => {
          console.error("[SDLC Specs] ZIP archive error:", err);
          try {
            if (!res.headersSent) {
              res
                .status(500)
                .json({ error: "Failed to generate specs ZIP archive." });
            } else {
              res.end();
            }
          } catch {
            // Ignore secondary errors while ending response
          }
        });

        archive.pipe(res);

        for (const file of files) {
          const relativePath =
            typeof file.path === "string" && file.path.trim().length > 0
              ? file.path
              : "specs/unnamed/spec.md";
          const content =
            typeof file.content === "string" ? file.content : "";
          archive.append(content, { name: relativePath });
        }

        await archive.finalize();
      } catch (error: any) {
        console.error(
          "[SDLC Specs] Failed to export specs ZIP archive:",
          error
        );
        if (!res.headersSent) {
          const message =
            error?.message || "Failed to export specs ZIP archive.";
          return res.status(500).json({ error: message });
        }
        res.end();
      }
    }
  );

  /**
   * AI-enhance an existing specs.md or requirements.md file for a project.
   * Returns enhanced markdown; caller is responsible for applying/saving.
   */
  app.post(
    "/api/sdlc/projects/:projectId/specs/enhance",
    async (req: Request, res: Response) => {
      try {
        const { projectId } = req.params;
        const { content, fileType } = req.body as {
          content?: string;
          fileType?: "specs" | "requirements" | string;
        };

        if (!projectId) {
          return res
            .status(400)
            .json({ error: "projectId is required in route params" });
        }

        if (!content || typeof content !== "string" || content.trim().length < 10) {
          return res.status(400).json({
            error:
              "Valid markdown content is required for enhancement (minimum length 10).",
          });
        }

        const normalizedType =
          typeof fileType === "string"
            ? fileType.toLowerCase()
            : "specs";

        const isRequirements = normalizedType === "requirements";

        const { llm } = await import("./llm-config");

        const systemPromptLines: string[] = [];
        if (isRequirements) {
          systemPromptLines.push(
            "You are an expert requirements engineer.",
            "You improve Markdown requirements quality checklists.",
            "You keep the checklist structure but improve clarity, testability, and consistency.",
            "Do not add implementation details; keep the tone concise and objective."
          );
        } else {
          systemPromptLines.push(
            "You are an expert product requirements and specification writer.",
            "You improve Markdown product specs to be clearer, more complete, and fully testable.",
            "Keep the existing headings and general layout.",
            "IMPORTANT: Preserve the metadata block at the top of the spec (# Feature:, Status:, Owner:, Last Updated:) exactly as-is — do not modify or remove it.",
            "Focus on tightening language, resolving vague statements, and making acceptance criteria explicit.",
            "Do not introduce technology-specific implementation details."
          );
        }

        const systemPrompt = systemPromptLines.join("\n");

        const userPrompt = [
          "Here is an existing Markdown document.",
          "Enhance it while preserving its structure and intent.",
          "",
          "Return ONLY the improved Markdown, no explanations.",
          "",
          "----- ORIGINAL MARKDOWN -----",
          content,
        ].join("\n");

        const response = await llm.azureOpenAI.chat.completions.create({
          model: process.env.AZURE_OPENAI_DEPLOYMENT || "gpt-4-turbo",
          messages: [
            { role: "system", content: systemPrompt },
            { role: "user", content: userPrompt },
          ],
          temperature: 0.25,
          max_tokens: 6000,
        });

        const enhanced =
          response.choices?.[0]?.message?.content?.trim() || content;

        return res.json({
          projectId,
          fileType: isRequirements ? "requirements" : "specs",
          enhancedContent: enhanced,
        });
      } catch (error: any) {
        console.error("[SDLC Specs] Failed to enhance specs content:", error);
        const message =
          error?.message || "Failed to enhance specs or requirements content.";
        return res.status(500).json({ error: message });
      }
    }
  );

  // ========== LEGACY SYNCHRONOUS ENDPOINT (backward compatibility) ==========

  // Generate test cases for review (NO GitHub save)
  app.post("/api/generate-testcases-preview", requireActivity("SDLC_TEST_CREATE"), async (req: Request, res: Response) => {
    const { userStory, projectId, testCaseTypes } = req.body;

    if (!userStory || !projectId) {
      return res.status(400).json({
        error: "Missing required parameters: userStory, projectId",
      });
    }

    try {

      // Split into core and extended types
      const coreTypes = {
        functional: testCaseTypes?.functional ?? true,
        negative: testCaseTypes?.negative ?? true,
        edgeCases: testCaseTypes?.edgeCases ?? true,
        accessibility: testCaseTypes?.accessibility ?? true,
      };

      const extendedTypes = {
        performance: testCaseTypes?.performance ?? false,
        security: testCaseTypes?.security ?? false,
        usability: testCaseTypes?.usability ?? false,
        reliability: testCaseTypes?.reliability ?? false,
      };

      const hasExtendedTypes = Object.values(extendedTypes).some(v => v);

      // BATCH 1: Generate core test cases (4 parallel)
      const { default: ManualTestCaseGenerator } = await import("./services/manual-test-case-generator");
      const generator = new ManualTestCaseGenerator();
      const testCaseResults = await generator.generateTestCasesForStories([userStory], coreTypes);

      if (!testCaseResults || testCaseResults.length === 0) {
        throw new Error("No test cases generated");
      }

      const result = testCaseResults[0];

      // Validate core categories
      const functionalTests = Array.isArray(result.functional) ? result.functional : [];
      const negativeTests = Array.isArray(result.negative) ? result.negative : [];
      const edgeCasesTests = Array.isArray(result.edgeCases) ? result.edgeCases : [];
      const accessibilityTests = Array.isArray(result.accessibility) ? result.accessibility : [];

      // Validate that SELECTED core categories have test cases
      const missingCategories = [];
      if (coreTypes.functional && functionalTests.length === 0) missingCategories.push("functional");
      if (coreTypes.negative && negativeTests.length === 0) missingCategories.push("negative");
      if (coreTypes.edgeCases && edgeCasesTests.length === 0) missingCategories.push("edgeCases");
      if (coreTypes.accessibility && accessibilityTests.length === 0) missingCategories.push("accessibility");

      if (missingCategories.length > 0) {
        console.error("[API] ❌ BATCH 1 VALIDATION FAILED: Missing categories:", missingCategories);
        throw new Error(
          `Test case generation incomplete. Missing categories: ${missingCategories.join(", ")}. ` +
          `The AI may have generated too many tests in one category. Please try again.`
        );
      }
      // BATCH 2: Generate extended test cases if selected (4 parallel)
      if (hasExtendedTypes) {
        const { ExtendedTestCaseGenerator } = await import("./services/extended-test-case-generator");
        const extendedGenerator = new ExtendedTestCaseGenerator();

        const extendedTestCases = await extendedGenerator.generateExtendedTestCases(userStory, extendedTypes);

        // Merge extended test cases into result
        if (extendedTestCases.performance) result.performance = extendedTestCases.performance;
        if (extendedTestCases.security) result.security = extendedTestCases.security;
        if (extendedTestCases.usability) result.usability = extendedTestCases.usability;
        if (extendedTestCases.reliability) result.reliability = extendedTestCases.reliability;

      }
      return res.json({
        success: true,
        testCases: result,
      });
    } catch (error) {
      console.error("[API] Error generating test cases for review:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to generate test cases for review",
        details: msg,
      });
    }
  });

  // ========== POLLING-BASED BDD GENERATION ==========

  /**
   * Generate BDD assets (Feature Files + Step Definitions) with polling
   */
  app.post("/api/bdd-assets/generate", async (req: Request, res: Response) => {
    const { testCases, userStory, testFramework } = req.body;


    if (!testCases || !userStory) {
      return res.status(400).json({
        error: "Missing required parameters: testCases, userStory",
      });
    }

    try {
      const { bddJobManager } = await import("./services/bdd-generation-job-manager");

      // Create job
      const jobId = bddJobManager.createJob(testCases, userStory, testFramework || 'playwright');

      // Start processing in background
      bddJobManager.processJob(jobId).catch(error => {
        console.error(`[API] Background BDD job ${jobId} failed:`, error);
      });

      return res.json({
        success: true,
        jobId,
        message: "BDD asset generation started. Poll for status using the jobId.",
      });
    } catch (error) {
      console.error("[API] Error starting BDD generation job:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to start BDD generation job",
        details: msg,
      });
    }
  });

  /**
   * Check BDD generation status (for polling)
   */
  app.get("/api/bdd-assets/generation-status/:jobId", async (req: Request, res: Response) => {
    const { jobId } = req.params;

    if (!jobId) {
      return res.status(400).json({
        error: "Missing jobId parameter",
      });
    }

    try {
      const { bddJobManager } = await import("./services/bdd-generation-job-manager");

      const job = bddJobManager.getJob(jobId);

      if (!job) {
        return res.status(404).json({
          error: "Job not found",
          jobId,
        });
      }

      return res.json({
        success: true,
        job: {
          id: job.id,
          status: job.status,
          progress: job.progress,
          error: job.error,
          createdAt: job.createdAt,
          updatedAt: job.updatedAt,
          completedAt: job.completedAt,
        },
      });
    } catch (error) {
      console.error("[API] Error checking BDD job status:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to check BDD job status",
        details: msg,
      });
    }
  });

  /**
   * Get BDD generation result (when completed)
   */
  app.get("/api/bdd-assets/generation-result/:jobId", async (req: Request, res: Response) => {
    const { jobId } = req.params;

    if (!jobId) {
      return res.status(400).json({
        error: "Missing jobId parameter",
      });
    }

    try {
      const { bddJobManager } = await import("./services/bdd-generation-job-manager");

      const job = bddJobManager.getJob(jobId);

      if (!job) {
        return res.status(404).json({
          error: "Job not found",
          jobId,
        });
      }

      if (job.status !== 'completed') {
        return res.status(400).json({
          error: "Job not completed yet",
          status: job.status,
          progress: job.progress,
        });
      }

      return res.json({
        success: true,
        result: job.result,
      });
    } catch (error) {
      console.error("[API] Error getting BDD job result:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to get BDD job result",
        details: msg,
      });
    }
  });

  // ========== LEGACY SYNCHRONOUS ENDPOINT (backward compatibility) ==========

  // Generate Feature Files and Step Definitions (synchronous - for backward compatibility)
  app.post("/api/generate-bdd-assets", async (req: Request, res: Response) => {
    const { testCases, userStory, testFramework } = req.body;

    if (!testCases || !userStory) {
      return res.status(400).json({
        error: "Missing required parameters: testCases, userStory",
      });
    }

    try {
      // Import generators
      const { FeatureFileGenerator } = await import("./services/feature-file-generator");
      const { StepDefinitionGenerator } = await import("./services/step-definition-generator");

      const featureGenerator = new FeatureFileGenerator();
      const stepDefGenerator = new StepDefinitionGenerator(testFramework || 'playwright');

      // Generate feature files
      const featureFiles = await featureGenerator.generateFeatureFiles(testCases, userStory);

      // Generate step definitions
      const stepDefFiles = await stepDefGenerator.generateStepDefinitions(testCases, userStory);

      return res.json({
        success: true,
        featureFiles,
        stepDefFiles,
        summary: {
          totalFeatureFiles: featureFiles.length,
          totalStepDefFiles: stepDefFiles.length,
          framework: testFramework || 'playwright'
        }
      });
    } catch (error) {
      console.error("[API] Error generating BDD assets:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to generate BDD assets",
        details: msg,
      });
    }
  });

