  // Push BDD Assets to Git (GitHub or ADO per project_git_config)
  app.post("/api/bdd-assets/push-to-git", async (req: Request, res: Response) => {
    const { featureFiles, stepDefFiles, userStory, organization, projectName, projectId } = req.body;

    if (!featureFiles || !stepDefFiles || !userStory) {
      return res.status(400).json({
        error: "Missing required parameters: featureFiles, stepDefFiles, userStory",
      });
    }
    if (!projectId) {
      return res.status(400).json({
        error: "Missing required parameter: projectId (needed to resolve Git storage)",
      });
    }

    try {
      const bddTenantId = await getTenantIdFromRequest(req);
      const storage = await getGitStorage(projectId, organization, projectName, getAzureDevOpsConfig, bddTenantId, {
        userId: (req as any).user?.id,
      });
      const { BDDAssetsManager } = await import("./services/bdd-assets-manager");
      const manager = new BDDAssetsManager();
      const structure = manager.organizeBDDAssets(featureFiles, stepDefFiles, userStory, organization, projectName, storage.provider);
      const result = await manager.pushToStorage(structure, storage);

      if (!result.success) {
        throw new Error(result.error || "Push to repository failed");
      }
      const baseUrl = storage.getBaseUrl?.() ?? "";
      return res.json({
        success: true,
        commitSha: result.commitSha,
        folderStructure: structure.rootFolder,
        repoUrl: baseUrl,
        message: "BDD assets pushed to repository successfully",
      });
    } catch (error) {
      console.error("[API] Error pushing BDD assets to Git:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to push BDD assets to repository",
        details: msg,
      });
    }
  });

  // Export BDD Assets as ZIP
  // PRODUCTION-SAFE: Cleanup guaranteed via finally block
  app.post("/api/bdd-assets/export-zip", async (req: Request, res: Response) => {
    const { featureFiles, stepDefFiles, userStory } = req.body;

    if (!featureFiles || !stepDefFiles || !userStory) {
      console.error("[API Export ZIP] Missing required parameters:", {
        hasFeatureFiles: !!featureFiles,
        hasStepDefFiles: !!stepDefFiles,
        hasUserStory: !!userStory
      });
      return res.status(400).json({
        error: "Missing required parameters: featureFiles, stepDefFiles, userStory",
      });
    }

    // Validate array structure
    if (!Array.isArray(featureFiles) || !Array.isArray(stepDefFiles)) {
      console.error("[API Export ZIP] Invalid array structure:", {
        featureFilesIsArray: Array.isArray(featureFiles),
        stepDefFilesIsArray: Array.isArray(stepDefFiles)
      });
      return res.status(400).json({
        error: "featureFiles and stepDefFiles must be arrays",
      });
    }

    // Validate file structure
    const validateFileStructure = (files: any[], type: string) => {
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        if (!file.filename || !file.content || !file.category) {
          console.error(`[API Export ZIP] Invalid ${type} file structure at index ${i}:`, {
            hasFilename: !!file.filename,
            hasContent: !!file.content,
            hasCategory: !!file.category,
            keys: Object.keys(file)
          });
          return false;
        }
      }
      return true;
    };

    if (!validateFileStructure(featureFiles, 'feature')) {
      return res.status(400).json({
        error: "Invalid feature file structure. Each file must have filename, content, and category properties.",
      });
    }

    if (!validateFileStructure(stepDefFiles, 'step definition')) {
      return res.status(400).json({
        error: "Invalid step definition file structure. Each file must have filename, content, and category properties.",
      });
    }

    let localPath: string | null = null;

    try {
      const { BDDAssetsManager } = await import("./services/bdd-assets-manager");
      const manager = new BDDAssetsManager();

      // Organize files into folder structure with organization and project
      const structure = manager.organizeBDDAssets(
        featureFiles,
        stepDefFiles,
        userStory,
        req.body.organization,
        req.body.projectName
      );

      // Create local folder structure
      localPath = await manager.createLocalFolderStructure(structure);

      // Create ZIP archive
      const zipFilename = `${structure.rootFolder}.zip`;
      const zipBuffer = await manager.createZipArchive(localPath, zipFilename);

      // Send ZIP file
      res.setHeader('Content-Type', 'application/zip');
      res.setHeader('Content-Disposition', `attachment; filename="${zipFilename}"`);
      res.setHeader('Content-Length', zipBuffer.length);
      res.send(zipBuffer);
    } catch (error) {
      console.error("[API Export ZIP] ❌ Error:", error);
      console.error("[API Export ZIP] Error stack:", error instanceof Error ? error.stack : 'No stack trace');
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to export BDD assets as ZIP",
        details: msg,
      });
    } finally {
      // CRITICAL: Always cleanup temp files, even if error occurred
      if (localPath) {
        const { BDDAssetsManager } = await import("./services/bdd-assets-manager");
        const manager = new BDDAssetsManager();
        await manager.cleanup(localPath).catch(err => {
          console.error('[API Export ZIP] Cleanup failed (non-critical):', err);
        });
      }
    }
  });

