  // Push manual test cases to Azure DevOps
  app.post("/api/test-cases/push-to-ado", requireActivity("SDLC_TEST_SYNC"), async (req: Request, res: Response) => {
    const { testCasesByCategory, userStory, organization, projectName } = req.body;

    // Validate required parameters
    if (!testCasesByCategory) {
      console.error("[API Push to ADO] Missing testCasesByCategory parameter");
      return res.status(400).json({
        error: "Missing required parameter: testCasesByCategory",
      });
    }

    if (!userStory || !userStory.adoWorkItemId) {
      console.error("[API Push to ADO] Missing user story or ADO work item ID");
      return res.status(400).json({
        error: "User story must have an ADO work item ID (adoWorkItemId) to link test cases",
      });
    }

    if (!organization || !projectName) {
      console.error("[API Push to ADO] Missing organization or projectName");
      return res.status(400).json({
        error: "Missing required parameters: organization, projectName",
      });
    }

    try {

      // **CRITICAL: Get ADO config from database (Artifact Organizations in Settings)**
      const azureConfig = await getAzureDevOpsConfig(projectName, organization);

      if (!azureConfig) {
        console.error("[API Push to ADO] Azure DevOps not configured for this organization/project");
        return res.status(400).json({
          error: "Azure DevOps not configured. Please configure in Settings > Central Settings > Artifact Organizations",
        });
      }

      console.log("[API Push to ADO] ✅ ADO Config found:", {
        organization: azureConfig.organization,
        project: azureConfig.project,
        hasToken: !!azureConfig.pat
      });

      // Import Azure DevOps service
      const { AzureDevOpsService } = await import("./azure-devops-service");

      // Initialize service with config object
      const adoService = new AzureDevOpsService(azureConfig);

      // Create categorized test cases
      const result = await adoService.createCategorizedTestCasesForStory(
        testCasesByCategory,
        userStory.adoWorkItemId,
        userStory.title
      );

      // **Tag the User Story in ADO** to indicate test cases have been generated
      if (result.summary.succeeded > 0) {
        try {
          await adoService.addTagsToWorkItem(
            userStory.adoWorkItemId,
            ['TestCases-Generated', 'DevX-Automation'],
            azureConfig.project
          );
        } catch (tagError) {
          console.warn(`[API Push to ADO] ⚠️ Failed to tag User Story (non-critical):`, tagError);
          // Continue even if tagging fails - it's not critical
        }
      }

      // Build ADO URL for the user story
      const userStoryUrl = `https://dev.azure.com/${azureConfig.organization}/${azureConfig.project}/_workitems/edit/${userStory.adoWorkItemId}`;

      return res.json({
        success: true,
        results: result.results,
        summary: result.summary,
        userStoryUrl,
        message: `Successfully pushed ${result.summary.succeeded} of ${result.summary.total} test cases to Azure DevOps`
      });

    } catch (error) {
      console.error("[API Push to ADO] ❌ Error:", error);
      console.error("[API Push to ADO] Error stack:", error instanceof Error ? error.stack : 'No stack trace');
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to push test cases to Azure DevOps",
        details: msg,
      });
    }
  });

  // Check which user stories have test artifacts in Git (GitHub or ADO per project)
  app.post("/api/bdd-assets/check-generated", async (req: Request, res: Response) => {
    const { userStories, organization, projectName, projectId } = req.body;

    if (!userStories || !Array.isArray(userStories)) {
      return res.status(400).json({
        error: "Missing or invalid required parameter: userStories (must be an array)",
      });
    }

    if (!organization || !projectName) {
      return res.status(400).json({
        error: "Missing required parameters: organization, projectName",
      });
    }

    try {
      // If no projectId, fall back to GitHub-only check (legacy)
      if (!projectId) {
        const tenantId = await getTenantIdFromRequest(req);
        const storage = await getAutomationGitStorage(
          tenantId,
          undefined,
          undefined,
          undefined,
          getAzureDevOpsConfig,
          (req as any).user?.id,
        );
        const { BDDAssetsManager } = await import("./services/bdd-assets-manager");
        const manager = new BDDAssetsManager();
        const results = await manager.checkGeneratedInStorage(userStories, organization, projectName, storage);
        return res.json({ success: true, results });
      }

      const chkTenantId = await getTenantIdFromRequest(req);
      const storage = await getGitStorage(projectId, organization, projectName, getAzureDevOpsConfig, chkTenantId, {
        userId: (req as any).user?.id,
      });
      const { BDDAssetsManager } = await import("./services/bdd-assets-manager");
      const manager = new BDDAssetsManager();
      const results = await manager.checkGeneratedInStorage(userStories, organization, projectName, storage);

      return res.json({ success: true, results });
    } catch (error) {
      console.error("[API] Error checking Git for generated artifacts:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      const results: Record<string, boolean> = {};
      userStories.forEach((story: any) => { results[story.id] = false; });
      return res.json({ success: false, results, error: msg });
    }
  });

  // Save reviewed test cases to Git (GitHub or ADO per project_git_config)
  app.post("/api/save-reviewed-testcases", requireActivity("SDLC_TEST_UPDATE"), async (req: Request, res: Response) => {
    const { testCases, userStory, projectId, projectName, organization } = req.body;

    if (!testCases || !userStory || !projectId) {
      return res.status(400).json({
        error: "Missing required parameters: testCases, userStory, projectId",
      });
    }

    let resolvedOrg = organization;
    let resolvedProjectName = projectName;
    if (!resolvedOrg || !resolvedProjectName) {
      try {
        const project = await sdlcService.getProject(projectId);
        if (project) {
          if (!resolvedProjectName) resolvedProjectName = project.name;
          if (!resolvedOrg) resolvedOrg = project.organization ?? undefined;
        }
      } catch (_) {
        // ignore; use request values or defaults below
      }
    }

    try {
      const saveTenantId = await getTenantIdFromRequest(req);
      const storage = await getGitStorage(projectId, resolvedOrg, resolvedProjectName, getAzureDevOpsConfig, saveTenantId, {
        userId: (req as any).user?.id,
      });

      const org = sanitizePathName(resolvedOrg || 'unknown-org');
      const proj = sanitizePathName(resolvedProjectName || 'default-project');
      const storyName = sanitizePathName(userStory.title || `story-${userStory.id}`);
      const projectFolder = `${org}-${proj}`;
      const basePath = buildStoryArtifactsPath(projectFolder, storyName);

      const testCasesPath = `${basePath}/test-cases.json`;
      await storage.pushFile(
        testCasesPath,
        JSON.stringify(testCases, null, 2),
        `Add reviewed test cases for ${userStory.title}`
      );

      const viewUrl = storage.getFileUrl?.(testCasesPath) ?? storage.getBaseUrl?.() ?? undefined;

      return res.json({
        success: true,
        message: "Test cases saved to repository successfully",
        gitHubUrls: [testCasesPath],
        viewUrl,
      });
    } catch (error: any) {
      console.error("[API] Error saving reviewed test cases:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      const code = typeof error?.code === "string" && (error.code === "ER_NO_SUCH_TABLE" || error.code === "ER_BAD_TABLE_ERROR")
        ? 503
        : 500;
      return res.status(code).json({
        error: "Failed to save reviewed test cases to repository",
        details: msg,
      });
    }
  });

  // Fetch BDD files from Git (GitHub or ADO when projectId provided) for a user story
  app.post("/api/github/fetch-bdd-files", async (req: Request, res: Response) => {
    const { userStoryId, userStoryTitle, organization, projectName, projectId } = req.body;

    if (!userStoryId || !userStoryTitle || !organization || !projectName) {
      return res.status(400).json({
        error: "Missing required parameters: userStoryId, userStoryTitle, organization, projectName",
      });
    }

    const org = sanitizePathName(organization);
    const proj = sanitizePathName(projectName);
    const storyName = sanitizePathName(userStoryTitle);
    const projectFolder = `${org}-${proj}`;

    const tenantId = await getTenantIdFromRequest(req);
    let storage;
    if (projectId) {
      storage = await getGitStorage(projectId, organization, projectName, getAzureDevOpsConfig, tenantId, {
        userId: (req as any).user?.id,
      });
    } else {
      storage = await getAutomationGitStorage(
        tenantId,
        undefined,
        undefined,
        undefined,
        getAzureDevOpsConfig,
        (req as any).user?.id,
      );
    }
    const basePath = buildStoryArtifactsPath(projectFolder, storyName);

    try {

      const featureFiles: Array<{ name: string; path: string; content: string }> = [];
      const stepDefinitionFiles: Array<{ name: string; path: string; content: string }> = [];

      try {
        const featuresPath = `${basePath}/features`;
        const featureFilesData = await storage.listDirectoryContents(featuresPath);
        if (Array.isArray(featureFilesData)) {
          for (const file of featureFilesData) {
            if (file.type === 'file' && file.name.endsWith('.feature')) {
              const content = await storage.getFileContent(file.path);
              featureFiles.push({ name: file.name, path: file.path, content: content || '' });
            }
          }
        }
      } catch (_) { }

      try {
        const stepDefsPath = `${basePath}/step-definitions`;
        const stepDefFilesData = await storage.listDirectoryContents(stepDefsPath);
        if (Array.isArray(stepDefFilesData)) {
          for (const file of stepDefFilesData) {
            if (file.type === 'file' && (file.name.endsWith('.js') || file.name.endsWith('.ts') || file.name.endsWith('.java'))) {
              const content = await storage.getFileContent(file.path);
              stepDefinitionFiles.push({ name: file.name, path: file.path, content: content || '' });
            }
          }
        }
      } catch (_) { }

      if (featureFiles.length === 0 && stepDefinitionFiles.length === 0) {
        return res.status(404).json({
          error: "BDD files not found",
          message: "No BDD feature files or step definitions found for this user story"
        });
      }

      return res.json({
        success: true,
        files: { features: featureFiles, stepDefinitions: stepDefinitionFiles },
        basePath
      });
    } catch (error) {
      console.error("[API] Error fetching BDD files:", error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      return res.status(500).json({
        error: "Failed to fetch BDD files",
        details: msg,
      });
    }
  });

