  /**
   * Helper to extract user identity from request headers/body
   * Expects user info to be sent from client (MSAL authenticated)
   */
  function extractUserIdentity(req: Request): {
    aadObjectId: string;
    userName: string;
    userEmail: string;
    displayName?: string;
    homeAccountId?: string;
    tenantId?: string;
    role?: "admin" | "user";
  } {
    // Extract from request body (preferred) or headers
    const body = req.body || {};
    const headers = req.headers || {};
    const reqUser = (req as any).user || {};
    const headerValue = (key: string): string | undefined => {
      const value = headers[key as keyof typeof headers];
      if (Array.isArray(value)) {
        return value[0];
      }
      return typeof value === "string" ? value : undefined;
    };
    const emailFromIdentity =
      reqUser.email || body.userEmail || body.email || headerValue("x-user-email");
    const displayNameFromIdentity =
      reqUser.displayName || body.displayName || body.name || headerValue("x-display-name");

    const aadObjectId =
      reqUser.azureOid ||
      reqUser.id ||
      body.aadObjectId ||
      body.userId ||
      headerValue("x-user-oid") ||
      headerValue("x-user-id") ||
      headerValue("x-aad-object-id");

    const userName =
      reqUser.username ||
      reqUser.displayName ||
      reqUser.email ||
      body.userName ||
      body.username ||
      headerValue("x-user-name") ||
      displayNameFromIdentity ||
      emailFromIdentity ||
      "";

    const userEmail =
      emailFromIdentity ||
      userName ||
      "";

    const displayName =
      displayNameFromIdentity ||
      undefined;

    const homeAccountId = body.homeAccountId || headerValue("x-home-account-id");
    const tenantId = body.tenantId || headerValue("x-tenant-id");

    // Optional role: default to 'user' if not provided.
    // Admins can be indicated via body.role or x-user-role header (e.g. 'admin').
    const rawRole = (body.role || headerValue("x-user-role") || "user") as string;
    const normalizedRole = rawRole.toString().toLowerCase() === "admin" ? "admin" : "user";

    if (!aadObjectId || !userName || !userEmail) {
      throw new Error(
        "Missing required user identity: aadObjectId, userName, and userEmail are required"
      );
    }

    return {
      aadObjectId: String(aadObjectId),
      userName: String(userName),
      userEmail: String(userEmail),
      displayName: displayName ? String(displayName) : undefined,
      homeAccountId: homeAccountId ? String(homeAccountId) : undefined,
      tenantId: tenantId ? String(tenantId) : undefined,
      role: normalizedRole,
    };
  }

