      if (!status) {
        return res.status(400).json({
          success: false,
          error: "status is required",
        });
      }

      const allowed: Array<"IN_PROGRESS" | "PAUSED" | "COMPLETED" | "INACTIVE" | "CANCELLED"> = [
        "IN_PROGRESS",
        "PAUSED",
        "COMPLETED",
        "INACTIVE",
        "CANCELLED",
      ];
      if (!allowed.includes(status as typeof allowed[number])) {
        return res.status(400).json({
          success: false,
          error: `status must be one of: ${allowed.join(", ")}`,
        });
      }

      const session = await sessionService.setSessionStatus(
        sessionId,
        userIdentity,
        status as "IN_PROGRESS" | "PAUSED" | "COMPLETED" | "INACTIVE" | "CANCELLED"
      );

