      if (!files || !Array.isArray(files) || files.length === 0) {
        console.log("[PUSH-TO-ADO] Missing files array");
        return res.status(400).json({
          error: "files array is required"
        });
      }

      if (!projectName || typeof projectName !== "string") {
        console.log("[PUSH-TO-ADO] Missing projectName");
        return res.status(400).json({
          error: "projectName is required"
        });
      }

      if (!organizationUrl || !projectId) {
        console.log("[PUSH-TO-ADO] Missing organizationUrl or projectId");
        return res.status(400).json({
          error: "Azure DevOps configuration (organizationUrl, projectId) is required"
        });
      }

      console.log(`[PUSH-TO-ADO] Pushing ${files.length} files to Azure DevOps`);

      // Add Azure Pipeline configuration for automatic deployment
      const pipelineConfig = `# Auto-generated Azure Pipeline for DevX Generated Code
# This pipeline enables automatic deployment when code is pushed

trigger:
  branches:
    include:
      - main
      - master
  paths:
    exclude:
      - README.md
      - docs/*
      - '*.md'

pool:
  vmImage: 'ubuntu-latest'

variables:
  - name: nodeVersion
    value: '20.x'
  - name: appServiceName
    value: 'codegen-f7hbbfcvcycjfjg7'
  - name: resourceGroupName
    value: 'rg-devxplatform'
  - name: subscriptionName
    value: 'MS-Sponsorship-GSS'
  - group: 'DevX-Variables'  # This links your variable group

stages:
  - stage: Build
    displayName: 'Build Application'
    jobs:
      - job: BuildJob
        displayName: 'Build'
        steps:
          - task: NodeTool@0
            displayName: 'Install Node.js'
            inputs:
              versionSpec: '$(nodeVersion)'

          - script: |
              if [ -f "package.json" ]; then
                echo "📦 Installing dependencies..."
                if [ -f "package-lock.json" ]; then
                  echo "✅ package-lock.json found, using npm ci for faster, reliable builds"
                  npm ci
                elif [ -f "yarn.lock" ]; then
                  echo "✅ yarn.lock found, using yarn install"
                  yarn install --frozen-lockfile
                else
                  echo "⚠️  No lock file found, using npm install"
                  npm install
                fi
              else
                echo "ℹ️  No package.json found, skipping dependency installation"
              fi
            displayName: 'Install Dependencies'

          - script: |
              if [ -f "package.json" ]; then
                echo "🏗️  Checking for build scripts..."
                if npm run | grep -q "build"; then
                  echo "✅ Build script found, running build..."
                  npm run build
                elif npm run | grep -q "compile"; then
                  echo "✅ Compile script found, running compile..."
                  npm run compile
                elif npm run | grep -q "dist"; then
                  echo "✅ Dist script found, running dist..."
                  npm run dist
                else
                  echo "ℹ️  No build script found, checking if TypeScript project..."
                  if [ -f "tsconfig.json" ]; then
                    echo "📝 TypeScript project detected, running tsc"
                    npx tsc
                  else
                    echo "✅ No build step required for this project"
                  fi
                fi
              else
                echo "ℹ️  No package.json found, skipping build"
              fi
            displayName: 'Build Application'

          - script: |
              echo "🎉 Build completed successfully!"
              echo "📊 Build Summary:"
              echo "   Repository: $(Build.Repository.Name)"
              echo "   Branch: $(Build.SourceBranchName)"
              echo "   Commit: $(Build.SourceVersion)"
              echo "   Build ID: $(Build.BuildId)"
              echo "   Trigger: $(Build.Reason)"
              echo "   Target App Service: $(appServiceName)"
              echo "   Resource Group: $(resourceGroupName)"
              echo "   Subscription: $(subscriptionName)"
              if [ -f "package.json" ]; then
                echo "   Project: $(cat package.json | grep '"name"' | cut -d'"' -f4)"
                echo "   Version: $(cat package.json | grep '"version"' | cut -d'"' -f4)"
              fi
              echo "✅ Ready for deployment to $(appServiceName).azurewebsites.net!"
            displayName: 'Build Summary'

          - task: ArchiveFiles@2
            displayName: 'Archive application'
            inputs:
              rootFolderOrFile: '$(System.DefaultWorkingDirectory)'
              includeRootFolder: false
              archiveType: 'zip'
              archiveFile: '$(Build.ArtifactStagingDirectory)/app.zip'
              replaceExistingArchive: true

          - task: PublishBuildArtifacts@1
            displayName: 'Publish build artifact'
            inputs:
              PathtoPublish: '$(Build.ArtifactStagingDirectory)/app.zip'
              ArtifactName: 'drop'

  - stage: Deploy
    displayName: 'Deploy Application'
    dependsOn: Build
    condition: and(succeeded(), eq(variables['Build.SourceBranch'], 'refs/heads/main'))
    jobs:
      - job: DeployJob
        displayName: 'Deploy to Azure App Service'
        steps:
          - task: DownloadBuildArtifacts@0
            displayName: 'Download build artifacts'
            inputs:
              buildType: 'current'
              downloadType: 'single'
              artifactName: 'drop'
              downloadPath: '$(Pipeline.Workspace)'

          - task: PowerShell@2
            displayName: 'Deploy to Azure App Service using Publish Profile'
            inputs:
              targetType: 'inline'
              script: |
                # Install Azure PowerShell if not available
                if (!(Get-Module -ListAvailable -Name Az.Websites)) {
                  Install-Module -Name Az.Websites -Force -AllowClobber -Scope CurrentUser
                }

                # Parse publish profile to extract deployment credentials
                $publishProfile = '$(AZURE_APP_SERVICE_PUBLISH_PROFILE)'
                [xml]$profileXml = $publishProfile

                $publishUrl = $profileXml.publishData.publishProfile[0].publishUrl
                $userName = $profileXml.publishData.publishProfile[0].userName
                $password = $profileXml.publishData.publishProfile[0].userPWD
                $siteName = $profileXml.publishData.publishProfile[0].msdeploySite

                Write-Host "Deploying to: $siteName"
                Write-Host "Publish URL: $publishUrl"

                # Deploy using Kudu ZIP Deploy API
                $zipFile = "$(Pipeline.Workspace)/drop/app.zip"
                $base64AuthInfo = [Convert]::ToBase64String([Text.Encoding]::ASCII.GetBytes("$userName" + ":" + "$password"))

                $deployUri = "https://$publishUrl/api/zipdeploy"

                Write-Host "Uploading zip file to: $deployUri"

                try {
                  Invoke-RestMethod -Uri $deployUri -Method Post -InFile $zipFile -ContentType "application/zip" -Headers @{Authorization = "Basic $base64AuthInfo"} -TimeoutSec 1800
                  Write-Host "✅ Deployment successful!"
                } catch {
                  Write-Error "❌ Deployment failed: $($_.Exception.Message)"
                  throw
                }

          - script: |
              echo "🚀 Deployment completed successfully!"
              echo "🌐 Your application is now available at:"
              echo "   https://$(appServiceName).canadacentral-01.azurewebsites.net"
              echo "📊 Deployment Details:"
              echo "   App Service: $(appServiceName)"
              echo "   Resource Group: $(resourceGroupName)"
              echo "   Subscription: $(subscriptionName)"
              echo "   Region: Canada Central"
              echo "✅ Application is live and ready to use!"
            displayName: 'Deployment Success Notification'
`;

      // Check for existing files to avoid duplicates
